create table "_Topic"
(
    "Id"                    integer generated by default as identity (start with 10000)
        constraint "_Topic_pk"
            primary key,
    "Type"                  smallint                                  not null,
    "EffectiveFrom"         timestamp with time zone default now()    not null,
    "EffectiveTo"           timestamp with time zone default now()    not null,
    "CreatedOn"             timestamp with time zone default now()    not null,
    "UpdatedOn"             timestamp with time zone default now()    not null,
    "Title"                 varchar(256)                              not null,
    "AdditionalInformation" text                     default ''::text not null
);

alter table "_Topic"
    owner to bcrpro;

create index "_Topic_EffectiveFrom_EffectiveTo_index"
    on "_Topic" ("EffectiveFrom", "EffectiveTo");

create index "_Topic_Type_index"
    on "_Topic" ("Type");

grant select on "_Topic" to dev_read;

create table "_TopicContent"
(
    "Id"        integer generated by default as identity (start with 10000)
        constraint "_TopicContent_pk"
            primary key,
    "TopicId"   integer                                                not null
        constraint "_TopicContent__Topic_Id_fk"
            references "_Topic",
    "CreatedOn" timestamp with time zone default now()                 not null,
    "UpdatedOn" timestamp with time zone default now()                 not null,
    "Language"  varchar(10)                                            not null,
    "Title"     varchar(256)                                           not null,
    "Author"    varchar(128)                                           not null,
    "Content"   text                                                   not null,
    "Subtitle"  varchar(256)             default ''::character varying not null
);

alter table "_TopicContent"
    owner to bcrpro;

create unique index "_TopicContent_TopicId_Language_UX"
    on "_TopicContent" ("Language", "TopicId");

create index "IX__TopicContent_TopicId"
    on "_TopicContent" ("TopicId");

grant select on "_TopicContent" to dev_read;

