    Dear Customer {{UserName}},
  </p>
<p style="font-size:14px;">
Thank you for initiating the online account application with BCR. By taking this step, you are becoming a part of the community of thousands of clients who have chosen BCR as their reliable partner for trading Forex, Precious Metals, Equity, and Commodity CFDs. To ensure the verification of your email address and the activation of your new BCR account, kindly click the link provided below.
</p>
  <p>
    <a href="{{CallbackUrl}}" target="_blank" style="color: #383d49;text-decoration: none;font-weight: 700;">Click Here</a>
    or copy the following address into your browser\'s address bar:
  </p>
  <div style="margin-left: auto;margin-right: auto;text-align: center;font-style: italic;">
    {{CallbackUrl}}
  </div>
  <p>For your account security, this link will be valid for <b>10 minutes</b>. This email is automatically generated by the system, please do not reply directly.</p>
</div>', 'Please use url to confirm email address');
INSERT INTO cms."_TopicContent" ("Id", "TopicId", "CreatedOn", "UpdatedOn", "Language", "Title", "Author", "Content", "Subtitle") VALUES (10006, 10001, '2023-08-15 23:25:52.326906 +00:00', '2023-08-15 23:29:46.587571 +00:00', 'zh-cn', '账户申请确认邮件', '', e'<div style="font-size: 12px; line-height: 20px">
