INSERT INTO cms."_TopicContent" ("Id", "TopicId", "CreatedOn", "UpdatedOn", "Language", "Title", "Author", "Content", "Subtitle") VALUES (10010, 11239, '2023-08-15 23:34:41.376535 +00:00', '2023-08-22 08:18:22.461469 +00:00', 'zh-cn', 'MyBCR 重要通知', '', e'
<div style="font-size: 14px; line-height: 20px">
<p>由于对MyBCR的升级，客户门户将在<b>2023年8月26日星期五</b>的市场收盘后不可用，并将在<b>2023年8月28日星期一</b>的市场开盘前恢复正常使用。
</p>
<p>如果您在周末需要客户服务，请通过电子邮件联系BCR支持团队：<a href="mailto:info@thebcr.com">info@thebcr.com</a>。</p>
<p>如果您对上述升级有任何进一步的问题，请通过在线聊天与我们联系，或通过电子邮件发送至info@thebcr.com。我们期待为您提供金融服务行业最佳的服务。</p>
<br />
致敬，
<br />
<b>BCR</b>
<br />
</div>', 'MyBCR 升级信息');
INSERT INTO cms."_TopicContent" ("Id", "TopicId", "CreatedOn", "UpdatedOn", "Language", "Title", "Author", "Content", "Subtitle") VALUES (10070, 11251, '2023-08-16 18:15:21.915955 +00:00', '2023-08-23 22:23:14.869080 +00:00', 'mn-mn', 'Татгалзах баталгаа', '', e'<div style="font-size: 12px; line-height: 20px">
