          style="
                 padding-left: 24px;
                 padding-right: 24px;
                 color: #383d49;
                 white-space: nowrap;
                 "
          >
        Дансны дугаар:
      </th>
      <td
          style="
                 padding-left: 24px;
                 padding-right: 24px;
                 word-wrap: break-word;
                 "
          >
        {{AccountNumber}}
      </td>
    </tr>
    <tr>
      <th
          style="
                 padding-left: 24px;
                 padding-right: 24px;
                 color: #383d49;
                 white-space: nowrap;
                 "
          >
        Валют:
      </th>
      <td
          style="
                 padding-left: 24px;
