', '');
INSERT INTO cms."_TopicContent" ("Id", "TopicId", "CreatedOn", "UpdatedOn", "Language", "Title", "Author", "Content", "Subtitle") VALUES (10071, 11252, '2023-08-16 18:16:20.975977 +00:00', '2023-09-14 20:01:38.548972 +00:00', 'mn-mn', 'Татан авалт амжилтгүй боллоо', '', e'<div style="font-size: 12px; line-height: 20px">
  <p
     style="font-size: 16px; font-weight: 700; line-height: 24px"
     >
    Удахгүй Хэрэглэгч,
  </p>
  <p>
    Таны гар утсанд явагдсан төлбөр буцаах хүсэлтийг боловсруулж чадсангүй болно, тиймээс
    таны хүсэлт татагдсангүй байна. Дэлгэрэнгүй мэдээллийг доорхидаа оруулсан байна:
  </p>
  <table
         class="letter-table"
         style="
                table-layout: fixed;
                line-height: 24px;
                margin-left: auto;
                margin-right: auto;
                text-align: left;
                padding: 8px;
                float: none;
                "
         bgcolor="#f2f2f2"
         align="left"
         >
    <tr>
      <th
          style="
                 padding-left: 24px;
                 padding-right: 24px;
                 color: #383d49;
                 white-space: nowrap;
                 "
          >
        Дансны дугаар:
      </th>
      <td
          style="
                 padding-left: 24px;
                 padding-right: 24px;
                 word-wrap: break-word;
                 "
          >
       {{AccountNumber}}
      </td>
    </tr>
    <tr>
      <th
          style="
                 padding-left: 24px;
                 padding-right: 24px;
                 color: #383d49;
                 white-space: nowrap;
                 "
          >
        Дансны нэр:
      </th>
      <td
          style="
                 padding-left: 24px;
                 padding-right: 24px;
                 word-wrap: break-word;
                 "
          >
       {{NativeName}}
      </td>
    </tr>
    <tr>
      <th
          style="
                 padding-left: 24px;
                 padding-right: 24px;
                 color: #383d49;
                 white-space: nowrap;
                 "
          >
        Валют:
      </th>
      <td
          style="
                 padding-left: 24px;
                 padding-right: 24px;
                 word-wrap: break-word;
                 "
          >
        {{Currency}}
      </td>
    </tr>
    <tr>
      <th
          style="
                 padding-left: 24px;
                 padding-right: 24px;
                 color: #383d49;
                 white-space: nowrap;
                 "
          >
        Татварын дүн:
      </th>
      <td
          style="
                 padding-left: 24px;
                 padding-right: 24px;
                 word-wrap: break-word;
                 "
          >
        $ {{FormattedAmount}}
      </td>
    </tr>
    <tr>
      <th
          style="
                 padding-left: 24px;
                 padding-right: 24px;
                 color: #383d49;
                 white-space: nowrap;
                 "
          >
        Хүсэлтийн огноо:
      </th>
      <td
          style="
                 padding-left: 24px;
                 padding-right: 24px;
                 word-wrap: break-word;
                 "
          >
       {{Date}}
      </td>
    </tr>
  </table>
  <p>
    Таны татсан хүсэлтийг боловсруулах боломжгүй болсон шалтгаан нь:
  </p>
  <p style="color: #cc1f1a; font-weight: 600">{{Reason}}</p>
  <br />
  <p>
    Хэрэв та таны хүсэлт баталгаажсан шалтгааныг ойлгож байгаагүй бол, таны дансны удирдлагагчтай
    холбогдоод живэ-чатаар бидэнтэй холбогдоно уу.
  </p>
</div>
', '');
