INSERT INTO cms."_TopicContent" ("Id", "TopicId", "CreatedOn", "UpdatedOn", "Language", "Title", "Author", "Content", "Subtitle") VALUES (11443, 11292, '2023-12-09 00:26:17.112090 +00:00', '2023-12-09 00:26:17.112090 +00:00', 'vi-vn', 'Chào mừng bạn đã lên tàu', '', e'<div style="font-size:12px;line-height:20px">
    <p style="font-size:16px;font-weight:700;line-height:24px">Kính gửi {{NativeName}},</p>
    <p>Cảm ơn bạn đã mở một tài khoản giao dịch CFD với BCR. Tài khoản của bạn đã sẵn sàng giao dịch từ ngày {{OpenedDate}}, và chi tiết tài khoản BCR ProTrader của bạn được liệt kê dưới đây:</p>
    <table class="letter-table"
           style="table-layout:fixed;line-height:24px;margin-left:auto;margin-right:auto;text-align:left;padding:8px;float:none"
           bgcolor="#f2f2f2" align="left">
        <tr>
            <th
                    style="padding-left:24px;padding-right:24px;color:#383d49;white-space:nowrap">
                Tài khoản MyBCR:</th>
            <td style="padding-left:24px;padding-right:24px;word-wrap:break-word">
                {{UserName}}</td>
        </tr>
        <tr>
            <th
                    style="padding-left:24px;padding-right:24px;color:#383d49;white-space:nowrap">
                Số tài khoản giao dịch:</th>
            <td style="padding-left:24px;padding-right:24px;word-wrap:break-word">
                {{AccountNumber}}</td>
        </tr>
        <tr>
            <th
                    style="padding-left:24px;padding-right:24px;color:#383d49;white-space:nowrap">
                Mật khẩu tài khoản giao dịch:</th>
            <td style="padding-left:24px;padding-right:24px;word-wrap:break-word">
                {{Password}}</td>
        </tr>
        <tr>
            <th
                    style="padding-left:24px;padding-right:24px;color:#383d49;white-space:nowrap">
                Mật khẩu nhà đầu tư:</th>
            <td style="padding-left:24px;padding-right:24px;word-wrap:break-word">
                {{InvestorPassword}}</td>
        </tr>
        <tr>
            <th
                    style="padding-left:24px;padding-right:24px;color:#383d49;white-space:nowrap">
                Mật khẩu điện thoại:</th>
            <td style="padding-left:24px;padding-right:24px;word-wrap:break-word">
                {{PhonePassword}}</td>
        </tr>
        <tr>
            <th
                    style="padding-left:24px;padding-right:24px;color:#383d49;white-space:nowrap">
                Máy chủ:</th>
            <td style="padding-left:24px;padding-right:24px;word-wrap:break-word">{{TradeServiceName}}
            </td>
        </tr>
    </table>
    <p style="font-weight:700;line-height:24px;font-size:14px">Theo các bước sau để bắt đầu giao dịch ngay bây giờ:</p>
    <ol>
        <li>Duyệt qua tab Khuyến mãi trên trang web chính thức của chúng tôi <a target="_blank"
                                                            href="https://cfds.thebcr.com"
                                                            style="color:#383d49;text-decoration:none;font-weight:700">Trang web chính thức</a> để tìm hiểu thêm về các chương trình khuyến mãi của BCR.</li>
        <li>Đăng nhập vào <a target="_blank" href="https://cfds-portal.thebcr.com/"
                style="color:#383d49;text-decoration:none;font-weight:700">MyBCR</a>
            và điều hướng đến tab Tải về để tải xuống nền tảng giao dịch BCR.</li>
        <li>Đăng nhập vào <a target="_blank" href="https://cfds-portal.thebcr.com/"
                style="color:#383d49;text-decoration:none;font-weight:700">MYBCR</a> và chọn My deposit để chọn phương thức gửi tiền.</li>
        <li>Đăng nhập vào BCR Trader (Nền tảng MT4 hoặc MT5) hoặc nếu bạn đang sử dụng thiết bị di động, hãy chọn Máy chủ {{TradeServiceName}} trong Mobile MetaTrader và sử dụng Số tài khoản và Mật khẩu giao dịch được liệt kê ở trên.</li>
    </ol>
    <p>
        Lưu ý rằng Mật khẩu nhà đầu tư chỉ cung cấp quyền truy cập chỉ đọc, không cho phép giao dịch trên tài khoản của bạn. Nếu bạn muốn đặt lệnh giao dịch qua điện thoại, bạn có thể liên hệ với chúng tôi qua một trong những số điện thoại sau:</p>
    <p style="font-weight:600;text-align:center">44 3300010590<br>
                                    <!-- New Zealand: 64-9-889-2558<br>
    UK: 44-161-818-9558<br>
    Southern China: 108 00152 1738 (Dịch vụ Điện thoại cố định)<br>
    Northern China: 108 00852 1738 (Dịch vụ Điện thoại cố định)<br> -->
    </p>
    <p>Vui lòng lưu ý rằng dịch vụ giao dịch qua điện thoại chỉ được sử dụng khi có sự cố kết nối mạng hoặc nền tảng giao dịch không hoạt động đúng cách.</p>

</div>
', 'Xác minh đã được thông qua');
INSERT INTO cms."_TopicContent" ("Id", "TopicId", "CreatedOn", "UpdatedOn", "Language", "Title", "Author", "Content", "Subtitle") VALUES (10084, 11247, '2023-08-16 18:33:53.316918 +00:00', '2023-09-14 17:14:02.999567 +00:00', 'jp-jp', '出金がキャンセルされました', '', e'
