INSERT INTO cms."_TopicContent" ("Id", "TopicId", "CreatedOn", "UpdatedOn", "Language", "Title", "Author", "Content", "Subtitle") VALUES (10060, 10001, '2023-08-16 01:32:42.482616 +00:00', '2023-08-16 01:32:42.482616 +00:00', 'mn-mn', ' Бүртгэлийн програмыг баталгаажуулах имэйл', '', e'<div style="font-size: 12px; line-height: 20px">
  <p style="font-size: 16px; font-weight: 700; line-height: 24px">
    Хүндэт харилцагч {{UserName}}-д,
  </p>
  <p style="font-size:14px;">
    Та BCR-тай анхдагчаар бүртгүүлсний тулд бидэнд баярлалаа. Энээлтэй байхад та Форекс, Угаалт хөнгөн, Сангийн хувь, борлуулагч CFD үйлдлийн манай хэмжээний хэрэглэгчидтэйгээ нэгтгэж байна. Таны цахим шуудангийг баталгаажуулах ба шинэ BCR дансныг идэвхжүүлэхийн тулд доорх холбоосыг дарна уу.
  </p>
  <p>
    <a href="{{CallbackUrl}}" target="_blank" style="color: #383d49;text-decoration: none;font-weight: 700;">Энд дарж нэвтрэх</a>
    Эсвэл холбоосыг хуулахын тулд хөтөчийн хаяг руу хуулна уу:
  </p>
  <div style="margin-left: auto;margin-right: auto;text-align: center;font-style: italic;">
    {{CallbackUrl}}
  </div>
  <p>Таны дансны аюулгүй байдлыг хангахын тулд энэ холбоос нь <strong>10 минут</strong> хүчинтэй байна. Энэ имэйл нь системийн аутомат бичгээр үүсгэгдсэн бол хариулах ямар ч хариу ирүүлэхгүй болно.</p>
</div>
', 'Имэйл хаягаа баталгаажуулахын тулд url ашиглана уу');
INSERT INTO cms."_TopicContent" ("Id", "TopicId", "CreatedOn", "UpdatedOn", "Language", "Title", "Author", "Content", "Subtitle") VALUES (10061, 10002, '2023-08-16 01:33:56.466632 +00:00', '2023-08-16 01:33:56.466632 +00:00', 'mn-mn', 'Нууц үгээ шинэчлэх', '', e'<div style="font-size: 12px; line-height: 20px">
  <p style="font-size: 16px; font-weight: 700; line-height: 24px">
    Хүндэт харилцагч {{UserName}}-д,
  </p>
  <p>
    <a href="{{CallbackUrl}}" target="_blank" style="color: #383d49;text-decoration: none;font-weight: 700;">Энд дарж нэвтрэх</a>
    эсвэл доорх хаягийг таны вэб хөтчийн хаягаар хуулаарай:
  </p>
  <div style="margin-left: auto;margin-right: auto;text-align: center;font-style: italic;">
    {{CallbackUrl}}
  </div>
  <p>Таны дансны аюулгүй байдлыг хангахын тулд энэ холбоос нь <strong>10 минут</strong> хүчинтэй байна. Энэ имэйл нь системийн аутомат бичгээр үүсгэгдсэн бол хариулах ямар ч хариу ирүүлэхгүй болно.</p>
</div>
', 'Нууц үгийн холбоосыг дахин тохируулах');
INSERT INTO cms."_TopicContent" ("Id", "TopicId", "CreatedOn", "UpdatedOn", "Language", "Title", "Author", "Content", "Subtitle") VALUES (10062, 11239, '2023-08-16 17:56:16.827580 +00:00', '2023-08-16 17:56:16.827580 +00:00', 'mn-mn', 'MyBCR-ийн чухал мессеж', '', e'<div style="font-size: 14px; line-height: 20px">
<p>MyBCR-ийн шинэчлэлтэд татгалзсан болон үүнийг авах боломжгүй болохын тулд Клиентийн портал нь <b>2023 оны 7-р сарын 21-нд</b> Худалдаа хаагдаж, ахмад гарч зөвшөөрсөн өдрийн өмнө давтан байршина.
</p>
<p>Хэрэв та уих-ын хувийг ашиглаж ажиллах горимд клиентийн үйлчилгээг хүлээн авах шаардлагатай бол, БСР дэмжлэгийн хаягаар <a href="mailto:info@au.thebcr.com">info@au.thebcr.com</a> холбогдоно уу.</p>
<p>Та дээдэлсэн шинэчлэлтээс дагагч, манай вэб сайт руу холбогдох эсвэл info@au.thebcr.com хаяг руу имэйлээр холбогдож асуудлыг хэлэхийг хүсвэл туслаарай. Бид хэмжээнд хамгийн сайн үйлчилгээгээ олгож байна.</p>
<br />
Таньд баярлалаа,
<br />
<b>БСР</b>
<br />
</div>
', 'MyBCR-д шинэчлэлт хийх');
INSERT INTO cms."_TopicContent" ("Id", "TopicId", "CreatedOn", "UpdatedOn", "Language", "Title", "Author", "Content", "Subtitle") VALUES (11423, 11286, '2023-10-31 22:58:24.552707 +00:00', '2024-04-11 20:30:02.835721 +00:00', 'en-us', 'Client Daily Confirmation', 'system', e'
    <meta http-equiv="content-type" content="text/html;charset=utf-8" />
<table
  align="center"
  style="
    width: 900px;
    border-collapse: collapse;
    font-family: \'微软雅黑\';
    padding: 5px 0px;
    -moz-border-radius: 5px;
    -webkit-border-radius: 5px;
    border-radius: 5px;
    border: 0px #ddcebd solid;
    background: url(https://s3.amazonaws.com/bcr-img-new/email/docs_bg.png)
      repeat-y;
    background-position: right 0 top 0;
  "
>
  <tr>
    <td>
      <table style="width: 100%">
        <tr>
                    <td
                                            style="
                                                text-align: left;
                                                line-height: 40px;
                                                font-size: 32px;
                                                font-family: \\\'Times New Roman\\\', Times, serif;
                                            "
                                        >
                                            <img src="https://s3.amazonaws.com/bcr-img-new/bcr_logo.png" />
                                        </td>
                                    </tr>
                                </table>
                            </td>
                        </tr>
                        <tr>
                            <td>
                                <table style="width: 100%; font-size: 12px">
                                    <tr>
                                        <td style="width: 25%">
                                                                                    Account: <strong>@Model.AccountNumber</strong>
                                                                                </td>
                                                                                <td style="width: 25%">Name: <strong>@Model.NativeName</strong></td>
                                                                                <td style="width: 25%"></td>
                                                                                <td style="width: 25%; text-align: right">@Model.ReportDate.ToString("yyyy-MM-dd HH:mm:ss")</td>
                                                                            </tr>
                                                                        </table>
                                                                    </td>
                                                                </tr>
                                                                <tr>
                                                                    <td>
                                                                        <table
                                                                            style="
                                                                                width: 100%;
                                                                                font-size: 10px;
                                                                                text-align: right;
                                                                                line-height: 20px;
                                                                                border-collapse: collapse;
                                                                                border: 0px solid #cccccc;
                                                                            "
                                                                        >
                                                                            <tr>
                                                                                <td colspan="13" align="left"><strong>Closed Trades:</strong></td>
                                                                            </tr>
                                                                            <tr
                                                                                style="
                                                                                    background: #f5f5f5;
                                                                                    text-align: center;
                                                                                    border: 1px solid #cccccc;
                                                                                "
                                                                            >
                                                                                <td style="border: 1px solid #cccccc" width="7%">Ticket</td>
                                                                                <td style="border: 1px solid #cccccc" width="12%">Open Time</td>
                                                                                <td style="border: 1px solid #cccccc" width="7%">Type</td>
                                                                                <td style="border: 1px solid #cccccc" width="6%">Size</td>
                                                                                <td style="border: 1px solid #cccccc" width="7%">Item</td>
                                                                                <td style="border: 1px solid #cccccc" width="7%">Price</td>
                                                                                <td style="border: 1px solid #cccccc" width="7%">S/L</td>
                                                                                <td style="border: 1px solid #cccccc" width="7%">T/P</td>
                                                                                <td style="border: 1px solid #cccccc" width="12%">Close Time</td>
                                                                                <td style="border: 1px solid #cccccc" width="7%">Price</td>
                                                                                <td style="border: 1px solid #cccccc" width="7%">Commission</td>
                                                                                <td style="border: 1px solid #cccccc" width="7%">Swap</td>
                                                                                <td style="border: 1px solid #cccccc" width="7%">Trade P/L</td>
                                                                            </tr>
                                                                            @{ var color = new[] { "#FFFFFF;", "#EEEEEE;" }; var counter = 0; } @if
