INSERT INTO cms."_TopicContent" ("Id", "TopicId", "CreatedOn", "UpdatedOn", "Language", "Title", "Author", "Content", "Subtitle") VALUES (11467, 11286, '2024-01-04 07:50:48.582098 +00:00', '2024-05-22 01:00:01.659359 +00:00', 'zh-cn', 'Client Daily Confirmation', '', e'<meta http-equiv="content-type" content="text/html;charset=utf-8" />
<table
align="center"
style="
    width: 900px;
    border-collapse: collapse;
    font-family: \'微软雅黑\';
    padding: 5px 0px;
    -moz-border-radius: 5px;
    -webkit-border-radius: 5px;
    border-radius: 5px;
    border: 0px #ddcebd solid;
    background: url(https://s3.amazonaws.com/bcr-img-new/email/docs_bg.png)
    repeat-y;
    background-position: right 0 top 0;
"
>
<tr>
    <td>
    <table style="width: 100%">
        <tr>
        <td
            style="
            text-align: left;
            line-height: 40px;
            font-size: 32px;
            font-family: \'Times New Roman\', Times, serif;
            "
        >
            <img src="https://s3.amazonaws.com/bcr-img-new/bcr_logo.png" />
        </td>
        </tr>
    </table>
    </td>
</tr>
<tr>
    <td>
    <table style="width: 100%; font-size: 12px">
        <tr>
        <td style="width: 25%">
            账号：<strong>@Model.AccountNumber</strong>
        </td>
        <td style="width: 25%">姓名：<strong>@Model.NativeName</strong></td>
        <td style="width: 25%"></td>
        <td style="width: 25%; text-align: right">
            @Model.ReportDate.ToString("yyyy-MM-dd HH:mm:ss")
        </td>
        </tr>
    </table>
    </td>
</tr>
<tr>
    <td>
    <table
        style="
        width: 100%;
        font-size: 10px;
        text-align: right;
        line-height: 20px;
        border-collapse: collapse;
        border: 0px solid #cccccc;
        "
    >
        <tr>
        <td colspan="13" align="left"><strong>平仓单：</strong></td>
        </tr>
        <tr
        style="
            background: #f5f5f5;
            text-align: center;
            border: 1px solid #cccccc;
        "
        >
        <td style="border: 1px solid #cccccc" width="7%">单号</td>
        <td style="border: 1px solid #cccccc" width="12%">开仓时间</td>
        <td style="border: 1px solid #cccccc" width="7%">类型</td>
        <td style="border: 1px solid #cccccc" width="6%">单量</td>
        <td style="border: 1px solid #cccccc" width="7%">产品</td>
        <td style="border: 1px solid #cccccc" width="7%">价格</td>
        <td style="border: 1px solid #cccccc" width="7%">止损</td>
        <td style="border: 1px solid #cccccc" width="7%">止盈</td>
        <td style="border: 1px solid #cccccc" width="12%">平仓时间</td>
        <td style="border: 1px solid #cccccc" width="7%">平仓价格</td>
        <td style="border: 1px solid #cccccc" width="7%">佣金</td>
        <td style="border: 1px solid #cccccc" width="7%">利息</td>
        <td style="border: 1px solid #cccccc" width="7%">交易盈亏</td>
        </tr>
        @{ var color = new[] { "#FFFFFF;", "#EEEEEE;" }; var counter = 0; } @if
        (Model.ClosedTrades != null && Model.ClosedTrades.Count > 0) { foreach
        (var trade in Model.ClosedTrades) {
        <tr style="background: @color[counter++ % 2]">
        <td style="border: 1px solid #cccccc">@trade.Ticket</td>
        <td style="border: 1px solid #cccccc">
            @trade.OpenAt.ToString("yyyy-MM-dd HH:mm:ss")
        </td>
                    <td style="border: 1px solid #cccccc">@if(trade.Cmd == 1) { <text>Sell</text> } else if (trade.Cmd == 0){ <text>Buy</text>
                    }
                    else if (trade.Cmd == 6){ <text>Balance</text> }
                    </td>
                        
                                            @if (trade.Cmd < 2) {
                                            <td style="border: 1px solid #cccccc">@trade.Volume</td>
                                            <td style="border: 1px solid #cccccc">@trade.Symbol</td>
                                            <td style="border: 1px solid #cccccc">
                                                @string.Format("{0:F" + trade.Digits + "}", trade.OpenPrice ?? 0)
                                            </td>
                                            <td style="border: 1px solid #cccccc">
                                                @string.Format("{0:F" + trade.Digits + "}", trade.Sl)
                                            </td>
                                            <td style="border: 1px solid #cccccc">
                                                @string.Format("{0:F" + trade.Digits + "}", trade.Tp)
                                            </td>
                                            <td style="border: 1px solid #cccccc">
                                                @trade.CloseAt.ToString("yyyy-MM-dd HH:mm:ss")
                                            </td>
                                            <td style="border: 1px solid #cccccc">
                                                @string.Format("{0:F" + trade.Digits + "}", trade.ClosePrice ?? 0)
                                            </td>
                                            <td style="border: 1px solid #cccccc">
                                                @string.Format("{0:N2}", trade.Commission)
                                            </td>
                                            <td style="border: 1px solid #cccccc">
                                                @string.Format("{0:N2}", trade.Swaps)
                                            </td>
                                            } else if (trade.Cmd > 5) {
                                            <td style="border: 1px solid #cccccc" colspan="9" align="right">
                        @trade.Comment
                                                                    </td>
                                                                    }
                                                
                                                                    <td style="border: 1px solid #cccccc">
                                                                        @string.Format("{0:N2}", trade.Profit)
                                                                    </td>
                                                                </tr>
                                                                } } else {
                                                                <tr style="background: #ffffff; text-align: center">
                                                                    <td style="border: 1px solid #cccccc" colspan="13">无平仓单</td>
                                                                </tr>
                                                                }
                                                
                                                                <tr style="background: #eeeeee">
                                                                    <td style="border: 1px solid #cccccc" colspan="10"></td>
                                                                    <td style="border: 1px solid #cccccc">
                                                                        @string.Format("{0:N2}", Model.ClosedTradeSummary.Commission)
                                                                    </td>
                                                                    <td style="border: 1px solid #cccccc">
                                                                        @string.Format("{0:N2}", Model.ClosedTradeSummary.Swaps)
                                                                    </td>
                                                                    <td style="border: 1px solid #cccccc">
                                                                        @string.Format("{0:N2}", Model.ClosedTradeSummary.Profit)
                                                                    </td>
                                                                </tr>
                                                            </table>
                                                        </td>
                                                    </tr>
                                                    <tr>
                                                        <td>
                                                            <table style="width: 100%; font-size: 12px">
                                                                <tr>
                                                                    <td>
                                                                        <strong
                                                                            >出入金: @string.Format("{0:N2}", Model.ClosedTradeSummary.Deposit)</strong
                                                                        >
                                                                    </td>
                                                                    <td>
                                                                        <strong
                                                                            >信用: @string.Format("{0:N2}",
                                                                            Model.ClosedTradeSummary.Credit)</strong
                                                                        >
                                                                    </td>
                                                                    <td style="text-align: right">
                                                                        <strong
                                                                            >交易盈亏: @string.Format("{0:N2}",
                                                                            Model.ClosedTradeSummary.TotalProfit)</strong
                                                                        >
                                                                    </td>
                                                                </tr>
                                                            </table>
                                                        </td>
                                                    </tr>
                                                    <tr>
                                                        <td>&nbsp;</td>
                                                    </tr>
                                                    <tr>
                                                        <td>
                                                            <table
                                                                style="
                                                                    width: 100%;
                                                                    font-size: 10px;
                                                                    text-align: right;
                                                                    line-height: 20px;
                                                                    border-collapse: collapse;
                                                                    border: 0px solid #cccccc;
                                                                "
                                                            >
                                                                <tr>
                                                                    <td colspan="12" align="left"><strong>开仓单:</strong></td>
                                                                </tr>
                                                                <tr
                                                                    style="
                                                                        background: #f5f5f5;
                                                                        text-align: center;
                                                                        border: 1px solid #cccccc;
                                                                        font-size: 11px;
                                                                    "
                                                                >
                                                                    <td style="border: 1px solid #cccccc" width="7%">单号</td>
                                                                    <td style="border: 1px solid #cccccc" width="12%">开仓时间</td>
                                                                    <td style="border: 1px solid #cccccc" width="7%">类型</td>
                                                                    <td style="border: 1px solid #cccccc" width="6%">单量</td>
                                                                    <td style="border: 1px solid #cccccc" width="7%">产品</td>
                                                                    <td style="border: 1px solid #cccccc" width="7%">价格</td>
                                                                    <td style="border: 1px solid #cccccc" width="7%">止损</td>
                                                                    <td style="border: 1px solid #cccccc" width="7%">止盈</td>
                                                                    <td style="border: 1px solid #cccccc" width="12%">平仓时间</td>
                                                                    <td style="border: 1px solid #cccccc" width="7%">价格</td>
                                                                    <td style="border: 1px solid #cccccc" width="7%">佣金</td>
                                                                    <td style="border: 1px solid #cccccc" width="7%">利息</td>
                                                                    <td style="border: 1px solid #cccccc" width="7%">交易盈亏</td>
                                                                </tr>
                                                                @{ counter = 0; } @if (Model.OpenTrades != null &&
                                                                Model.OpenTrades.Count > 0) { foreach (var trade in Model.OpenTrades) {
                                                                if (trade.Cmd < 2) {
                                                                <tr style="background: @color[counter++ % 2]">
                                                                    <td style="border: 1px solid #cccccc">@trade.Ticket</td>
                                                                    <td style="border: 1px solid #cccccc">
                                                                        @trade.OpenAt.ToString("yyyy-MM-dd HH:mm:ss")
                                                                    </td>
                                                                    <td style="border: 1px solid #cccccc">
                                                                        @if(trade.Cmd == 1) { <text>Sell</text> } else { <text>Buy</text> }
                                                                    </td>
                                                                    <td style="border: 1px solid #cccccc">
                                                                        @string.Format("{0:f2}", trade.Volume)
                                                                    </td>
                                                                    <td style="border: 1px solid #cccccc">@trade.Symbol</td>
                                                                    <td style="border: 1px solid #cccccc">
                                                                        @string.Format("{0:F" + trade.Digits + "}", trade.OpenPrice ?? 0)
                                                                    </td>
                                                                    <td style="border: 1px solid #cccccc">
                                                                        @string.Format("{0:F" + trade.Digits + "}", trade.Sl)
                                                                    </td>
                                                                    <td style="border: 1px solid #cccccc">
                                                                        @string.Format("{0:F" + trade.Digits + "}", trade.Tp)
                                                                    </td>
                                                                    <td style="border: 1px solid #cccccc"></td>
                                                                    <td style="border: 1px solid #cccccc">
                                                                        @string.Format("{0:F" + trade.Digits + "}", trade.CurrentPrice ?? 0)
                                                                    </td>
                                                                    <td style="border: 1px solid #cccccc">
                                                                        @string.Format("{0:N2}", trade.Commission)
                                                                    </td>
                                                                    <td style="border: 1px solid #cccccc">
                                                                        @string.Format("{0:N2}", trade.Swaps)
                                                                    </td>
                                                                    <td style="border: 1px solid #cccccc">
                                                                        @string.Format("{0:N2}", trade.Profit)
                                                                    </td>
                                                                </tr>
                                                                } } } else {
                                                                <tr style="background: #ffffff; text-align: center">
                                                                    <td style="border: 1px solid #cccccc" colspan="13">无开仓单</td>
                                                                </tr>
                                                                }
                                                
                                                                <tr style="background: #eeeeee">
                                                                    <td style="border: 1px solid #cccccc" colspan="10"></td>
                                                                    <td style="border: 1px solid #cccccc">
                                                                        @string.Format("{0:N2}", Model.OpenTradeSummary.Commission)
                                                                    </td>
                                                                    <td style="border: 1px solid #cccccc">
                                                                        @string.Format("{0:N2}", Model.OpenTradeSummary.Swaps)
                                                                    </td>
                                                                    <td style="border: 1px solid #cccccc">
                                                                        @string.Format("{0:N2}", Model.OpenTradeSummary.Profit)
                                                                    </td>
                                                                </tr>
                                                            </table>
                                                        </td>
                                                    </tr>
                                                    <tr>
                                                        <td>
                                                            <table style="width: 100%; font-size: 12px; border-collapse: collapse">
                                                                <tr>
                                                                    <td><strong>&nbsp;</strong></td>
                                                                    <td align="right">
                                                                        <strong
                                                                            >浮动盈亏:&nbsp;&nbsp;&nbsp;&nbsp; @string.Format("{0:N2}", Model.OpenTradeSummary.TotalProfit)</strong
                                                                        >
                                                                    </td>
                                                                </tr>
                                                            </table>
                                                        </td>
                                                    </tr>
                                                    <tr>
                                                        <td>&nbsp;</td>
                                                    </tr>
                                                    <tr>
                                                        <td>
                                                            <table
                                                                style="
                                                                    width: 100%;
                                                                    font-size: 10px;
                                                                    text-align: right;
                                                                    line-height: 20px;
                                                                    border-collapse: collapse;
                                                                "
                                                            >
                                                                <tr>
                                                                    <td colspan="12" align="left"><strong>待发单:</strong></td>
                                                                </tr>
                                                                <tr style="background: #eeeeee; text-align: center">
                                                                    <td style="border: 1px solid #cccccc" width="7%">单号</td>
                                                                    <td style="border: 1px solid #cccccc" width="12%">开仓时间</td>
                                                                    <td style="border: 1px solid #cccccc" width="7%">类型</td>
                                                                    <td style="border: 1px solid #cccccc" width="6%">单量</td>
                                                                    <td style="border: 1px solid #cccccc" width="7%">产品</td>
                                                                    <td style="border: 1px solid #cccccc" width="7%">价格</td>
                                                                    <td style="border: 1px solid #cccccc" width="7%">止损</td>
                                                                    <td style="border: 1px solid #cccccc" width="7%">止盈</td>
                                                                    <td style="border: 1px solid #cccccc" width="12%">市价</td>
                                                                    <td style="border: 1px solid #cccccc" width="28%"></td>
                                                                </tr>
                                                                @{ counter = 0; } @if (Model.PendingTrades != null &&
                                                                Model.PendingTrades.Count > 0) { foreach (var trade in
                                                                Model.PendingTrades) {
                                                                <tr style="background: @color[counter++ % 2]">
                                                                    <td style="border: 1px solid #cccccc">@trade.Ticket</td>
                                                                    <td style="border: 1px solid #cccccc">
                                                                        @trade.OpenAt.ToString("yyyy-MM-dd HH:mm:ss")
                                                                    </td>
                                                                    <td style="border: 1px solid #cccccc">
                                                                        @if(trade.Cmd == 1) { <text>Sell</text> } else { <text>Buy</text> }
                                                                    </td>
                                                                    <td style="border: 1px solid #cccccc">
                                                                        @string.Format("{0:f2}", trade.Volume)
                                                                    </td>
                                                                    <td style="border: 1px solid #cccccc">@trade.Symbol</td>
                                                                    <td style="border: 1px solid #cccccc">
                                                                        @string.Format("{0:F" + trade.Digits + "}", trade.OpenPrice ?? 0)
                                                                    </td>
                                                                    <td style="border: 1px solid #cccccc">
                                                                        @string.Format("{0:F" + trade.Digits + "}", trade.Sl)
                                                                    </td>
                                                                    <td style="border: 1px solid #cccccc">
                                                                        @string.Format("{0:F" + trade.Digits + "}", trade.Tp)
                                                                    </td>
                                                                    <td style="border: 1px solid #cccccc">
                                                                        @string.Format("{0:F" + trade.Digits + "}", trade.ClosePrice ?? 0)
                                                                    </td>
                                                                    <td style="border: 1px solid #cccccc">@trade.Comment</td>
                                                                </tr>
                                                                } } else {
                                                                <tr style="background: #eeeeee; text-align: center">
                                                                    <td style="border: 1px solid #cccccc" colspan="10">无待发单</td>
                                                                </tr>
                                                                }
                                                            </table>
                                                        </td>
                                                    </tr>
                                                    <tr>
                                                        <td>
                                                            <table
                                                                style="
                                                                    width: 100%;
                                                                    font-size: 12px;
                                                                    text-align: right;
                                                                    line-height: 20px;
                                                                "
                                                            >
                                                                <tr>
                                                                    <td colspan="4" align="left"><strong>帐户摘要:</strong></td>
                                                                </tr>
                                                                <tr>
                                                                    <td style="width: 25%; text-align: left">上期结存:</td>
                                                                    <td style="width: 25%">
                                                                        <strong>@string.Format("{0:N2}", Model.Summary.PrevBalance)</strong>
                                                                    </td>
                                                                    <td style="width: 25%">浮动盈亏:</td>
                                                                    <td style="width: 25%; text-align: right">
                                                                        <strong
                                                                            >@string.Format("{0:N2}",  Model.OpenTradeSummary.TotalProfit)</strong
                                                                        >
                                                                    </td>
                                                                </tr>
                                                                <tr>
                                                                    <td style="width: 25%; text-align: left">平仓盈亏:</td>
                                                                    <td style="width: 25%">
                                                                        <strong
                                                                            >@string.Format("{0:N2}", Model.ClosedTradeSummary.Profit)</strong
                                                                        >
                                                                    </td>
                                                                    <td style="width: 25%">信用:</td>
                                                                    <td style="width: 25%; text-align: right">
                                                                        <strong>@string.Format("{0:N2}", Model.Summary.Credit)</strong>
                                                                    </td>
                                                                </tr>
                                                                <tr>
                                                                    <td style="width: 25%; text-align: left">出入金:</td>
                                                                    <td style="width: 25%">
                                                                        <strong
                                                                            >@string.Format("{0:N2}", Model.Summary.Deposit)</strong
                                                                        >
                                                                    </td>
                                                                    <td style="width: 25%">浮动资金:</td>
                                                                    <td style="width: 25%; text-align: right">
                                                                        <strong
                                                                            >@string.Format("{0:N2}", (Model.Summary.Balance +
                                                                            Model.Summary.Credit +
                                                                            Model.OpenTradeSummary.TotalProfit))</strong
                                                                        >
                                                                    </td>
                                                                </tr>
                                                                <tr>
                                                                    <td style="width: 25%; text-align: left">余额:</td>
                                                                    <td style="width: 25%">
                                                                        <strong>@string.Format("{0:N2}", Model.Summary.Balance)</strong>
                                                                    </td>
                                                                    <td style="width: 25%">保证金:</td>
                                                                    <td style="width: 25%; text-align: right">
                                                                        <strong>@string.Format("{0:N2}", Model.Summary.Margin)</strong>
                                                                    </td>
                                                                </tr>
                                                                <tr>
                                                                    <td style="width: 25%">&nbsp;</td>
                                                                    <td style="width: 25%">&nbsp;</td>
                                                                    <td style="width: 25%">可用保证金:</td>
                                                                    <td style="width: 25%; text-align: right">
                                                                        <strong
                                                                            >@string.Format("{0:N2}", (Model.Summary.Balance +
                                                                            Model.Summary.Credit + Model.OpenTradeSummary.TotalProfit -
                                                                            Model.Summary.Margin))</strong
                                                                        >
                                                                    </td>
                                                                </tr>
                                                            </table>
                                                        </td>
                                                    </tr>
                                                    <tr>
                                                        <td>&nbsp;</td>
                                                    </tr>
                                                    <tr>
                                                        <td align="left" style="font-size: 12px">此致</td>
                                                    </tr>
                                                    <tr>
                                                        <td align="left" style="font-size: 12px">BCR</td>
                                                    </tr>
                                                    <tr>
                                                        <td align="center" style="font-size: 10px">
                                                            如果本结算单有误，请在48小时内向我们报告。否则，本结算单将被视为您已确认。
                                                        </td>
                                                    </tr>
                                                    <tr>
                                                        <td align="center" style="font-size: 10px">
                                                            所有浮动盈亏和权益数字是根据报告生成时的工具价格计算的，可能与工具的实际收盘价格不同。
                                                        </td>
                                                    </tr>
                                                </table>
                                                ', '');
INSERT INTO cms."_TopicContent" ("Id", "TopicId", "CreatedOn", "UpdatedOn", "Language", "Title", "Author", "Content", "Subtitle") VALUES (10072, 11253, '2023-08-16 18:17:53.290543 +00:00', '2023-08-23 22:25:17.221442 +00:00', 'mn-mn', 'MT4 нууц үг өөрчлөгдсөн', '', e'<div style="font-size: 12px; line-height: 20px">
  <p style="font-size: 16px; font-weight: 700; line-height: 24px">
    Удахгүй Хэрэглэгч,
  </p>
  <p>
    Таны нууц үг амжилттай өөрчилсөн бөгөөд {{$wl->date_on_letter->format(\'F jS, Y\')}}
    -нд таны BCR ProTrader MT4 дансны мэдээллийг доорхидаа оруулсан байна:
  </p>
  <table class="letter-table"
         style="table-layout: fixed; line-height: 24px; margin-left: auto; margin-right: auto; text-align: left; padding: 8px; float: none"
         bgcolor="#f2f2f2" align="left">
    <tr>
      <th style="padding-left: 24px; padding-right: 24px; color: #383d49; white-space: nowrap">
        Миний MyBCR Данс:</th>
      <td style="padding-left: 24px; padding-right: 24px; word-wrap: break-word">
        {{$wl->user->email}}</td>
    </tr>
    <tr>
      <th style="padding-left: 24px; padding-right: 24px; color: #383d49; white-space: nowrap">
        MT4 Данс:</th>
      <td style="padding-left: 24px; padding-right: 24px; word-wrap: break-word">
        {{$wl->user->login}}</td>
    </tr>
    <tr>
      <th style="padding-left: 24px; padding-right: 24px; color: #383d49; white-space: nowrap">
        Трейд Дансны Нууц үг:</th>
      <td style="padding-left: 24px; padding-right: 24px; word-wrap: break-word">
        {{$wl->decryptPassword}}</td>
    </tr>
    <tr>
      <th style="padding-left: 24px; padding-right: 24px; color: #383d49; white-space: nowrap">
        MT4 Сервер:</th>
      <td style="padding-left: 24px; padding-right: 24px; word-wrap: break-word">BCR-REAL
      </td>
    </tr>
  </table>
  <p style="font-weight: 700; line-height: 24px; font-size: 14px">Дараах зааврыг дагаарайж
    үз:</p>
  <ol>
    <li>Та хувийн мэдээллийг авахыг хүсвэл бидний <a target="_blank"
                                            href="https://au.thebcr.com/en"
                                            style="color: #383d49; text-decoration: none; font-weight: 700">үнэгүй Вэбсайт</a>-н
      Танилцуулга хэсэг руу орж тогтмол ашиглаж болно.</li>
    <li>Миний <a target="_blank" href="https://client-portal.thebcr.com/"
                     style="color: #383d49; text-decoration: none; font-weight: 700">MyBCR</a>-д нэвтэрнэ үү, Таталт табыг сонгоод BCR хөрөнгийн салбарт орж татаарай.</li>
    <li>Миний <a target="_blank" href="https://client-portal.thebcr.com/"
                     style="color: #383d49; text-decoration: none; font-weight: 700">MYBCR</a>-д нэвтэрнэ үү, Таталт табыг сонгоод татвар сонголт хийгээрэй.</li>
    <li>BCR Trader (MT4 Платформ) руу нэвтрэхэд эсвэл та гар утас ашиглаж байгаа бол, Mobile MetaTrader 4-д
      BCR-Real Серверийг сонгоод дансны дугаар болон Трейд Дансны Нууц үгийг оруулж ашиглах боломжтой.</li>
  </ol>
  <p>
    Тэмдэглэл: Инвестор Нууц үг нь зөвхөн хувийн төлөвлөгөөр, худалдаа хийх боломжгүй.
    Хэрвээ та телефон утас дээрээ худалдаа хийхийг хүсвэл, дараах утас дугаар руу холбогдоно уу:</p>
  <p style="font-weight: 600; text-align: center">+44 3300010590 <br>
  </p>
  <p>Тэлэвэл холбогдох боломжгүй болсон буюу гүйцэтгэлээр ажиллахгүй бол эсвэл
    худалдааны платформ ажиллагааг хийх боломжгүй бол, утасны худалдаа хийх үйлчилгээг
    ашиглаж болно.
  </p>
</div>
', '');
INSERT INTO cms."_TopicContent" ("Id", "TopicId", "CreatedOn", "UpdatedOn", "Language", "Title", "Author", "Content", "Subtitle") VALUES (10075, 11261, '2023-08-16 18:21:43.902689 +00:00', '2023-08-16 18:21:43.902689 +00:00', 'mn-mn', 'Үйлчлүүлэгчийн данс бүртгэлтэй', '', e'<div style="font-size: 12px; line-height: 20px">
  <p style="font-size: 16px; font-weight: 700; line-height: 24px">
    Уважаемый партнер BCR,
  </p>
  <p>
    Это письмо для уведомления о том, что ваш клиент открыл
    новый торговый счет в BCR. Номер его счета предоставлен
    ниже:
  </p>
  <table
         class="letter-table"
         style="
                table-layout: fixed;
                line-height: 24px;
                margin-left: auto;
                margin-right: auto;
                text-align: left;
                padding: 8px;
                float: none;
                "
         bgcolor="#f2f2f2"
         align="left"
         >
    <tr>
      <th
          style="
                 padding-left: 24px;
                 padding-right: 24px;
                 color: #383d49;
                 white-space: nowrap;
                 "
          >
        Номер счета:
      </th>
      <td
          style="
                 padding-left: 24px;
                 padding-right: 24px;
                 word-wrap: break-word;
                 "
          >
        {{AccountNumber}}
      </td>
    </tr>
    <tr>
      <th
          style="
                 padding-left: 24px;
                 padding-right: 24px;
                 color: #383d49;
                 white-space: nowrap;
                 "
          >
        Имя счета:
      </th>
      <td
          style="
                 padding-left: 24px;
                 padding-right: 24px;
                 word-wrap: break-word;
                 "
          >
        {{NativeName}}
      </td>
    </tr>
    <tr>
      <th
          style="
                 padding-left: 24px;
                 padding-right: 24px;
                 color: #383d49;
                 white-space: nowrap;
                 "
          >
        Дата открытия счета:
      </th>
      <td
          style="
                 padding-left: 24px;
                 padding-right: 24px;
                 word-wrap: break-word;
                 "
          >
        {{Date}}
      </td>
    </tr>
  </table>
  <p>
    Информация о счете для торговой платформы была отправлена
    на электронную почту вашего клиента. Пароль вашего клиента
    для доступа только для чтения - ({{ReadOnlyCode}}).
  </p>
</div>
', 'таны үйлчлүүлэгчийн зөвхөн унших нууц үгийг тохирууллаа');
INSERT INTO cms."_TopicContent" ("Id", "TopicId", "CreatedOn", "UpdatedOn", "Language", "Title", "Author", "Content", "Subtitle") VALUES (10076, 11262, '2023-08-16 18:22:45.028532 +00:00', '2023-08-16 18:22:45.028532 +00:00', 'mn-mn', 'Баримт бичгийг татгалзсан', '', e'<div>Уважаемый(ая) {{NativeName}}</div>

<p>С сожалением сообщаем, что ваше загруженное фото не прошло нашу процедуру верификации. Мы обязаны соблюдать строгие руководящие принципы безопасности и политику, чтобы обеспечить конфиденциальность и безопасность всех наших пользователей.</p>
', '');
INSERT INTO cms."_TopicContent" ("Id", "TopicId", "CreatedOn", "UpdatedOn", "Language", "Title", "Author", "Content", "Subtitle") VALUES (10078, 10001, '2023-08-16 18:27:15.276616 +00:00', '2023-08-16 18:27:15.276616 +00:00', 'jp-jp', 'アカウント申請確認メール', '', e'<div style="font-size: 12px; line-height: 20px">
  <p style="font-size: 16px; font-weight: 700; line-height: 24px">
    お客様 {{UserName}} 様へ,
  </p>
  <p style="font-size:14px;">
    BCR アカウントのオンライン申し込みを開始いただき、ありがとうございます。これにより、数千人のクライアントの一員として、BCR は外国為替、貴金属、株式、商品 CFD を取引するための信頼できるプロバイダとして選ばれています。新しい BCR アカウントのメールアドレスを確認し、アカウントを有効化するために、以下のリンクをクリックしてください。
  </p>
  <p>
    <a href="{{CallbackUrl}}" target="_blank" style="color: #383d49;text-decoration: none;font-weight: 700;">こちらをクリック</a>
    もしくは、ブラウザのアドレスバーにリンクをコピーしてください:
  </p>
  <div style="margin-left: auto;margin-right: auto;text-align: center;font-style: italic;">
    {{CallbackUrl}}
  </div>
  <p>アカウントのセキュリティのため、このリンクは <strong>10 分間</strong> 有効です。このメールはシステムによって自動生成されるものですので、直接返信しないでください。</p>
</div>', 'URL を使用してメールアドレスを確認してください');
INSERT INTO cms."_TopicContent" ("Id", "TopicId", "CreatedOn", "UpdatedOn", "Language", "Title", "Author", "Content", "Subtitle") VALUES (10079, 10002, '2023-08-16 18:28:02.856692 +00:00', '2023-08-16 18:28:02.856692 +00:00', 'jp-jp', 'パスワードのリセット', '', e'お客様 {{UserName}} 様へ、

<p>
  <a href="{{CallbackUrl}}" target="_blank" style="color: #383d49;text-decoration: none;font-weight: 700;">こちらをクリック</a>
  もしくは以下のアドレスをブラウザのアドレスバーにコピーしてください：
</p>
<div style="margin-left: auto;margin-right: auto;text-align: center;font-style: italic;">
  {{CallbackUrl}}
</div>
<p>アカウントのセキュリティのため、このリンクは <strong>10 分間</strong> 有効です。このメールはシステムによって自動生成されるものですので、直接返信しないでください。</p>', 'パスワードのリセットリンク');
INSERT INTO cms."_TopicContent" ("Id", "TopicId", "CreatedOn", "UpdatedOn", "Language", "Title", "Author", "Content", "Subtitle") VALUES (10080, 11239, '2023-08-16 18:29:01.738637 +00:00', '2023-08-16 18:29:01.738637 +00:00', 'jp-jp', 'MyBCR 重要なメッセージ', '', e'<div style="font-size: 14px; line-height: 20px">
<p><b>お知らせ：</b></p>
<p>MyBCRのアップグレードに伴い、クライアントポータルは<b>2023年7月21日金曜日のマーケットクローズ後</b>から利用できなくなり、通常通りの利用が<b>2023年7月24日月曜日のマーケットオープン前</b>に再開されます。</p>
<p>週末にクライアントサービスが必要な場合は、<a href="mailto:info@au.thebcr.com">info@au.thebcr.com</a> にご連絡いただくか、BCRサポートまでお問い合わせください。</p>
<p>上記のアップグレードに関するご質問がございましたら、オンラインチャットでお問い合わせいただくか、<a href="mailto:info@au.thebcr.com">info@au.thebcr.com</a> までメールでお問い合わせください。お客様に最高の金融サービスを提供できることを楽しみにしております。</p>
<br />
敬具,
<br />
<b>BCR</b>
<br />
</div>', 'MyBCR へのアップグレード');
INSERT INTO cms."_TopicContent" ("Id", "TopicId", "CreatedOn", "UpdatedOn", "Language", "Title", "Author", "Content", "Subtitle") VALUES (11578, 11329, '2024-03-26 18:41:02.563141 +00:00', '2024-03-26 18:55:36.508579 +00:00', 'en-us', 'Transfer Failed', 'system', e'<div style="font-size: 12px; line-height: 20px">
