INSERT INTO cms."_TopicContent" ("Id", "TopicId", "CreatedOn", "UpdatedOn", "Language", "Title", "Author", "Content", "Subtitle") VALUES (10082, 11245, '2023-08-16 18:32:04.680987 +00:00', '2023-08-16 18:32:04.680987 +00:00', 'jp-jp', 'レバレッジが変更されました', '', e'
<div style="font-size: 12px; line-height: 20px">
<p style="font-size: 16px; font-weight: 700; line-height: 24px">お客様へ</p>
<p>BCR取引口座のレバレッジ変更リクエストを受け取り、処理しました。この変更は直ちに有効となり、今後のすべてのオープンポジションに新しいレバレッジが反映されます。</p>
<table class="letter-table"
style="table-layout: fixed; line-height: 24px; margin-left: auto; margin-right: auto; text-align: left; padding: 8px; float: none"
bgcolor="#f2f2f2" align="left">
<tr>
<th style="padding-left: 24px; padding-right: 24px; color: #383d49; white-space: nowrap">アカウント番号：</th>
<td style="padding-left: 24px; padding-right: 24px; word-wrap: break-word">{{AccountNumber}}</td>
</tr>
<tr>
<th style="padding-left: 24px; padding-right: 24px; color: #383d49; white-space: nowrap">口座名義：</th>
<td style="padding-left: 24px; padding-right: 24px; word-wrap: break-word">{{NativeName}}</td>
</tr>
<tr>
<th style="padding-left: 24px; padding-right: 24px; color: #383d49; white-space: nowrap">新しいレバレッジ：</th>
<td style="padding-left: 24px; padding-right: 24px; word-wrap: break-word">{{Leverage}} :1</td>
</tr>
<tr>
<th style="padding-left: 24px; padding-right: 24px; color: #383d49; white-space: nowrap">コメント：</th>
<td style="padding-left: 24px; padding-right: 24px; word-wrap: break-word">レバレッジは{{OriginalLeverage}} :1から更新されました。</td>
</tr>
</table>
</div>', '');
INSERT INTO cms."_TopicContent" ("Id", "TopicId", "CreatedOn", "UpdatedOn", "Language", "Title", "Author", "Content", "Subtitle") VALUES (10085, 11248, '2023-08-16 18:36:00.606683 +00:00', '2023-08-16 18:36:00.606683 +00:00', 'jp-jp', 'デポジットリンク', '', e'
<div style="font-size: 12px; line-height: 20px">
  <p style="font-size: 16px; font-weight: 700; line-height: 24px">お客様へ</p>
  <div style="padding: 12px; background-color: #f2f2f2">
    <p style="line-height: 24px; font-size: 14px; color: #383d49; font-weight: 600;">入金情報</p>
    <p>以下はBCRの入金リンクです。支払いを行うには、リンクをクリックし、指示に従って操作してください。</p>
    <p>参照番号: {{$deposit->ref_id}}<br />入金金額: US${{ number_format($deposit->amount, 2)}}</p>
    <div style="font-style: italic">
      <a href="{{$payLink}}" target="_blank" style="color: #383d49; text-decoration: none; font-weight: 700;">{{$payLink}}</a>
    </div>
    <p>このリンクの有効期限は20分です。できるだけ早くご利用ください。</p>
    <p style="color: #cc1f1a; font-weight: 600">注意：<br />
      このリンクでは、支払い通貨が香港ドル（HKD）で表示されます。要求された入金金額は米ドル（USD）からHKDに変換され、HKDの取引金額が表示されます。銀行カードで支払うことを選択した後、UnionPayは自動的にHKDをRMBに変換し、支払いページに実際に支払われるRMB金額が表示されます。</p>
  </div>
</div>', 'リンク');
INSERT INTO cms."_TopicContent" ("Id", "TopicId", "CreatedOn", "UpdatedOn", "Language", "Title", "Author", "Content", "Subtitle") VALUES (10086, 11249, '2023-08-16 18:37:30.361010 +00:00', '2023-08-23 20:20:54.954493 +00:00', 'jp-jp', '入金通知書', '', e'<div style="font-size:12px;line-height:20px">
