INSERT INTO cms."_TopicContent" ("Id", "TopicId", "CreatedOn", "UpdatedOn", "Language", "Title", "Author", "Content", "Subtitle") VALUES (10090, 11253, '2023-08-16 18:42:22.427068 +00:00', '2023-08-23 22:25:24.616445 +00:00', 'jp-jp', 'MT4のパスワードが変更されました', '', e'
<div style="font-size:12px;line-height:20px">
  <p style="font-size:16px;font-weight:700;line-height:24px">お客様へ</p>
  <p>お知らせいたしますが、お客様のアカウントパスワードは{{$wl->date_on_letter->format(\'F jS, Y\')}}に変更されました。BCR ProTrader MT4アカウントの詳細は以下の通りです：</p>
  <table class="letter-table"
         style="table-layout:fixed;line-height:24px;margin-left:auto;margin-right:auto;text-align:left;padding:8px;float:none"
         bgcolor="#f2f2f2" align="left">
    <tr>
      <th
          style="padding-left:24px;padding-right:24px;color:#383d49;white-space:nowrap">
        MyBCRアカウント：</th>
      <td style="padding-left:24px;padding-right:24px;word-wrap:break-word">
        {{$wl->user->email}}</td>
    </tr>
    <tr>
      <th
          style="padding-left:24px;padding-right:24px;color:#383d49;white-space:nowrap">
        MT4アカウント：</th>
      <td style="padding-left:24px;padding-right:24px;word-wrap:break-word">
        {{$wl->user->login}}</td>
    </tr>
    <tr>
      <th
          style="padding-left:24px;padding-right:24px;color:#383d49;white-space:nowrap">
        取引口座のパスワード：</th>
      <td style="padding-left:24px;padding-right:24px;word-wrap:break-word">
        {{$wl->decryptPassword}}</td>
    </tr>
    <tr>
      <th
          style="padding-left:24px;padding-right:24px;color:#383d49;white-space:nowrap">
        MT4サーバー：</th>
      <td style="padding-left:24px;padding-right:24px;word-wrap:break-word">BCR-REAL
      </td>
    </tr>
  </table>
  <p style="font-weight:700;line-height:24px;font-size:14px">以下の手順に従って、今すぐ取引を開始してください：</p>
  <ol>
    <li><a target="_blank"
           href="https://au.thebcr.com/en"
           style="color:#383d49;text-decoration:none;font-weight:700">公式ウェブサイト</a>のプロモーションタブをご覧になり、さまざまなBCRプロモーションについて詳しく学びましょう。</li>
    <li><a target="_blank" href="https://client-portal.thebcr.com/"
           style="color:#383d49;text-decoration:none;font-weight:700">MyBCR</a>にログインし、ダウンロードタブに移動してBCR取引プラットフォームをダウンロードします。</li>
    <li><a target="_blank" href="https://client-portal.thebcr.com/"
           style="color:#383d49;text-decoration:none;font-weight:700">MYBCR</a>にログインし、マイデポジットに移動して入金オプションを選択します。</li>
    <li>BCR Trader（MT4プラットフォーム）にログインするか、モバイルデバイスを使用している場合は、Mobile MetaTrader 4でBCR-Real Serverを選択し、上記の口座番号と取引パスワードを使用します。</li>
  </ol>
  <p>投資家パスワードは読み取り専用で、取引の非取引アクセスを提供します。電話で取引注文を行いたい場合は、以下の番号にお問い合わせいただけます：</p>
  <p style="font-weight:600;text-align:center">+44 3300010590 <br>
  </p>
  <p>電話取引サービスは、ネットワーク接続の問題がある場合や取引プラットフォームが正常に動作しない場合にのみご利用いただけます。</p>
</div>', '');
