INSERT INTO cms."_TopicContent" ("Id", "TopicId", "CreatedOn", "UpdatedOn", "Language", "Title", "Author", "Content", "Subtitle") VALUES (10096, 10001, '2023-08-16 18:50:52.125512 +00:00', '2023-08-16 18:50:52.125512 +00:00', 'vi-vn', ' Email xác nhận đăng ký tài khoản', '', e'
<div style="font-size: 12px; line-height: 20px">
  <p style="font-size: 16px; font-weight: 700; line-height: 24px">
    Kính gửi Quý khách hàng {{UserName}},
  </p>
<p style="font-size:14px;">
Chúng tôi xin chân thành cảm ơn Quý khách đã bắt đầu quá trình đăng ký tài khoản trực tuyến tại BCR. Việc này đồng nghĩa với việc Quý khách đang gia nhập hàng ngàn khách hàng đã chọn BCR là đối tác tin cậy để giao dịch Forex, Kim loại quý, Cổ phiếu và CFD hàng hóa. Để xác nhận địa chỉ email của Quý khách và kích hoạt tài khoản BCR mới, vui lòng nhấp vào liên kết bên dưới.
</p>
  <p>
    <a href="{{CallbackUrl}}" target="_blank" style="color: #383d49;text-decoration: none;font-weight: 700;">Nhấn vào đây</a>
    Hoặc sao chép địa chỉ vào thanh địa chỉ trình duyệt:
  </p>
  <div style="margin-left: auto;margin-right: auto;text-align: center;font-style: italic;">
    {{CallbackUrl}}
  </div>
  <p>Để đảm bảo an toàn cho tài khoản của Quý khách, liên kết này sẽ có hiệu lực trong <strong>10 phút</strong>. Email này được tự động tạo ra bởi hệ thống, vui lòng không trả lời trực tiếp.</p>
</div>', 'Vui lòng sử dụng url để xác nhận địa chỉ email');
INSERT INTO cms."_TopicContent" ("Id", "TopicId", "CreatedOn", "UpdatedOn", "Language", "Title", "Author", "Content", "Subtitle") VALUES (10097, 10002, '2023-08-16 18:51:43.410996 +00:00', '2023-08-16 18:51:43.410996 +00:00', 'vi-vn', 'Đặt lại mật khẩu', '', e'
Kính gửi quý khách hàng {{UserName}},

<p>
