INSERT INTO cms."_TopicContent" ("Id", "TopicId", "CreatedOn", "UpdatedOn", "Language", "Title", "Author", "Content", "Subtitle") VALUES (10098, 11239, '2023-08-16 18:52:44.707360 +00:00', '2023-08-16 18:52:44.707360 +00:00', 'vi-vn', ' MyBCR Thông báo quan trọng', '', e'
<div style="font-size: 14px; line-height: 20px">
<p>Vì việc nâng cấp hệ thống MyBCR, Trang Quản lý Khách hàng sẽ không khả dụng sau thời gian Đóng thị trường vào <b>Thứ Sáu, ngày 21 tháng 7 năm 2023</b>, và sẽ được mở lại để sử dụng bình thường trước thời gian Mở thị trường vào <b>Thứ Hai, ngày 24 tháng 7 năm 2023</b>.</p>
<p>Nếu quý khách cần hỗ trợ khách hàng trong suốt cuối tuần, vui lòng liên hệ BCR Support qua địa chỉ email <a href="mailto:info@au.thebcr.com">info@au.thebcr.com</a>.</p>
<p>Nếu quý khách có bất kỳ câu hỏi nào liên quan đến việc nâng cấp trên, vui lòng liên hệ chúng tôi qua trò chuyện trực tuyến hoặc gửi email đến địa chỉ info@au.thebcr.com. Chúng tôi rất mong được cung cấp dịch vụ tốt nhất trong ngành dịch vụ tài chính.</p>
<br />
Trân trọng,
<br />
<b>BCR</b>
<br />
</div>', 'Nâng cấp lên MyBCR');
INSERT INTO cms."_TopicContent" ("Id", "TopicId", "CreatedOn", "UpdatedOn", "Language", "Title", "Author", "Content", "Subtitle") VALUES (10095, 10003, '2023-08-16 18:49:16.846451 +00:00', '2025-03-21 21:47:32.756399 +00:00', 'vi-vn', 'Default Layout', '', e'<!DOCTYPE PUBLIC "-//W3C//DTD HTML 4.01 Transitional//EN" "http://www.w3.org/TR/html1/DTD/html1-transitional.dtd">
<html lang="vi" xmlns="http://www.w3.org/1999/xhtml">
<head>
    <meta name="viewport" content="width=device-width, initial-scale=1.0" />
    <meta http-equiv="Content-Type" content="text/html; charset=UTF-8" />
    <meta http-euiqv="X-UA-Compatible" content="IE=edge" />
  <title>Email từ Thebcr</title>
</head>
<body
      style="
             font-family: Lato, sans-serif;
             "
      >
  <div style="background-color:#efeeee;width:100%;height:100%">
    <table width="600" style="background-color:#ffffff;max-width: 600px;border:none;border-spacing:0;margin:auto;">
      <tr>
        <td></td><td></td>
      </tr>
      <tr>
          <td colspan="2" style="height:15rem;background: url(https://img.thebcr.com/email/emailbg.jpg);background-repeat: no-repeat;background-size: cover;">
            <table style="color: white; background: rgba(0, 0, 0, 0.5);height:100%;width: 100%;">
            <tr><td style="height:50px;"></td></tr>
            <tr>
              <td style="font-size: 26px; font-weight: 700;padding-left: 2rem;height:30px;">{{Title}}</td>
            </tr>
            <tr><td style="padding-left: 2rem;height:10px;"><div style="width: 12rem; border-top: 3px solid #ffd400"></div></td></tr>
            <tr>
              <td style="font-weight: 600;padding-left: 2rem;font-size: 16px;height:30px;">{{Subtitle}}</td>
            </tr>
            <tr><td style="height:30px;"></td></tr>
            <tr>
              <td style="padding-left: 2rem;height:30px;"><a href="https://thebcrglobal.com" style="color: white;font-size:16px;text-decoration: none;">
                <div style="display: inline-block;border: 6px solid transparent;border-left-color: #ffd400;"></div>
                Đăng nhập MyBCR</a>
              </td>
            </tr>
            <tr><td></td></tr>
          </table>
        </td>
      </tr>
      <tr><td colspan="2" style="padding: 30px 20px;">
        <table style="width:100%;">
          <tr><td>{{Content}}</td></tr>
        </table>
        </td>
      </tr>
    </table>
  </div>
  <div style="background-color:#efeeee;width:100%;height:100%">
    <table width="600" style="background-color:#ffffff;max-width: 600px;border:none;border-spacing:0;          margin-left: auto;
          margin-right: auto;">
      <tr>
        <td></td><td></td>
      </tr>
      <tr>
        <td colspan="2" style="border-bottom: 2px solid #ffd400;background-color: #e9edeb;height: 15px;"></td>
      </tr>
