INSERT INTO cms."_TopicContent" ("Id", "TopicId", "CreatedOn", "UpdatedOn", "Language", "Title", "Author", "Content", "Subtitle") VALUES (10103, 11248, '2023-08-16 18:56:56.024728 +00:00', '2023-08-16 18:56:56.024728 +00:00', 'vi-vn', 'Liên kết gửi tiền', '', e'
<div style="font-size: 12px; line-height: 20px">
  <p style="font-size: 16px; font-weight: 700; line-height: 24px">
    Kính gửi Quý khách hàng,
  </p>
  <div style="padding: 12px; background-color: #f2f2f2">
    <p style="line-height: 24px; font-size: 14px; color: #383d49; font-weight: 600;">
      Thông Tin Nạp Tiền
    </p>
    <p>
      Vui lòng xem liên kết nạp tiền BCR dưới đây - để thực hiện thanh toán,
      nhấp vào liên kết và làm theo hướng dẫn đã được cung cấp.
    </p>
    <p>
      Số Tham Chiếu: {{$deposit->ref_id}}<br />Số Tiền Nạp: US${{ number_format($deposit->amount, 2)}}
    </p>
    <div style="font-style: italic">
      <a href="{{$payLink}}" target="_blank" style="color: #383d49; text-decoration: none; font-weight: 700;">
        {{$payLink}}
      </a>
    </div>
    <p>
      Liên kết này sẽ hết hạn sau 20 phút. Vui lòng sử dụng càng sớm càng tốt.
    </p>
    <p style="color: #cc1f1a; font-weight: 600">
      Ghi chú:<br />
      Liên kết sẽ hiển thị số tiền thanh toán trong Đô la Hồng Kông (HKD). Số tiền nạp yêu cầu sẽ được chuyển đổi từ Đô la Mỹ (USD) sang HKD và số tiền giao dịch HKD sẽ được hiển thị. Sau khi chọn thanh toán bằng thẻ ngân hàng của bạn, UnionPay sẽ tự động chuyển đổi HKD sang RMB và số tiền RMB đã thanh toán thực tế sẽ được hiển thị trên trang thanh toán.
    </p>
  </div>
</div>', 'liên kết');
INSERT INTO cms."_TopicContent" ("Id", "TopicId", "CreatedOn", "UpdatedOn", "Language", "Title", "Author", "Content", "Subtitle") VALUES (10104, 11249, '2023-08-16 18:58:05.460382 +00:00', '2023-08-23 20:21:05.486587 +00:00', 'vi-vn', ' Thông báo đặt cọc', '', e'
<div style="font-size:12px;line-height:20px">
  <p style="font-size:16px;font-weight:700;line-height:24px">Kính gửi {{NativeName}} thân mến,</p>
  <p>
    Cảm ơn bạn đã mở tài khoản giao dịch CFD với BCR. Số tài khoản của bạn là
    {{AccountNumber}}. Để bắt đầu giao dịch CFD trên Nền tảng Giao dịch BCR,
