INSERT INTO cms."_TopicContent" ("Id", "TopicId", "CreatedOn", "UpdatedOn", "Language", "Title", "Author", "Content", "Subtitle") VALUES (10073, 11254, '2023-08-16 18:18:34.044697 +00:00', '2023-11-29 00:20:29.822614 +00:00', 'mn-mn', 'Демо данс нээсэн', '', e'<div style="font-size: 12px; line-height: 20px">
  <p style="font-size: 16px; font-weight: 700; line-height: 24px">Уважаемый/ая {{NativeName}},</p>
  <p>Благодарим вас за создание демо-счета в BCR. Теперь вы можете использовать информацию ниже,
    чтобы войти в платформу BCR Trader.</p>
  <table class="letter-table"
         style="table-layout: fixed; line-height: 24px; margin-left: auto; margin-right: auto; text-align: left; padding: 8px; float: none"
         bgcolor="#f2f2f2" align="left">
    <tr>
      <th style="padding-left: 24px; padding-right: 24px; color: #383d49; white-space: nowrap">
        Номер Счета:</th>
      <td style="padding-left: 24px; padding-right: 24px; word-wrap: break-word">{{AccountNumber}}
      </td>
    </tr>
    <tr>
      <th style="padding-left: 24px; padding-right: 24px; color: #383d49; white-space: nowrap">
        Пароль:</th>
      <td style="padding-left: 24px; padding-right: 24px; word-wrap: break-word">
        {{Password}}</td>
    </tr>
    <tr>
      <th style="padding-left: 24px; padding-right: 24px; color: #383d49; white-space: nowrap">
        Сервер:</th>
      <td style="padding-left: 24px; padding-right: 24px; word-wrap: break-word">{{ServerName}}
      </td>
    </tr>
  </table>
  <p>
    Следующим шагом является скачивание платформы BCR Trader, используя одну из ссылок ниже.
    BCR стремится предоставить непревзойденное обслуживание клиентов, поэтому если у вас есть
    какие-либо вопросы или опасения, свяжитесь с представителем BCR по адресу <a
                                                              href="mailto:info@thebcr.com">info@thebcr.com</a></p>

</div>
', '');
INSERT INTO cms."_TopicContent" ("Id", "TopicId", "CreatedOn", "UpdatedOn", "Language", "Title", "Author", "Content", "Subtitle") VALUES (11346, 11254, '2023-08-16 21:24:55.632236 +00:00', '2023-11-29 00:20:53.303417 +00:00', 'vi-vn', 'Demo Account Opened', '', e'<div style="font-size: 12px; line-height: 20px">
