INSERT INTO cms."_TopicContent" ("Id", "TopicId", "CreatedOn", "UpdatedOn", "Language", "Title", "Author", "Content", "Subtitle") VALUES (11299, 11245, '2023-07-19 22:45:59.929428 +00:00', '2023-08-16 01:03:18.260113 +00:00', 'en-us', 'Leverage Changed', 'system', e'<div style="font-size:12px;line-height:20px">
