INSERT INTO cms."_TopicContent" ("Id", "TopicId", "CreatedOn", "UpdatedOn", "Language", "Title", "Author", "Content", "Subtitle") VALUES (11302, 11248, '2023-07-19 22:52:54.561316 +00:00', '2023-08-16 01:06:30.862831 +00:00', 'en-us', 'Deposit Link', 'system', e'<div style="font-size: 12px; line-height: 20px">
  <p
     style="font-size: 16px; font-weight: 700; line-height: 24px"
     >
    Dear Client,
  </p>
  <div style="padding: 12px; background-color: #f2f2f2">
    <p
       style="
              line-height: 24px;
              font-size: 14px;
              color: #383d49;
              font-weight: 600;
              "
       >
      Deposit Information
    </p>
    <p>
      Please see below BCR deposit link - to make a payment,
      click the link and follow the provided instructions.
    </p>
    <p>
      Reference Number: {{$deposit->ref_id}}<br />Deposit
      Amount: US${{ number_format($deposit->amount, 2)}}
    </p>
    <div style="font-style: italic">
      <a
         href="{{$payLink}}"
         target="_blank"
         style="
                color: #383d49;
                text-decoration: none;
                font-weight: 700;
                "
         >{{$payLink}}</a
        >
    </div>
    <p>
      This link will be expired in 20 minutes. Please use as
      soon as possible.
    </p>
    <p style="color: #cc1f1a; font-weight: 600">
      Notes:<br />
      The link will display the payment currency in Hong Kong
      Dollars (HKD). The requested deposit amount will be
      converted from US Dollars (USD) to HKD and the HKD
      transaction amount will be displayed. After choosing to
      pay with your bank card, UnionPay will automatically
      convert the HKD into RMB, and the actual paid RMB amount
      will be displayed on the payment page.
    </p>
  </div>
</div>', 'Link');
