INSERT INTO cms."_TopicContent" ("Id", "TopicId", "CreatedOn", "UpdatedOn", "Language", "Title", "Author", "Content", "Subtitle") VALUES (11345, 11253, '2023-08-16 21:24:13.067285 +00:00', '2023-08-23 22:25:41.397729 +00:00', 'vi-vn', 'MT4 Password Changed', '', e'<div style="font-size: 12px; line-height: 20px">
  <p style="font-size: 16px; font-weight: 700; line-height: 24px">
    Kính gửi Quý khách hàng thân mến,
  </p>
  <p>
    Mật khẩu tài khoản của Quý khách đã được thay đổi từ ngày {{$wl->date_on_letter->format(\'j F, Y\')}}, và chi tiết tài khoản BCR ProTrader MT4 của Quý khách được liệt kê dưới đây:
  </p>
  <table class="letter-table" style="
                      table-layout: fixed;
                      line-height: 24px;
                      margin-left: auto;
                      margin-right: auto;
                      text-align: left;
                      padding: 8px;
                      float: none;
                    " bgcolor="#f2f2f2" align="left">
    <tr>
      <th style="
                          padding-left: 24px;
                          padding-right: 24px;
                          color: #383d49;
                          white-space: nowrap;
                        ">
        Tài Khoản MyBCR:
      </th>
      <td style="
                          padding-left: 24px;
                          padding-right: 24px;
                          word-wrap: break-word;
                        ">
        {{$wl->user->email}}
      </td>
    </tr>
    <tr>
      <th style="
                          padding-left: 24px;
                          padding-right: 24px;
                          color: #383d49;
                          white-space: nowrap;
                        ">
        Tài Khoản MT4:
      </th>
      <td style="
                          padding-left: 24px;
                          padding-right: 24px;
                          word-wrap: break-word;
                        ">
        {{$wl->user->login}}
      </td>
    </tr>
    <tr>
      <th style="
                          padding-left: 24px;
                          padding-right: 24px;
                          color: #383d49;
                          white-space: nowrap;
                        ">
        Mật Khẩu Tài Khoản Giao Dịch:
      </th>
      <td style="
                          padding-left: 24px;
                          padding-right: 24px;
                          word-wrap: break-word;
                        ">
        {{$wl->decryptPassword}}
      </td>
    </tr>
    <tr>
      <th style="
                          padding-left: 24px;
                          padding-right: 24px;
                          color: #383d49;
                          white-space: nowrap;
                        ">
        Máy Chủ MT4:
      </th>
      <td style="
                          padding-left: 24px;
                          padding-right: 24px;
                          word-wrap: break-word;
                        ">
        BCR-REAL
      </td>
    </tr>
  </table>
  <p style="font-weight: 700; line-height: 24px; font-size: 14px">
    Làm theo các bước sau để bắt đầu giao dịch ngay bây giờ:
  </p>
  <ol>
    <li>Truy cập tab Khuyến Mãi trên <a target="_blank"
                                            href="https://au.thebcr.com/en"
                                            style="color: #383d49; text-decoration: none; font-weight: 700">Trang Web Chính Thức</a> của BCR để tìm hiểu thêm về các chương trình khuyến mãi BCR khác nhau.</li>
    <li>Đăng nhập vào <a target="_blank" href="https://client-portal.thebcr.com/"
                     style="color: #383d49; text-decoration: none; font-weight: 700">MyBCR</a>
      và chọn tab Tải Xuống để tải xuống nền tảng giao dịch BCR.</li>
    <li>Đăng nhập vào <a target="_blank" href="https://client-portal.thebcr.com/"
                     style="color: #383d49; text-decoration: none; font-weight: 700">MYBCR</a> và chọn tab Nạp Tiền của Tôi để chọn phương thức nạp tiền.</li>
    <li>Đăng nhập vào BCR Trader (Nền tảng MT4) hoặc nếu Quý khách đang sử dụng thiết bị di động, chọn Máy Chủ BCR-Real trong Mobile MetaTrader 4 và sử dụng Số Tài Khoản và Mật Khẩu Giao Dịch được liệt kê ở trên.</li>
  </ol>
  <p>
    Vui lòng lưu ý rằng Mật Khẩu Nhà Đầu Tư cung cấp quyền truy cập chỉ để đọc, không thể giao dịch vào tài khoản của Quý khách. Nếu Quý khách muốn đặt lệnh giao dịch qua điện thoại, Quý khách có thể liên hệ với chúng tôi qua số điện thoại sau đây:</p>
  <p style="font-weight: 600; text-align: center">
    +44 3300010590 <br>
  </p>
  <p>
    Vui lòng lưu ý rằng dịch vụ giao dịch qua điện thoại chỉ được sử dụng khi có sự cố về kết nối mạng hoặc nền tảng giao dịch không hoạt động bình thường.
  </p>
</div>
', '');
