INSERT INTO cms."_TopicContent" ("Id", "TopicId", "CreatedOn", "UpdatedOn", "Language", "Title", "Author", "Content", "Subtitle") VALUES (11348, 11261, '2023-08-16 21:26:49.364122 +00:00', '2023-08-16 21:26:49.364122 +00:00', 'vi-vn', ' Tài khoản khách hàng đã được đăng ký', '', e'<div style="font-size: 12px; line-height: 20px">
