INSERT INTO cms."_TopicContent" ("Id", "TopicId", "CreatedOn", "UpdatedOn", "Language", "Title", "Author", "Content", "Subtitle") VALUES (11352, 11269, '2023-08-16 21:52:26.774973 +00:00', '2023-08-16 21:55:45.912461 +00:00', 'en-us', 'Evidence Required Email', 'system', e'<div style="font-size:12px;line-height:20px">
  <p style="font-size:16px;font-weight:700;line-height:24px">
    Dear BCR Client,
  </p>
  <p>
    Thank you for your recent application to become a BCR Pro. We     require additional documents to complete our review. 
  </p>

  <p>
      Please see the following details for the Evidence Required for each specific channel. Please note all clients who receive this email must sign and date the 
    <a  href="https://bcrpropublic.s3.ap-southeast-1.amazonaws.com/docs/ba/en-us/Wholesale/Sophisticated+Investor+Acknowledgement.pdf
">Sophisticated Investor Acknowledgement</a> 
    form and return to BCR.
  </p>

  <p>
    In the meantime, if you have any further questions regarding the BCR Pro Account offering, please contact us via online chat or email us at <a href="mailto:wholesale@au.thebcr.com">wholesale@au.thebcr.com</a>. We look forward to providing you with the best service in the CFD industry.
  </p>
  <p style="text-decoration:underline;font-weight:600;">Channel 1: Trading History</p>
  <ul>
    <li>
      <p>Trading statements from your CFD broker(s)</p>
      <p>We require proof of your previous trading history. You must have traded at least 75 trades  with a firm for Margin FX, CFDs over Indices, Commodities, Currencies, Metals and Shares over the previous 12 months, or Traded at least 50 significant trades  over the previous 12 months with a firm for Margin FX, CFDs over Indices, Commodities, Currencies, Metals and Shares.
      </p>
    </li>
  </ul>
  <p style="text-decoration:underline;font-weight:600;">Channel 2: Relevant Work Experience</p>
  <p>
    If you have previously worked or are still working in the financial sector, for at least one year in a position which requires knowledge of leveraged trading, then you can provide evidence of your professional working experience.
  </p>
  <p>
    Accepted document types to demonstrate your professional working experience are:
  </p>
  <ul>
    <li>
      <p>Letter from current employer confirming the position and start date or time in role, and including a position description; or</p>
    </li>
     <li>
      <p>Employment contract evidencing the position and start date, and including a position description; or </p>
    </li>
    <li>
      <p>References from previous employers detailing the prior position and responsibilities; or</p>
    </li>
    <li>
      <p>LinkedIn profile evidencing the position and responsibilities, start date or relevant time in role, original or PDF copy of pay slip evidencing same employer.</p>
    </li>
  </ul>
  <p style="text-decoration:underline;font-weight:600;">Channel 3: Relevant Formal Qualifications</p>
  <p>
   If you possess formal qualifications relevant to the understanding of Margin FX, CFDs over indices, commodities, currencies, metals and shares. Post graduate qualifications are preferred (for example, a Bachelor of Commerce or a Bachelor of Business would not be sufficient to demonstrate experience, however a course or major in Finance or Applied Finance may be relevant).
  </p>
  <p>
    Accepted document types to demonstrate your formal qualifications are:
  </p>
  <ul>
    <li>
      <p>Diploma from an accredited university which specifies the courses take; or</p>
    </li>
     <li>
      <p>Certificate from a licensed compliance training or CPD course provider; or </p>
    </li>
    <li>
      <p> 	Certificate from a higher education FASEA-approved course provider.</p>
    </li>
  </ul>
  <p>
    You can take a photo of your documents using your phone and email them to <a href="mailto:wholesale@au.thebcr.com" >wholesale@au.thebcr.com</a>. Once we have received your documents, we will let you know the outcome of your application within 7 business days.
  </p>
    <p>
    If you have any further questions regarding the Wholesale accounts, please contact us via online chat or email us at <a href="mailto:wholesale@au.thebcr.com">wholesale@au.thebcr.com</a>. We look forward to providing you with the best service in the CFD industry.
  </p>
  <br/>
  Regards,<br/>
  BCR

</div>', 'Wholesale Account');
INSERT INTO cms."_TopicContent" ("Id", "TopicId", "CreatedOn", "UpdatedOn", "Language", "Title", "Author", "Content", "Subtitle") VALUES (11353, 11270, '2023-08-16 21:52:33.892026 +00:00', '2023-08-16 21:56:49.983693 +00:00', 'en-us', 'Evidence Required Email – Wealth Threshold Application', 'system', e'<div style="font-size:12px;line-height:20px">
  <p style="font-size:16px;font-weight:700;line-height:24px">Dear BCR Client,</p>
  <p>
    Thank you for your recent application to become a BCR Pro. 
  </p>

  <p>
   As you applied under the Wealth Threshold Application, you will need an eligible member of a professional accounting body to complete the<a href="https://bcrpropublic.s3.ap-southeast-1.amazonaws.com/docs/ba/en-us/Wholesale/Certificate+By+a+Qualified+Accountant.pdf"> Certificate by a Qualified Accountant</a> form certifying you meet one of the following criteria: 
  </p>
  <ul>
    <li>
       	Have net assets of at least AUD$2.5M  OR
    </li>
    <li>
       	Have a gross income for each of the last 2 financial years of at least AUD$250,000
    </li>
  </ul>
  <p>
    Please email a scanned image of the completed Certificate to <a href="mailto:wholesale@au.thebcr.com">wholesale@au.thebcr.com</a>. <br>
    Please post the original Certificate to BCR’S office at:
  </p>
  <p>
    
  </p>
  <p>
    Bacera Co Pty Ltd<br>
    Level 24, 171 Sussex Street <br>
    Sydney, NSW 2000

  </p>
  <p>
    Thank you for submitting documents related to your Wholesale Account Application. Once we have received your documents, we will let you know the outcome of your application within 7 business days. If you have any further questions regarding the Wholesale accounts, please contact us via online chat or email us at <a href="mailto:wholesale@au.thebcr.com">wholesale@au.thebcr.com</a>. We look forward to providing you with the best service in the CFD industry.
  </p>
  <br/>
  Regards,<br/>
  BCR

</div>', 'Wholesale Account');
INSERT INTO cms."_TopicContent" ("Id", "TopicId", "CreatedOn", "UpdatedOn", "Language", "Title", "Author", "Content", "Subtitle") VALUES (11354, 11271, '2023-08-16 21:52:41.108355 +00:00', '2023-08-16 22:00:47.065357 +00:00', 'en-us', 'BCR Pro Account Welcome Letter', 'system', e'<div style="font-size:12px;line-height:20px">
  <p style="font-size:16px;font-weight:700;line-height:24px">Dear BCR Client,</p>
  <p>
    Bacera Co Pty Ltd (“BCR”) has reviewed and assessed your application to be classified as a Wholesale Client (“BCR Pro”).
  </p>
  <p>
    This is a notice to confirm that BCR classifies you as a Wholesale Client. You have met the criteria of a Wholesale Client under the Corporations Act 2001 (Cth) (the “Corporations Act”). You have fulfilled the following requirement(s):
  </p>
  <p>Internal Note: we need to specify which requirement client fulfilled:</p>
  <ol>
    <li>
      Wealth Threshold Application – You have provided a completed Certificate by a Qualified Accountant which verifies you meet one of our Wealth Threshold Application requirements.
    </li>
    <li>
      Sophisticated Investor Test – You have fulfilled the requirements of Channel 1: Knowledge Test & Trading History / Channel 2: Relevant Work Experience / Channel 3: Relevant Formal Qualifications to be classified as a Sophisticated Investor. 
    </li>
  </ol>
  <p style="font-weight:600;">
    What changes when you are a Wholesale Client?
  </p>
  <p>
    This classification will decrease the protections awarded, which means you will not have the benefit of certain protections that are provided to Retail Clients. The decreased protections include but are not limited to the below examples:
  </p>
  <ul>
    <li>
      As a wholesale client you will not receive some of the protections retail clients receive, or a product disclosure statement. Product risks and other important information are detailed in the Wholesale Client Disclosure Notice.
    </li>
    <li>
      Protections under ASIC’s Product Intervention Order – Contracts for Difference Instrument 2020/986 including leverage restrictions and negative balance protection (commencing on 29 March 2021).
    </li>
    <li>
      You may not be eligible to access the dispute resolution services offered by the Australian Financial Complaints Authority (“AFCA”).
    </li>
    <li>
      You will not receive disclosure documents namely, Financial Services Guides and Product Disclosure Statements.
    </li>
  </ul>
  <p>
    This classification supersedes any previous notice you may have received from BCR.
  </p>
  <p>
    You have the right to request your classification be changed to a Retail Client, allowing you to obtain the highest level of regulatory protection awarded.
  </p>
  <p>
    If you have any questions or concerns regarding your status as a Wholesale Client, please contact <a href="mailto:wholesale@au.thebcr.com">wholesale@au.thebcr.com</a>.
  </p>

  <p style="font-weight:600;">
    Negative Balance
  </p>
  <p>
    As a wholesale client you may be eligible for a single negative balance protection of up to AUD$10,000 of your total balance, which is the combined balance of all trading accounts after all open trades have been closed. BCR reserves the right to not grant negative balance protection in cases where there is reasonable evidence, in our sole determination, of misconduct or trading abuse causing the negative balance to occur. Where this is the case, BCR will provide reasons to you as to why negative balance protection has not been applied.
  </p>
  <p style="font-weight:600;">
    Margin Close-out
  </p>
  <p>
    BCR will close out your position(s) if your equity falls below 50% of the required margin.
  </p>
  <p style="font-weight:600;">
    Leverage Settings
  </p>
  <p>
    The leverage on your BCR Pro account will be automatically adjusted based on your Account Equity. See the table below for more specific information. BCR will not be responsible if your Pro account’s positions are automatically closed out due to a change in the account’s leverage.
  </p>
  <table style="border-collapse: collapse;">
    <thead>
      <tr>
        <th style="border:1px solid black;padding:5px 10px;text-align:left;">Account Equity</th>
        <th style="border:1px solid black;padding:5px 10px;">Account Max Leverage</th>
      </tr>
    </thead>
    <tbody>
      <tr>
        <td style="border:1px solid black;padding:5px 10px;">Below $50,000</td>
        <td style="border:1px solid black;padding:5px 10px;">1:400</td>
      </tr>
      <tr>
        <td style="border:1px solid black;padding:5px 10px;">$50,001– $100,000</td>
        <td style="border:1px solid black;padding:5px 10px;">1:200</td>
      </tr>
      <tr>
        <td style="border:1px solid black;padding:5px 10px;">$100,001- $200,000</td>
        <td style="border:1px solid black;padding:5px 10px;">1:100</td>
      </tr>
      <tr>
        <td style="border:1px solid black;padding:5px 10px;">$200,001 – $300,000</td>
        <td style="border:1px solid black;padding:5px 10px;">1:50</td>
      </tr>
      <tr>
        <td style="border:1px solid black;padding:5px 10px;">$300,0001– $500,000</td>
        <td style="border:1px solid black;padding:5px 10px;">1:25</td>
      </tr>
      <tr>
        <td style="border:1px solid black;padding:5px 10px;">$500,001 - $1,000,000</td>
        <td style="border:1px solid black;padding:5px 10px;">1:20</td>
      </tr>
      <tr>
        <td style="border:1px solid black;padding:5px 10px;">$1,000,001 or more</td>
        <td style="border:1px solid black;padding:5px 10px;">1:10</td>
      </tr>
    </tbody>
  </table>
  <p style="font-weight:600;">
    Margin Use
  </p>
  <p>
    The leverage on your BCR Pro account will be automatically adjusted based on your Used Margin. See the table below for more specific information. BCR will not be responsible if your Pro account’s positions are automatically closed out due to a change in the account’s leverage.
  </p>
  <table style="border-collapse: collapse;">
    <thead>
      <tr>
        <th style="border:1px solid black;padding:5px 10px;text-align:left;">Used Margin</th>
        <th style="border:1px solid black;padding:5px 10px;">Account Max Leverage</th>
      </tr>
    </thead>
    <tbody>
      <tr>
        <td style="border:1px solid black;padding:5px 10px;">Below $50,000</td>
        <td style="border:1px solid black;padding:5px 10px;">1:400</td>
      </tr>
      <tr>
        <td style="border:1px solid black;padding:5px 10px;">$50,001– $100,000</td>
        <td style="border:1px solid black;padding:5px 10px;">1:100</td>
      </tr>
      <tr>
        <td style="border:1px solid black;padding:5px 10px;">$200,001 or more</td>
        <td style="border:1px solid black;padding:5px 10px;">1:50</td>
      </tr>
    </tbody>
  </table>
  <p>
    In instances where both the above Account Equity & Margin Use rules may apply to your account, the lowest applicable leverage setting will be applied.
  </p>
  <p style="font-weight:600;">
    Example:
  </p>
  <p >
    Account Equity = $500,000
  </p>
  <p >
    Used Margin = $100,000
  </p>
  <p style="font-weight:600;">
    Applicable Margin = 1:25
  </p>
  <p >
    The “$” may refer to USD or AUD, based on the denominated currency of your BCR trading account.
  </p>
  <p style="font-weight:600;">
    Funding Instructions
  </p>
  <p >
    Below you will find the banking details necessary to make a deposit into your BCR Pro trading account. Clients may only fund their account via bank transfer. BCR may not make or receive third party payments. Deposits will only be accepted in the account holder’s name.
  </p>
    <table style="border-collapse: collapse;">
    <thead>
      <tr>
        <th style="border:1px solid black;padding:5px 10px;text-align:left;background-color:#d9d9d9;" colspan="2">USD Deposits</th>
       
      </tr>
    </thead>
    <tbody>
      <tr>
        <td style="border:1px solid black;padding:5px 10px; font-weight:600;background-color:#d9d9d9;">Bank:</td>
        <td style="border:1px solid black;padding:5px 10px;">Commonwealth Bank</td>
      </tr>
      <tr>
        <td style="border:1px solid black;padding:5px 10px; font-weight:600;background-color:#d9d9d9;">BSB Code:</td>
        <td style="border:1px solid black;padding:5px 10px;">062-000</td>
      </tr>
      <tr>
        <td style="border:1px solid black;padding:5px 10px; font-weight:600;background-color:#d9d9d9;">SWIFT Code:</td>
        <td style="border:1px solid black;padding:5px 10px;">CTBAAU2S</td>
      </tr>
            <tr>
        <td style="border:1px solid black;padding:5px 10px; font-weight:600;background-color:#d9d9d9;">Beneficiary:</td>
        <td style="border:1px solid black;padding:5px 10px;">Bacera Co Pty Ltd</td>
      </tr>
            <tr>
        <td style="border:1px solid black;padding:5px 10px; font-weight:600;background-color:#d9d9d9;">Beneficiary Address:</td>
        <td style="border:1px solid black;padding:5px 10px;">48 Martin Place Sydney, Sydney, NSW 2000, Australia</td>
      </tr>
            <tr>
        <td style="border:1px solid black;padding:5px 10px; font-weight:600;background-color:#d9d9d9;">Beneficiary Account #:</td>
        <td style="border:1px solid black;padding:5px 10px;">200015750601</td>
      </tr>
                  <tr>
        <td style="border:1px solid black;padding:5px 10px; font-weight:600;background-color:#d9d9d9;">REF:</td>
        <td style="border:1px solid black;padding:5px 10px;">Reference your BCR Pro Account #</td>
      </tr>
    </tbody>
  </table>
  <br/>
  Regards,<br/>
  BCR

</div>', 'Wholesale Account');
