INSERT INTO cms."_TopicContent" ("Id", "TopicId", "CreatedOn", "UpdatedOn", "Language", "Title", "Author", "Content", "Subtitle") VALUES (11357, 11269, '2023-08-16 21:55:57.717938 +00:00', '2023-08-18 20:36:41.415313 +00:00', 'zh-cn', '电子邮件：要求提供相关证明', '', e'<div style="font-size:12px;line-height:20px">
  <p style="font-size:16px;font-weight:700;line-height:24px">
   尊敬的客户，
  </p>
  <p>
   感谢您申请获得BCR高端客户资格！您还需提供一些文件资料才能完成评审。
  </p>

  <p>
     请参阅下列每种具体证明方式所需证明的详细说明。 请注意，所有收到此邮件的客户都必须在 
    <a  href="https://bcrpropublic.s3.ap-southeast-1.amazonaws.com/docs/ba/zh-cn/Wholesale/Sophisticated+Investor+Acknowledgement.pdf
">成熟投资者确认函</a> 
    表单文件上签字并注明日期，然后把该表单文件交回BCR公司。
  </p>
  <p style="text-decoration:underline;font-weight:600;">方式1：交易历史</p>
  <ul>
    <li>
      <p>由您的差价合约经纪公司所提供的交易报表</p>
      <p>您需要提供您以往交易历史的相关证明。您在过去12个月，必须与一家公司就保证金外汇、指数差价合约、大宗商品差价合约、货币差价合约、金属差价合约和股票差价合约至少进行了75笔交易 ，或者，在过去12个月，必须与一家公司就保证金外汇、指数差价合约、大宗商品差价合约、货币差价合约、金属差价合约和股票差价合约至少进行了50笔重大交易。
      </p>
    </li>
  </ul>
  <p style="text-decoration:underline;font-weight:600;">方式2：相关工作经验</p>
  <p>
    如果您曾经在或者现在仍然在金融领域工作，并且至少在需要具备杠杆衍生品交易知识的专业岗位上工作过一年，那么，您可以提供您的专业工作经验证明。
  </p>
  <p>
    本公司认可以下专业工作经验证明文件：
  </p>
  <ul>
    <li>
      <p>由您的现任雇主所出具的证明函，确认证明您的工作职位、工作起始日期或时间，以及包括职位描述；或者</p>
    </li>
     <li>
      <p> 	您的雇佣合同，以证明您所担任的职位及雇佣起始日期以及职位描述；或者</p>
    </li>
    <li>
      <p> 	由您以前的雇主所出具的推荐信，详细说明您以前担任的职位和职责；或者</p>
    </li>
    <li>
      <p> 	您在领英（LinkedIn）上登记的个人资料，以证明您的职位和工作职责、工作起始日期或工作相关时间、工资单原件或PDF副本，以证明您受雇于同一名雇主。</p>
    </li>
  </ul>
  <p style="text-decoration:underline;font-weight:600;">方式3：相关正式资质</p>
  <p>
 如果您具备保证金外汇、指数差价合约、大宗商品差价合约、货币差价合约、金属差价合约和股票差价合约相关知识的正式资质，可提供此类相关证明。 研究生学历优先（例如，商科学士学位或商业学士学位并不足以证明您已拥有相关经验，但是，金融学或应用金融学课程或专业可能与上述正式资质相关）。
  </p>
  <p>
    可用于证明您具有正式资质的文件类型包括：
  </p>
  <ul>
    <li>
      <p> 	由业经认可的大学所颁发的文凭，该文凭上具体注明了您已经学习过的课程；或者</p>
    </li>
     <li>
      <p> 	由持牌合规培训或持续专业进修（CPD）课程提供方所出具的证书；或者</p>
    </li>
    <li>
      <p>  	由澳大利亚财务顾问标准和道德管理局（FASEA）批准的课程提供者向您出具的高等教育证书。</p>
    </li>
  </ul>
  <p>
    您可以把以上证明文件用您的手机拍照，然后将照片发送电子邮件至 <a href="mailto:wholesale@au.thebcr.com" >wholesale@au.thebcr.com</a>。本公司收到您的上述文件后，将在7个工作日内通知您申请结果。
  </p>
    <p>
    如果您对BCR高端客戶存有其他任何疑问，请通过在线聊天或者发送电子邮件至 <a href="mailto:wholesale@au.thebcr.com">wholesale@au.thebcr.com</a>. 与我们联系。我们期待着为您提供业内最优质的差价合约服务。
  </p>
  <br/>
 谨致问候，<br/>
BCR公司

</div>', 'BCR高端客戶');
INSERT INTO cms."_TopicContent" ("Id", "TopicId", "CreatedOn", "UpdatedOn", "Language", "Title", "Author", "Content", "Subtitle") VALUES (11358, 11270, '2023-08-16 21:57:01.074276 +00:00', '2023-08-18 20:35:36.768777 +00:00', 'zh-cn', '电子邮件：要求提供相关证明 – 财富阈值申请程序', '', e'<div style="font-size:12px;line-height:20px">
  <p style="font-size:16px;font-weight:700;line-height:24px">尊敬的客户，</p>
  <p>
    感谢您申请获得BCR高端客户资格！
  </p>

  <p>
   您已申请通过财富阈值申请程序获得BCR高端客户资格，但是，您还需提供会计专业团体的一名合格成员所完整出具的<a href="https://bcrpropublic.s3.ap-southeast-1.amazonaws.com/docs/ba/zh-cn/Wholesale/Certificate+By+a+Qualified+Accountant.pdf"> 由合格会计师出具的证明表单文件</a>，以此证明您符合以下任意一项条件要求： 
  </p>
  <ul>
    <li>
       	 	拥有净资产至少AUD$250万澳元 ，或者
    </li>
    <li>
       	 	在过去两个财政年度中，每个财政年度的总收入至少为AUD$250,000澳元
    </li>
  </ul>
  <p>
    请将完整证明的扫描件发送电子邮件至<a href="mailto:wholesale@au.thebcr.com">wholesale@au.thebcr.com</a>. <br>
    请将证明原件邮寄至BCR公司的以下办公地址：
  </p>
  <p>
    
  </p>
  <p>
    澳洲百汇（Bacera Co Pty Ltd）<br>
    新南威尔士州，悉尼市<br>
    萨塞克斯大街（Sussex Street）171号24楼   邮编：2000
  </p>
  <p>
   感谢您提交《BCR高端客戶申请》相关文件。本公司收到您提交的资料后，将在7个工作日内通知您申请结果。如果您对BCR高端客戶存有其他任何疑问，请通过在线聊天或者发送电子邮件与我们联系，电子邮件请发送至<a href="mailto:wholesale@au.thebcr.com">wholesale@au.thebcr.com</a>。我们期待着为您提供业内最优质的差价合约服务。
  </p>
  <br/>
  谨此问候，<br/>
  BCR公司

</div>', 'BCR高端客戶');
INSERT INTO cms."_TopicContent" ("Id", "TopicId", "CreatedOn", "UpdatedOn", "Language", "Title", "Author", "Content", "Subtitle") VALUES (11359, 11271, '2023-08-16 21:58:45.593198 +00:00', '2023-08-18 20:21:17.224997 +00:00', 'zh-cn', 'BCR高端客户欢迎函', '', e'<div style="font-size:12px;line-height:20px">
  <p style="font-size:16px;font-weight:700;line-height:24px">尊敬的BCR高端客户，</p>
  <p>
    澳洲BCR（简称“BCR公司”）已经审核并评估了您提交的高端客户（简称“BCR高端客户”）申请资料。
  </p>
  <p>
    特此出具此通知是向您确认BCR公司将您归类为BCR高端客户。您已符合《澳大利亚2001年联邦公司法》（简称“公司法”）规定的BCR高端客户资质标准。您已符合以下要求：
  </p>
  <p>内部提示：我们应具体说明客户需满足以下哪项要求：</p>
  <ol>
    <li>
      财富阈值申请程序 – 您已提供了由一名合格会计师完整填写的《由合格会计师出具的证明》表单文件，以此证明您符合本公司的财富阈值申请的其中一项要求。
    </li>
    <li>
      成熟投资者测试 – 如果您希望被归类于成熟投资者，那么，您需要满足以下要求：方式1：相关知识测试及交易历史/方式2：相关工作经验/方式3：相关正式资质。
    </li>
  </ol>
  <p style="font-weight:600;">
    您成为BCR高端客户后，将会发生哪些变化？
  </p>
  <p>
    BCR高端客户所获得的保护更少，这意味着您将无法获得面向散户而提供的某些保护。被减少的保护包括，但不限于（部分举例如下）：
  </p>
  <ul>
    <li>
      作为BCR高端客户，您不会收到某些面向散户的保护或产品披露信息。产品风险及其他重要信息，详见《BCR高端客户信息披露通知书》。
    </li>
    <li>
      根据澳大利亚证券和投资委员会（ASIC）的 ASIC公司（产品干预令 – 差价合约）工具2020/986的规定而提供的保护，其中包括：杠杆限制及负余额保护（从2021年3月29日开始）。
    </li>
    <li>
      您可能没有资格使用澳大利亚金融投诉管理局（简称“AFCA”）提供的争议解决服务。
    </li>
    <li>
      您将不会收到信息披露文件，即：《金融服务指南》和《产品信息披露声明》。
    </li>
  </ul>
  <p>
    此《客户类别通知书》将取代您之前从BCR公司接收到的任何通知书。
  </p>
  <p>
    您有权要求把您的客户类别变更为散户，这样，您就可以获得最高级别的监管保护。
  </p>
  <p>
    如果您对于您的BCR高端客户身份存有任何疑问或担忧，请联系<a href="mailto:wholesale@au.thebcr.com">wholesale@au.thebcr.com</a>.
  </p>
  <p style="font-weight:600;">
    负余额
  </p>
  <p>
    作为BCR高端客户，您可能有资格获得一次负余额保护，您的余额总额最高可达AUD$10,000澳元，此余额是您所有未平仓交易结束后，您所有交易账户的合计余额。BCR公司保留相关权利，如若有合理的证据证明存在不当行为或交易滥用导致出现负余额，那么，据本公司自行斟酌，本公司可以不给予负余额保护。在此情形下，BCR公司将向您说明未提供负余额保护的原因。
  </p>
  <p style="font-weight:600;">
    保证金平仓
  </p>
  <p>
    如果您的股本低于所要求的保证金的50%，那么，BCR公司将平仓您的头寸。
  </p>
  <p style="font-weight:600;">
    杠杆设置
  </p>
  <p>
    您的BCR高端账户上的杠杆将根据您的账户净值自动调整。更多具体详情，请参阅下表。如果您的高端账户的头寸由于账户杠杆变动而被自动平仓，BCR公司概不担责。
  </p>
  <table style="border-collapse: collapse;">
    <thead>
      <tr>
        <th style="border:1px solid black;padding:5px 10px;text-align:left;">账户净值</th>
        <th style="border:1px solid black;padding:5px 10px;">账户最大杠杆</th>
      </tr>
    </thead>
    <tbody>
      <tr>
        <td style="border:1px solid black;padding:5px 10px;">低于 $50,000</td>
        <td style="border:1px solid black;padding:5px 10px;">1:400</td>
      </tr>
      <tr>
        <td style="border:1px solid black;padding:5px 10px;">$50,001– $100,000</td>
        <td style="border:1px solid black;padding:5px 10px;">1:200</td>
      </tr>
      <tr>
        <td style="border:1px solid black;padding:5px 10px;">$100,001- $200,000</td>
        <td style="border:1px solid black;padding:5px 10px;">1:100</td>
      </tr>
      <tr>
        <td style="border:1px solid black;padding:5px 10px;">$200,001 – $300,000</td>
        <td style="border:1px solid black;padding:5px 10px;">1:50</td>
      </tr>
      <tr>
        <td style="border:1px solid black;padding:5px 10px;">$300,0001– $500,000</td>
        <td style="border:1px solid black;padding:5px 10px;">1:25</td>
      </tr>
      <tr>
        <td style="border:1px solid black;padding:5px 10px;">$500,001 - $1,000,000</td>
        <td style="border:1px solid black;padding:5px 10px;">1:20</td>
      </tr>
      <tr>
        <td style="border:1px solid black;padding:5px 10px;">$1,000,001 或更多</td>
        <td style="border:1px solid black;padding:5px 10px;">1:10</td>
      </tr>
    </tbody>
  </table>
  <p style="font-weight:600;">
    保证金使用说明
  </p>
  <p>
    您的BCR高端账户上的杠杆将根据您已使用的保证金而自动调整。更多具体详情，请参阅下表。如果您的高端账户的头寸由于账户杠杆变动而被自动平仓，BCR公司概不担责。
  </p>
  <table style="border-collapse: collapse;">
    <thead>
      <tr>
        <th style="border:1px solid black;padding:5px 10px;text-align:left;">已使用的保证金</th>
        <th style="border:1px solid black;padding:5px 10px;">账户最大杠杆</th>
      </tr>
    </thead>
    <tbody>
      <tr>
        <td style="border:1px solid black;padding:5px 10px;">低于 $50,000</td>
        <td style="border:1px solid black;padding:5px 10px;">1:400</td>
      </tr>
      <tr>
        <td style="border:1px solid black;padding:5px 10px;">$50,001– $100,000</td>
        <td style="border:1px solid black;padding:5px 10px;">1:100</td>
      </tr>
      <tr>
        <td style="border:1px solid black;padding:5px 10px;">$200,001 或更多</td>
        <td style="border:1px solid black;padding:5px 10px;">1:50</td>
      </tr>
    </tbody>
  </table>
  <p>
    如果上述账户净值规则以及保证金使用规则均适用于您的账户，那么，最低杠杆设置将适用。
  </p>
  <p style="font-weight:600;">
    例如：
  </p>
  <p >
    账户净值 = $500,000
  </p>
  <p >
    已使用的保证金 = $100,000
  </p>
  <p style="font-weight:600;">
    适用的保证金率 = 1:25
  </p>
  <p >
    根据您的BCR交易账户的计价货币，货币符号“$”可能指美元（USD），也可能指澳元（AUD）。
  </p>
  <p style="font-weight:600;">
