INSERT INTO cms."_TopicContent" ("Id", "TopicId", "CreatedOn", "UpdatedOn", "Language", "Title", "Author", "Content", "Subtitle") VALUES (11375, 11269, '2023-08-16 22:20:30.560513 +00:00', '2023-08-16 22:20:30.560513 +00:00', 'jp-jp', '証拠が必要な電子メール', '', e'<div style="font-size:12px;line-height:20px">
    <p style="font-size:16px;font-weight:700;line-height:24px">BCRクライアント様へ</p>
    <p>
        最近のBCR Proアカウント申請に関して、追加の書類が必要となりました。弊社の審査を完了させるために、以下の詳細をご確認ください。
    </p>

    <p>
        各特定のチャンネルに必要な証拠に関する詳細は以下の通りです。このメールを受信した全てのお客様は、<a href="https://bcrpropublic.s3.ap-southeast-1.amazonaws.com/docs/ba/jp-jp/Wholesale/Sophisticated+Investor+Acknowledgement.pdf">ソフィスティケートドインベスターアクノウリッジメント</a>フォームに署名と日付を行い、BCRに提出していただく必要があります。
    </p>

    <p>
        一方、BCR Proアカウントのオファリングに関する質問がある場合は、オンラインチャットまたは<a href="mailto:wholesale@au.thebcr.com">wholesale@au.thebcr.com</a>へご連絡いただくか、CFD業界で最高のサービスを提供することを楽しみにしております。
    </p>
    
    <p style="text-decoration:underline;font-weight:600;">チャンネル1：取引履歴</p>
    <ul>
        <li>
            <p>CFDブローカーからの取引明細書</p>
            <p>以前の取引履歴の証拠が必要です。過去12ヶ月間に、Margin FX、指数、商品、通貨、金属、株式に関するFirmで少なくとも75回の取引を行うか、過去12ヶ月間にMargin FX、指数、商品、通貨、金属、株式に関するFirmで少なくとも50回の重要な取引を行う必要があります。</p>
        </li>
    </ul>
    
    <p style="text-decoration:underline;font-weight:600;">チャンネル2：関連する職務経験</p>
    <p>
        以前に金融セクターで少なくとも1年間、レバレッジ取引の知識が必要なポジションで勤務した経験がある場合、専門的な職務経験の証拠を提供することができます。
    </p>
    
    <p>
        専門的な職務経験を証明するための受け入れ可能な書類の種類は以下の通りです。
    </p>
    
    <ul>
        <li>
            <p>現職の雇用主からのポジションと開始日または役割の時間を確認する手紙、ポジションの説明を含む；または</p>
        </li>
        <li>
            <p>ポジションと開始日を証明し、ポジションの説明を含む雇用契約；または</p>
        </li>
        <li>
            <p>以前の雇用主から前職の詳細なポジションと責任を示す参照；または</p>
        </li>
        <li>
            <p>ポジションと責任、開始日または関連する職務の時間を証明するLinkedInプロファイル、同じ雇用主を証明する元のPDFコピーの給与明細書。</p>
        </li>
    </ul>
    
    <p style="text-decoration:underline;font-weight:600;">チャンネル3：関連する正規の資格</p>
    <p>
        Margin FX、指数、商品、通貨、金属、株式の理解に関連する正規の資格を所有している場合、大学院課程の資格が望ましいです（例えば、Bachelor of CommerceやBachelor of Businessだけでは経験を示すには十分ではありませんが、ファイナンスや応用ファイナンスのコースや専攻は関連する場合があります）。
    </p>
    
    <p>
        正規の資格を証明するための受け入れ可能な書類の種類は以下の通りです。
    </p>
    
    <ul>
        <li>
            <p>認定された大学からのコースを指定するディプロマ；または</p>
        </li>
        <li>
            <p>ライセンスされたコンプライアンストレーニングまたはCPDコースプロバイダーからの証明書；または</p>
        </li>
        <li>
            <p>FASEA認可の高等教育プロバイダーからの証明書。</p>
        </li>
    </ul>
    
    <p>
        携帯電話で書類の写真を撮影し、<a href="mailto:wholesale@au.thebcr.com">wholesale@au.thebcr.com</a>へメールで送信していただけます。書類を受け取り次第、申請の結果を7営業日以内にお知らせいたします。
    </p>
    
    <p>
        卸売アカウントに関する追加の質問がある場合は、オンラインチャットか<a href="mailto:wholesale@au.thebcr.com">wholesale@au.thebcr.com</a>へご連絡いただくか、CFD業界で最高のサービスを提供することを楽しみにしております。
    </p>
    
    <br/>
    敬具,<br/>
    BCR
</div>
', 'ホールセールアカウント');
INSERT INTO cms."_TopicContent" ("Id", "TopicId", "CreatedOn", "UpdatedOn", "Language", "Title", "Author", "Content", "Subtitle") VALUES (11376, 11270, '2023-08-16 22:22:14.293383 +00:00', '2023-08-16 22:22:14.293383 +00:00', 'jp-jp', '証拠が必要な電子メール – 資産閾値申請', '', e'<div style="font-size:12px;line-height:20px">
