INSERT INTO cms."_TopicContent" ("Id", "TopicId", "CreatedOn", "UpdatedOn", "Language", "Title", "Author", "Content", "Subtitle") VALUES (11381, 11270, '2023-08-16 22:27:31.285298 +00:00', '2023-08-16 22:27:31.285298 +00:00', 'vi-vn', ' Email Yêu cầu Bằng chứng – Đơn xin Ngưỡng Giàu có', '', e'<div style="font-size:12px;line-height:20px">
  <p style="font-size:16px;font-weight:700;line-height:24px">Kính gửi Quý khách hàng của BCR,</p>
  <p>
    Xin chân thành cảm ơn Quý khách hàng vì đã gửi đơn đăng ký gần đây để trở thành BCR Pro. 
  </p>

  <p>
   Do Quý khách hàng đã nộp đơn dưới Hồ sơ Ngưỡng Tài sản, Quý khách hàng cần một thành viên đủ điều kiện của một tổ chức kiểm toán chuyên nghiệp để hoàn thành<a href="https://bcrpropublic.s3.ap-southeast-1.amazonaws.com/docs/ba/vi-vn/Wholesale/Certificate+By+a+Qualified+Accountant.pdf"> Mẫu Chứng nhận của Kế toán viên Đủ điều kiện</a> xác nhận rằng Quý khách hàng đáp ứng một trong các tiêu chí sau: 
  </p>
  <ul>
    <li>
       	Có tài sản ròng ít nhất là AUD$2.5 triệu  HOẶC
    </li>
    <li>
       	Có thu nhập gộp trong mỗi trong 2 năm tài chính gần đây ít nhất là AUD$250.000
    </li>
  </ul>
  <p>
    Xin vui lòng gửi ảnh quét hoàn thành Mẫu Chứng nhận qua email tới <a href="mailto:wholesale@au.thebcr.com">wholesale@au.thebcr.com</a>. <br>
    Xin vui lòng gửi bản gốc của Mẫu Chứng nhận đến văn phòng của BCR tại:
  </p>
  <p>
    
  </p>
  <p>
    Công ty TNHH Bacera<br>
    Tầng 24, 171 Sussex Street <br>
    Sydney, NSW 2000

  </p>
  <p>
    Xin chân thành cảm ơn vì đã nộp tài liệu liên quan đến Đơn đăng ký Tài khoản Sỉ của Quý khách hàng. Sau khi chúng tôi nhận được tài liệu của Quý khách hàng, chúng tôi sẽ thông báo kết quả đơn đăng ký trong vòng 7 ngày làm việc. Nếu Quý khách hàng có bất kỳ câu hỏi nào liên quan đến tài khoản Sỉ, xin vui lòng liên hệ chúng tôi qua trò chuyện trực tuyến hoặc gửi email tới địa chỉ <a href="mailto:wholesale@au.thebcr.com">wholesale@au.thebcr.com</a>. Chúng tôi mong đợi mang đến dịch vụ tốt nhất trong ngành CFD.
  </p>
  <br/>
  Trân trọng,<br/>
  BCR

</div>
', 'Tài khoản Bán buôn');
INSERT INTO cms."_TopicContent" ("Id", "TopicId", "CreatedOn", "UpdatedOn", "Language", "Title", "Author", "Content", "Subtitle") VALUES (11382, 11271, '2023-08-16 22:28:59.343760 +00:00', '2023-08-16 22:28:59.343760 +00:00', 'vi-vn', ' Thư chào mừng tài khoản BCR Pro', '', e'<div style="font-size:12px;line-height:20px">
  <p style="font-size:16px;font-weight:700;line-height:24px">Kính gửi Quý khách hàng của BCR,</p>
  <p>
    Công ty TNHH Bacera ("BCR") đã xem xét và đánh giá đơn đăng ký của Quý khách hàng để được phân loại là Khách hàng Sỉ ("BCR Pro").
  </p>
  <p>
    Đây là thông báo xác nhận rằng BCR phân loại Quý khách hàng là Khách hàng Sỉ. Quý khách hàng đã đáp ứng tiêu chí của một Khách hàng Sỉ theo Đạo luật về Tổ chức năm 2001 (Cth) (theo "Đạo luật về Tổ chức"). Quý khách hàng đã đáp ứng các yêu cầu sau đây:
  </p>
  <p>Chú thích nội bộ: chúng ta cần xác định yêu cầu nào mà khách hàng đã đáp ứng:</p>
  <ol>
    <li>
      Đơn đăng ký Ngưỡng Tài sản - Quý khách hàng đã cung cấp Mẫu Chứng nhận của Kế toán viên Đủ điều kiện đã được hoàn thành, xác nhận Quý khách hàng đáp ứng một trong những yêu cầu của Đơn đăng ký Ngưỡng Tài sản của chúng tôi.
    </li>
    <li>
      Kiểm tra Nhà đầu tư Tinh vi - Quý khách hàng đã đáp ứng yêu cầu của Kênh 1: Kiểm tra Kiến thức và Lịch sử Giao dịch / Kênh 2: Kinh nghiệm làm việc có liên quan / Kênh 3: Bằng cấp chuyên ngành có liên quan để được phân loại là Nhà đầu tư Tinh vi.
    </li>
  </ol>
  <p style="font-weight:600;">
    Những thay đổi khi Quý khách hàng trở thành Khách hàng Sỉ?
  </p>
  <p>
    Phân loại này sẽ giảm bớt các quyền lợi được cấp, điều này có nghĩa là Quý khách hàng sẽ không có lợi ích từ một số quyền lợi được cấp cho Khách hàng Bán lẻ. Các quyền lợi giảm bao gồm nhưng không giới hạn ở các ví dụ dưới đây:
  </p>
  <ul>
    <li>
      Là một khách hàng sỉ, Quý khách hàng sẽ không nhận được một số quyền lợi được cấp cho khách hàng bán lẻ hoặc một tuyên bố tiết lộ sản phẩm. Những thông tin về rủi ro sản phẩm và thông tin quan trọng khác được nêu chi tiết trong Thông báo Tiết lộ Khách hàng Sỉ.
    </li>
    <li>
      Quyền lợi dưới sắc lệnh Can thiệp Sản phẩm của ASIC - Công cụ Hợp đồng cho Sự khác biệt 2020/986 bao gồm hạn chế đòn bẩy và bảo vệ số dư âm (bắt đầu từ ngày 29 tháng 3 năm 2021).
    </li>
    <li>
      Có thể không đủ điều kiện để truy cập dịch vụ giải quyết tranh chấp do Tổ chức Kiến nghị Tài chính Australia ("AFCA") cung cấp.
    </li>
    <li>
      Quý khách hàng sẽ không nhận được các tài liệu tiết lộ, chẳng hạn như Hướng dẫn Dịch vụ Tài chính và Tuyên bố tiết lộ sản phẩm.
    </li>
  </ul>
  <p>
    Phân loại này thay thế bất kỳ thông báo trước đây mà Quý khách hàng có thể đã nhận từ BCR.
  </p>
  <p>
    Quý khách hàng có quyền yêu cầu thay đổi phân loại của mình thành Khách hàng Bán lẻ, cho phép Quý khách hàng nhận được mức bảo vệ theo quy định cao nhất.
  </p>
  <p>
    Nếu Quý khách hàng có bất kỳ câu hỏi hoặc lo ngại nào liên quan đến tình trạng Khách hàng Sỉ của mình, xin vui lòng liên hệ <a href="mailto:wholesale@au.thebcr.com">wholesale@au.thebcr.com</a>.
  </p>

  <p style="font-weight:600;">
    Số Dư Âm
  </p>
  <p>
    Là một khách hàng sỉ, Quý khách hàng có thể được hưởng quyền bảo vệ số dư âm duy nhất lên đến AUD$10,000 của tổng số dư của tất cả các tài khoản giao dịch sau khi tất cả các giao dịch đang mở đã được đóng lại. BCR có quyền từ chối cấp bảo vệ số dư âm trong trường hợp có bằng chứng hợp lý, do quyết định riêng của chúng tôi, về hành vi sai trái hoặc lạm dụng giao dịch dẫn đến sự xuất hiện của số dư âm. Trong trường hợp này, BCR sẽ cung cấp lý do tại sao bảo vệ số dư âm không được áp dụng.
  </p>
  <p style="font-weight:600;">
    Đóng Hạn Mức
  </p>
  <p>
    BCR sẽ đóng tài khoản(s) của Quý khách hàng nếu vốn sở hữu của Quý khách hàng giảm xuống dưới 50% của tổng vốn cần thiết.
  </p>
  <p style="font-weight:600;">
    Thiết Lập Đòn Bẩy
  </p>
  <p>
    Đòn bẩy trên tài khoản BCR Pro của Quý khách hàng sẽ được tự động điều chỉnh dựa trên Vốn tài khoản. Xem bảng dưới đây để biết thêm thông tin cụ thể. BCR sẽ không chịu trách nhiệm nếu các vị trí tài khoản Pro của Quý khách hàng bị đóng tự động do thay đổi đòn bẩy của tài khoản.
  </p>
  <table style="border-collapse: collapse;">
    <thead>
      <tr>
        <th style="border:1px solid black;padding:5px 10px;text-align:left;">Vốn Tài khoản</th>
        <th style="border:1px solid black;padding:5px 10px;">Đòn Bẩy Tối đa Tài khoản</th>
      </tr>
    </thead>
    <tbody>
      <tr>
        <td style="border:1px solid black;padding:5px 10px;">Dưới $50,000</td>
        <td style="border:1px solid black;padding:5px 10px;">1:400</td>
      </tr>
      <tr>
        <td style="border:1px solid black;padding:5px 10px;">$50,001– $100,000</td>
        <td style="border:1px solid black;padding:5px 10px;">1:200</td>
      </tr>
      <tr>
        <td style="border:1px solid black;padding:5px 10px;">$100,001- $200,000</td>
        <td style="border:1px solid black;padding:5px 10px;">1:100</td>
      </tr>
      <tr>
        <td style="border:1px solid black;padding:5px 10px;">$200,001 – $300,000</td>
        <td style="border:1px solid black;padding:5px 10px;">1:50</td>
      </tr>
      <tr>
        <td style="border:1px solid black;padding:5px 10px;">$300,0001– $500,000</td>
        <td style="border:1px solid black;padding:5px 10px;">1:25</td>
      </tr>
      <tr>
        <td style="border:1px solid black;padding:5px 10px;">$500,001 - $1,000,000</td>
        <td style="border:1px solid black;padding:5px 10px;">1:20</td>
      </tr>
      <tr>
        <td style="border:1px solid black;padding:5px 10px;">$1,000,001 hoặc hơn</td>
        <td style="border:1px solid black;padding:5px 10px;">1:10</td>
      </tr>
    </tbody>
  </table>
  <p style="font-weight:600;">
    Sử dụng Vốn
  </p>
  <p>
    Đòn bẩy trên tài khoản BCR Pro của Quý khách hàng sẽ được tự động điều chỉnh dựa trên Vốn Sử dụng. Xem bảng dưới đây để biết thêm thông tin cụ thể. BCR sẽ không chịu trách nhiệm nếu các vị trí tài khoản Pro của Quý khách hàng bị đóng tự động do thay đổi đòn bẩy của tài khoản.
  </p>
  <table style="border-collapse: collapse;">
    <thead>
      <tr>
        <th style="border:1px solid black;padding:5px 10px;text-align:left;">Vốn Sử dụng</th>
        <th style="border:1px solid black;padding:5px 10px;">Đòn Bẩy Tối đa Tài khoản</th>
      </tr>
    </thead>
    <tbody>
      <tr>
        <td style="border:1px solid black;padding:5px 10px;">Dưới $50,000</td>
        <td style="border:1px solid black;padding:5px 10px;">1:400</td>
      </tr>
      <tr>
        <td style="border:1px solid black;padding:5px 10px;">$50,001– $100,000</td>
        <td style="border:1px solid black;padding:5px 10px;">1:100</td>
      </tr>
      <tr>
        <td style="border:1px solid black;padding:5px 10px;">$200,001 hoặc hơn</td>
        <td style="border:1px solid black;padding:5px 10px;">1:50</td>
      </tr>
    </tbody>
  </table>
  <p>
    Trong trường hợp cả hai quy tắc Vốn Tài khoản & Sử dụng Vốn có thể áp dụng cho tài khoản của Quý khách hàng, quy tắc đòn bẩy áp dụng thấp nhất sẽ được áp dụng.
  </p>
  <p style="font-weight:600;">
    Ví dụ:
  </p>
  <p>
    Vốn Tài khoản = $500,000
  </p>
  <p>
    Vốn Sử dụng = $100,000
  </p>
  <p style="font-weight:600;">
    Đòn Bẩy Áp dụng = 1:25
  </p>
  <p>
    “$” có thể áp dụng cho USD hoặc AUD, dựa trên đồng tiền sử dụng trong tài khoản giao dịch BCR của Quý khách hàng.
  </p>
  <p style="font-weight:600;">
    Hướng Dẫn Nạp Tiền
  </p>
  <p>
    Dưới đây là thông tin ngân hàng cần thiết để thực hiện việc nạp tiền vào tài khoản giao dịch BCR Pro của Quý khách hàng. Khách hàng chỉ có thể nạp tiền vào tài khoản của họ bằng cách chuyển khoản ngân hàng. BCR có thể không thực hiện hoặc nhận thanh toán từ bên thứ ba. Chúng tôi chỉ chấp nhận khoản nạp tiền vào tài khoản của chủ tài khoản.
  </p>
  <table style="border-collapse: collapse;">
    <thead>
      <tr>
