      </tr>
            <tr>
        <td style="border:1px solid black;padding:5px 10px; font-weight:600;background-color:#d9d9d9;">Địa chỉ Người Hưởng:</td>
        <td style="border:1px solid black;padding:5px 10px;">48 Martin Place Sydney, Sydney, NSW 2000, Australia</td>
      </tr>
            <tr>
        <td style="border:1px solid black;padding:5px 10px; font-weight:600;background-color:#d9d9d9;">Số tài khoản Người Hưởng:</td>
        <td style="border:1px solid black;padding:5px 10px;">200015750601</td>
      </tr>
                  <tr>
        <td style="border:1px solid black;padding:5px 10px; font-weight:600;background-color:#d9d9d9;">Ghi chú:</td>
