INSERT INTO cms."_TopicContent" ("Id", "TopicId", "CreatedOn", "UpdatedOn", "Language", "Title", "Author", "Content", "Subtitle") VALUES (11386, 11275, '2023-09-13 18:25:06.868884 +00:00', '2024-04-04 22:06:48.834291 +00:00', 'en-us', 'Customer Withdrawal Confirmation', 'system', e'<div style="font-size: 12px; line-height: 20px">
