      </th>
      <td
          style="

                 padding-left: 24px;
                 padding-right: 24px;
                 word-wrap: break-word;
                 "
          >
        {{NativeName}}
      </td>
    </tr>
    <tr>
      <th
          style="
                 padding-left: 24px;
                 padding-right: 24px;
                 color: #383d49;
                 white-space: nowrap;
                 "
          >
        Currency:
      </th>
      <td
          style="
                 padding-left: 24px;
                 padding-right: 24px;
                 word-wrap: break-word;
                 "
          >
        {{Currency}}
      </td>
    </tr>
    <tr>
      <th
          style="
                 padding-left: 24px;
                 padding-right: 24px;
                 color: #383d49;
                 white-space: nowrap;
                 "
          >
        Amount:
      </th>
      <td
          style="
                 padding-left: 24px;
                 padding-right: 24px;
                 word-wrap: break-word;
                 "
          >
        $ {{Amount}}
      </td>
    </tr>
  </table>
  <p>
    To check your withdrawal records, log in to the
    <a
       target="_blank"
       href="https://cfds-portal.thebcr.com/"
       style="
              color: #383d49;
              text-decoration: none;
              font-weight: 700;
              "
       >MyBCR</a
      >
    section of your account.
  </p>
</div>', ' ');
INSERT INTO cms."_TopicContent" ("Id", "TopicId", "CreatedOn", "UpdatedOn", "Language", "Title", "Author", "Content", "Subtitle") VALUES (11469, 11286, '2024-01-04 19:16:25.273473 +00:00', '2024-04-11 20:34:31.627899 +00:00', 'vi-vn', 'Client Daily Confirmation', '', e'<meta http-equiv="content-type" content="text/html;charset=utf-8" />
<table
  align="center"
  style="
    width: 900px;
    border-collapse: collapse;
    font-family: \'微软雅黑\';
    padding: 5px 0px;
    -moz-border-radius: 5px;
    -webkit-border-radius: 5px;
    border-radius: 5px;
    border: 0px #ddcebd solid;
    background: url(https://s3.amazonaws.com/bcr-img-new/email/docs_bg.png)
      repeat-y;
    background-position: right 0 top 0;
  "
>
  <tr>
    <td>
      <table style="width: 100%">
        <tr>
          <td
            style="
              text-align: left;
              line-height: 40px;
              font-size: 32px;
              font-family: \'Times New Roman\', Times, serif;
            "
          >
            <img src="https://s3.amazonaws.com/bcr-img-new/bcr_logo.png" />
          </td>
        </tr>
      </table>
    </td>
  </tr>
  <tr>
    <td>
      <table style="width: 100%; font-size: 12px">
        <tr>
          <td style="width: 25%">
            Tài khoản: <strong>@Model.AccountNumber</strong>
          </td>
          <td style="width: 25%">Tên: <strong>@Model.NativeName</strong></td>
          <td style="width: 25%"></td>
          <td style="width: 25%; text-align: right">
            @Model.ReportDate.ToString("yyyy-MM-dd HH:mm:ss")
          </td>
        </tr>
      </table>
    </td>
  </tr>
  <tr>
    <td>
      <table
        style="
          width: 100%;
          font-size: 10px;
          text-align: right;
          line-height: 20px;
          border-collapse: collapse;
          border: 0px solid #cccccc;
        "
      >
        <tr>
          <td colspan="13" align="left"><strong>Giao dịch Đóng:</strong></td>
        </tr>
        <tr
          style="
            background: #f5f5f5;
            text-align: center;
            border: 1px solid #cccccc;
          "
        >
          <td style="border: 1px solid #cccccc" width="7%">Số Giao dịch</td>
          <td style="border: 1px solid #cccccc" width="12%">Thời gian Mở</td>
          <td style="border: 1px solid #cccccc" width="7%">Loại</td>
          <td style="border: 1px solid #cccccc" width="6%">Kích thước</td>
          <td style="border: 1px solid #cccccc" width="7%">Sản phẩm</td>
          <td style="border: 1px solid #cccccc" width="7%">Giá</td>
          <td style="border: 1px solid #cccccc" width="7%">S/L</td>
          <td style="border: 1px solid #cccccc" width="7%">T/P</td>
          <td style="border: 1px solid #cccccc" width="12%">Thời gian Đóng</td>
          <td style="border: 1px solid #cccccc" width="7%">Giá</td>
          <td style="border: 1px solid #cccccc" width="7%">Phí Giao dịch</td>
          <td style="border: 1px solid #cccccc" width="7%">Hoán đổi</td>
          <td style="border: 1px solid #cccccc" width="7%">
            Lợi nhuận Giao dịch
          </td>
        </tr>
        @{ var color = new[] { "#FFFFFF;", "#EEEEEE;" }; var counter = 0; } @if
        (Model.ClosedTrades != null && Model.ClosedTrades.Count > 0) { foreach
        (var trade in Model.ClosedTrades) {
        <tr style="background: @color[counter++ % 2]">
          <td style="border: 1px solid #cccccc">@trade.Ticket</td>
          <td style="border: 1px solid #cccccc">
                        @trade.OpenAt.ToString("yyyy-MM-dd HH:mm:ss")
                                            </td>
                                           <td style="border: 1px solid #cccccc">@if(trade.Cmd == 1) { <text>Sell</text> } else if (trade.Cmd == 0){ <text>Buy</text>
                                                                }
                                                                else if (trade.Cmd == 6){ <text>Balance</text> }
                                                            </td>
                                                                
                                                                                    @if (trade.Cmd < 2) {
                                                                                    <td style="border: 1px solid #cccccc">@trade.Volume</td>
                                                                                    <td style="border: 1px solid #cccccc">@trade.Symbol</td>
                                                                                    <td style="border: 1px solid #cccccc">
                                                                                        @string.Format("{0:F" + trade.Digits + "}", trade.OpenPrice ?? 0)
                                                                                    </td>
                                                                                    <td style="border: 1px solid #cccccc">
                                                                                        @string.Format("{0:F" + trade.Digits + "}", trade.Sl)
                                                                                                                                                                            </td>
                                                                                                                                                                            <td style="border: 1px solid #cccccc">
                                                                                                                                                                                @string.Format("{0:F" + trade.Digits + "}", trade.Tp)
                                                                                                                                                                            </td>
                                                                                                                                                                            <td style="border: 1px solid #cccccc">@trade.CloseAt</td>
                                                                                                                                                                            <td style="border: 1px solid #cccccc">
                                                                                                                                                                                @string.Format("{0:F" + trade.Digits + "}", trade.ClosePrice ?? 0)
                                                                                                                                                                            </td>
                                                                                                                                                                            <td style="border: 1px solid #cccccc">
                                                                                                                                                                                @string.Format("{0:N2}", trade.Commission)
                                                                                                                                                                            </td>
                                                                                                                                                                            <td style="border: 1px solid #cccccc">
                                                                                                                                                                                @string.Format("{0:N2}", trade.Swaps)
                                                                                                                                                                            </td>
                                                                                                                                                                            } else if (trade.Cmd > 5) {
                                                                                                                                                                            <td style="border: 1px solid #cccccc" colspan="9" align="right">
                                                                                                                                                                                @trade.Comment
                                                                                                                                                                            </td>
                                                                                                                                                                            }
                                                                                                                                                        
                                                                                                                                                                            <td style="border: 1px solid #cccccc">
                                                                                                                                                                                @string.Format("{0:N2}", trade.Profit)
                                                                                                                                                                            </td>
                                                                                                                                                                        </tr>
                                                                                                                                                                        } } else {
                                                                                                                                                                        <tr style="background: #ffffff; text-align: center">
                                                                                                                                                                            <td style="border: 1px solid #cccccc" colspan="13">
                                                                                                                                                                                Không có giao dịch
                                                                                                                                                                            </td>
                                                                                                                                                                        </tr>
                                                                                                                                                                        }
                                                                                                                                                        
                                                                                                                                                                        <tr style="background: #eeeeee">
                                                                                                                                                                            <td style="border: 1px solid #cccccc" colspan="10"></td>
                                                                                                                                                                            <td style="border: 1px solid #cccccc">
                                                                                                                                                                                @string.Format("{0:N2}", Model.ClosedTradeSummary.Commission)
                                                                                                                                                                            </td>
                                                                                                                                                                            <td style="border: 1px solid #cccccc">
                                                                                                                                                                                @string.Format("{0:N2}", Model.ClosedTradeSummary.Swaps)
                                                                                                                                                                            </td>
                                                                                                                                                                            <td style="border: 1px solid #cccccc">
                                                                                                                                                                                @string.Format("{0:N2}", Model.ClosedTradeSummary.Profit)
                                                                                                                                                                            </td>
                                                                                                                                                                        </tr>
                                                                                                                                                                    </table>
                                                                                                                                                                </td>
                                                                                                                                                            </tr>
                                                                                                                                                            <tr>
                                                                                                                                                                <td>
                                                                                                                                                                    <table style="width: 100%; font-size: 12px">
                                                                                                                                                                        <tr>
                                                                                                                                                                            <td>
                                                                                                                                                                                <strong>
                                                                                                                                                                                    Gửi/Rút tiền: @string.Format("{0:N2}",
                                                                                                                                                                                    Model.ClosedTradeSummary.Deposit)
                                                                                                                                                                                </strong>
                                                                                                                                                                            </td>
                                                                                                                                                                            <td>
                                                                                                                                                                                <strong>
                                                                                                                                                                                    Dư nợ tín dụng: @string.Format("{0:N2}",
                                                                                                                                                                                    Model.ClosedTradeSummary.Credit)
                                                                                                                                                                                </strong>
                                                                                                                                                                            </td>
                                                                                                                                                                            <td style="text-align: right">
                                                                                                                                                                                <strong>
                                                                                                                                                                                    Lãi/lỗ giao dịch Đóng:
                                                                                                                                                                                    &nbsp;&nbsp;&nbsp;&nbsp;@string.Format("{0:N2}",
                                                                                                                                                                                    Model.ClosedTradeSummary.TotalProfit)
                                                                                                                                                                                </strong>
                                                                                                                                                                            </td>
                                                                                                                                                                        </tr>
                                                                                                                                                                    </table>
                                                                                                                                                                </td>
                                                                                                                                                            </tr>
                                                                                                                                                            <tr>
                                                                                                                                                                <td>&nbsp;</td>
                                                                                                                                                            </tr>
                                                                                                                                                            <tr>
                                                                                                                                                                <td>
                                                                                                                                                                    <table
                                                                                                                                                                        style="
                                                                                                                                                                            width: 100%;
                                                                                                                                                                            font-size: 10px;
                                                                                                                                                                            text-align: right;
                                                                                                                                                                            line-height: 20px;
                                                                                                                                                                            border-collapse: collapse;
                                                                                                                                                                            border: 0px solid #cccccc;
                                                                                                                                                                        "
                                                                                                                                                                    >
                                                                                                                                                                        <tr>
                                                                                                                                                                            <td colspan="12" align="left"><strong>Giao dịch Mở:</strong></td>
                                                                                                                                                                        </tr>
                                                                                                                                                                        <tr
                                                                                                                                                                            style="
                                                                                                                                                                                background: #f5f5f5;
                                                                                                                                                                                text-align: center;
                                                                                                                                                                                border: 1px solid #cccccc;
                                                                                                                                                                                font-size: 11px;
                                                                                                                                                                            "
                                                                                                                                                                        >
                                                                                                                                                                            <td style="border: 1px solid #cccccc" width="7%">Mã giao dịch</td>
                                                                                                                                                                            <td style="border: 1px solid #cccccc" width="12%">Thời gian mở</td>
                                                                                                                                                                            <td style="border: 1px solid #cccccc" width="7%">Loại</td>
                                                                                                                                                                            <td style="border: 1px solid #cccccc" width="6%">Kích thước</td>
                                                                                                                                                                            <td style="border: 1px solid #cccccc" width="7%">Mặt hàng</td>
