                                                                                                                                                                            </td>
                                                                                                                                                                            <td style="border: 1px solid #cccccc">
                                                                                                                                                                                @string.Format("{0:N2}", trade.Commission)
                                                                                                                                                                            </td>
                                                                                                                                                                            <td style="border: 1px solid #cccccc">
                                                                                                                                                                                @string.Format("{0:N2}", trade.Swaps)
                                                                                                                                                                            </td>
                                                                                                                                                                            <td style="border: 1px solid #cccccc">
                                                                                                                                                                                @string.Format("{0:N2}", trade.Profit)
                                                                                                                                                                            </td>
                                                                                                                                                                        </tr>
                                                                                                                                                                        } } } else {
                                                                                                                                                                        <tr style="background: #ffffff; text-align: center">
                                                                                                                                                                            <td style="border: 1px solid #cccccc" colspan="13">
                                                                                                                                                                                Không có giao dịch
                                                                                                                                                                            </td>
                                                                                                                                                                        </tr>
