                                                                                                                                                                        <tr>
                                                                                                                                                                            <td><strong>&nbsp;</strong></td>
                                                                                                                                                                            <td align="right">
                                                                                                                                                                                <strong>
                                                                                                                                                                                    Lãi/lỗ giao dịch thường: &nbsp;&nbsp;&nbsp;&nbsp;
                                                                                                                                                                                    @string.Format("{0:N2}",  Model.OpenTradeSummary.TotalProfit)
                                                                                                                                                                                </strong>
                                                                                                                                                                            </td>
                                                                                                                                                                        </tr>
                                                                                                                                                                    </table>
                                                                                                                                                                </td>
                                                                                                                                                            </tr>
                                                                                                                                                            <tr>
                                                                                                                                                                <td>&nbsp;</td>
                                                                                                                                                            </tr>
                                                                                                                                                            <tr>
                                                                                                                                                                <td>
                                                                                                                                                                    <table style="width: 100%; font-size: 12px; border-collapse: collapse">
