                                                                                                                                                                            line-height: 20px;
                                                                                                                                                                            border-collapse: collapse;
                                                                                                                                                                        "
                                                                                                                                                                    >
                                                                                                                                                                        <tr>
                                                                                                                                                                            <td colspan="12" align="left">
