                                                                                                                                                                            <td style="width: 25%">Lợi nhuận/Thua lỗ dạng nổi:</td>
                                                                                                                                                                            <td style="width: 25%; text-align: right">
                                                                                                                                                                                <strong
                                                                                                                                                                                    >@string.Format("{0:N2}",  Model.OpenTradeSummary.TotalProfit)</strong
                                                                                                                                                                                >
                                                                                                                                                                            </td>
                                                                                                                                                                        </tr>
                                                                                                                                                                        <tr>
                                                                                                                                                                            <td style="width: 25%; text-align: left">
                                                                                                                                                                                Lợi nhuận/Thua lỗ từ các giao dịch đã đóng:
                                                                                                                                                                            </td>
                                                                                                                                                                            <td style="width: 25%">
                                                                                                                                                                                <strong
                                                                                                                                                                                    >@string.Format("{0:N2}", Model.ClosedTradeSummary.Profit)</strong
                                                                                                                                                                                >
                                                                                                                                                                            </td>
                                                                                                                                                                            <td style="width: 25%">Tín dụng:</td>
                                                                                                                                                                            <td style="width: 25%; text-align: right">
                                                                                                                                                                                <strong>@string.Format("{0:N2}", Model.Summary.Credit)</strong>
                                                                                                                                                                            </td>
                                                                                                                                                                        </tr>
                                                                                                                                                                        <tr>
                                                                                                                                                                            <td style="width: 25%; text-align: left">Tiền gửi/Rút tiền:</td>
                                                                                                                                                                            <td style="width: 25%">
                                                                                                                                                                                <strong
                                                                                                                                                                                    >@string.Format("{0:N2}", Model.Summary.Deposit)</strong
                                                                                                                                                                                >
                                                                                                                                                                            </td>
                                                                                                                                                                            <td style="width: 25%">Vốn:</td>
                                                                                                                                                                            <td style="width: 25%; text-align: right">
                                                                                                                                                                                <strong
                                                                                                                                                                                    >@string.Format("{0:N2}", (Model.Summary.Balance +
                                                                                                                                                                                    Model.Summary.Credit +
                                                                                                                                                                                    Model.OpenTradeSummary.TotalProfit))</strong
                                                                                                                                                                                >
                                                                                                                                                                            </td>
                                                                                                                                                                        </tr>
                                                                                                                                                                        <tr>
                                                                                                                                                                            <td style="width: 25%; text-align: left">Số dư:</td>
                                                                                                                                                                            <td style="width: 25%">
                                                                                                                                                                                <strong>@string.Format("{0:N2}", Model.Summary.Balance)</strong>
                                                                                                                                                                            </td>
                                                                                                                                                                            <td style="width: 25%">Yêu cầu thế chấp:</td>
                                                                                                                                                                            <td style="width: 25%; text-align: right">
                                                                                                                                                                                <strong>@string.Format("{0:N2}", Model.Summary.Margin)</strong>
                                                                                                                                                                            </td>
                                                                                                                                                                        </tr>
                                                                                                                                                                        <tr>
                                                                                                                                                                            <td style="width: 25%">&nbsp;</td>
                                                                                                                                                                            <td style="width: 25%">&nbsp;</td>
                                                                                                                                                                            <td style="width: 25%">Thế chấp có sẵn:</td>
                                                                                                                                                                            <td style="width: 25%; text-align: right">
                                                                                                                                                                                <strong
                                                                                                                                                                                    >@string.Format("{0:N2}", (Model.Summary.Balance +
                                                                                                                                                                                    Model.Summary.Credit + Model.OpenTradeSummary.TotalProfit -
                                                                                                                                                                                    Model.Summary.Margin))</strong
                                                                                                                                                                                >
                                                                                                                                                                            </td>
                                                                                                                                                                        </tr>
                                                                                                                                                                    </table>
                                                                                                                                                                </td>
                                                                                                                                                            </tr>
                                                                                                                                                            <tr>
                                                                                                                                                                <td>&nbsp;</td>
                                                                                                                                                            </tr>
                                                                                                                                                            <tr>
                                                                                                                                                                <td align="left" style="font-size: 12px">Trân trọng,</td>
                                                                                                                                                            </tr>
                                                                                                                                                            <tr>
                                                                                                                                                                <td align="left" style="font-size: 12px">BCR</td>
                                                                                                                                                            </tr>
                                                                                                                                                            <tr>
                                                                                                                                                                <td align="center" style="font-size: 10px">
                                                                                                                                                                    Vui lòng báo cáo cho chúng tôi trong vòng 48 giờ nếu bản tuyên bố này
                                                                                                                                                                    không chính xác. Nếu không, bản tuyên bố này sẽ được xem xét là đã được
                                                                                                                                                                    xác nhận bởi bạn.
                                                                                                                                                                </td>
                                                                                                                                                            </tr>
                                                                                                                                                            <tr>
                                                                                                                                                                <td align="center" style="font-size: 10px">
                                                                                                                                                                    Tất cả số dư lợi nhuận/thua lỗ và số liệu vốn được tính dựa trên giá cả
                                                                                                                                                                    của các công cụ tài chính tại thời điểm báo cáo được tạo ra và có thể khác
                                                                                                                                                                    với giá đóng cửa thực tế của các công cụ tài chính.
                                                                                                                                                                </td>
                                                                                                                                                            </tr>
                                                                                                                                                        </table>
                                                                                                                                                        ', '');
INSERT INTO cms."_TopicContent" ("Id", "TopicId", "CreatedOn", "UpdatedOn", "Language", "Title", "Author", "Content", "Subtitle") VALUES (11583, 11325, '2024-03-26 19:04:24.612306 +00:00', '2024-03-26 19:04:24.612306 +00:00', 'th-th', ' โอนใบสมัคร', '', e'<div style="font-size: 12px; line-height: 20px">
  <p
     style="font-size: 16px; font-weight: 700; line-height: 24px"
     >
    เรียนลูกค้าท่านสุดความเป็นเจ้าของ,
  </p>
  <p>
    คำขอการโอนเงินของท่านได้รับการดำเนินการเรียบร้อยแล้ว กรุณารอการดำเนินการ 1-2 วันทำการ เพิ่มเติมด้านล่าง:
  </p>
  <table
         class="letter-table"
         style="
                table-layout: fixed;
                line-height: 24px;
                margin-left: auto;
                margin-right: auto;
                text-align: left;
                padding: 8px;
                float: none;
                "
         bgcolor="#f2f2f2"
         align="left"
         >
    <tr>
      <th
          style="
                 padding-left: 24px;
                 padding-right: 24px;
                 color: #383d49;
                 white-space: nowrap;
                 "
          >
        จาก:
      </th>
      <td
          style="
                 padding-left: 24px;
                 padding-right: 24px;
                 word-wrap: break-word;
                 "
          >
        {{SourceAccountNumber}}
      </td>
    </tr>
    <tr>
      <th
          style="
                 padding-left: 24px;
                 padding-right: 24px;
                 color: #383d49;
                 white-space: nowrap;
                 "
          >
       ถึง:
      </th>
      <td
          style="
                 padding-left: 24px;
                 padding-right: 24px;
                 word-wrap: break-word;
                 "
          >
        {{TargetAccountNumber}}
      </td>
    </tr>
    <tr>
      <th
          style="
                 padding-left: 24px;
                 padding-right: 24px;
                 color: #383d49;
                 white-space: nowrap;
                 "
          >
        จำนวนเงินที่โอน:
      </th>
      <td
          style="
                 padding-left: 24px;
                 padding-right: 24px;
                 word-wrap: break-word;
                 "
          >
     $ {{FormattedAmount}}
      </td>
    </tr>
    <tr>
      <th
          style="
                 padding-left: 24px;
                 padding-right: 24px;
                 color: #383d49;
                 white-space: nowrap;
                 "
          >
        วันที่โอน:
      </th>
      <td
          style="
                 padding-left: 24px;
                 padding-right: 24px;
                 word-wrap: break-word;
                 "
          >
      {{Date}}
      </td>
    </tr>
  </table>

</div>
', '');
INSERT INTO cms."_TopicContent" ("Id", "TopicId", "CreatedOn", "UpdatedOn", "Language", "Title", "Author", "Content", "Subtitle") VALUES (11585, 11325, '2024-03-26 19:07:07.369019 +00:00', '2024-03-26 19:07:07.369019 +00:00', 'mn-mn', 'Өргөдөл шилжүүлэх', '', e'<div style="font-size: 12px; line-height: 20px">
  <p
     style="font-size: 16px; font-weight: 700; line-height: 24px"
     >
    Урагшаарай хэрэглэгч,
  </p>
  <p>
    Таны шилжүүлгийн хүсэлт амжилттай болов. Захиалгыг боловсруулахад 1-2 ажлын өдрөө зөвшөөрөхийг оролдож байна. Нэмэлт мэдээлэл доорхи байрлалтай:
  </p>
  <table
         class="letter-table"
         style="
                table-layout: fixed;
                line-height: 24px;
                margin-left: auto;
                margin-right: auto;
                text-align: left;
                padding: 8px;
                float: none;
                "
         bgcolor="#f2f2f2"
         align="left"
         >
    <tr>
      <th
          style="
                 padding-left: 24px;
                 padding-right: 24px;
                 color: #383d49;
                 white-space: nowrap;
                 "
          >
        Эхлээд:
      </th>
      <td
          style="
                 padding-left: 24px;
                 padding-right: 24px;
                 word-wrap: break-word;
                 "
          >
        {{SourceAccountNumber}}
      </td>
    </tr>
    <tr>
      <th
          style="
                 padding-left: 24px;
                 padding-right: 24px;
                 color: #383d49;
                 white-space: nowrap;
                 "
          >
       Хүлээн авах:
      </th>
      <td
          style="
                 padding-left: 24px;
                 padding-right: 24px;
                 word-wrap: break-word;
                 "
          >
        {{TargetAccountNumber}}
      </td>
    </tr>
    <tr>
      <th
          style="
                 padding-left: 24px;
                 padding-right: 24px;
                 color: #383d49;
                 white-space: nowrap;
                 "
          >
        Шилжүүлэх дүн:
      </th>
      <td
          style="
                 padding-left: 24px;
                 padding-right: 24px;
                 word-wrap: break-word;
                 "
          >
     $ {{FormattedAmount}}
      </td>
    </tr>
    <tr>
      <th
          style="
                 padding-left: 24px;
                 padding-right: 24px;
                 color: #383d49;
                 white-space: nowrap;
                 "
          >
        Шилжүүлэх огноо:
      </th>
      <td
          style="
                 padding-left: 24px;
                 padding-right: 24px;
                 word-wrap: break-word;
                 "
          >
      {{Date}}
      </td>
    </tr>
  </table>

</div>
', '');
INSERT INTO cms."_TopicContent" ("Id", "TopicId", "CreatedOn", "UpdatedOn", "Language", "Title", "Author", "Content", "Subtitle") VALUES (11472, 11286, '2024-01-04 19:46:10.685718 +00:00', '2024-04-11 20:34:07.859874 +00:00', 'th-th', 'Client Daily Confirmation', '', e'
  <meta http-equiv="content-type" content="text/html;charset=utf-8" />
  <table
    align="center"
    style="
      width: 900px;
      border-collapse: collapse;
      font-family: \'微软雅黑\';
      padding: 5px 0px;
      -moz-border-radius: 5px;
      -webkit-border-radius: 5px;
      border-radius: 5px;
      border: 0px #ddcebd solid;
      background: url(https://s3.amazonaws.com/bcr-img-new/email/docs_bg.png)
        repeat-y;
      background-position: right 0 top 0;
    "
  >
    <tr>
      <td>
        <table style="width: 100%">
          <tr>
            <td
              style="
                text-align: left;
                line-height: 40px;
                font-size: 32px;
                font-family: \'Times New Roman\', Times, serif;
              "
            >
              <img src="https://s3.amazonaws.com/bcr-img-new/bcr_logo.png" />
            </td>
          </tr>
        </table>
      </td>
    </tr>
    <tr>
      <td>
        <table style="width: 100%; font-size: 12px">
          <tr>
            <td style="width: 25%">
              บัญชี: <strong>@Model.AccountNumber</strong>
            </td>
            <td style="width: 25%">ชื่อ: <strong>@Model.NativeName</strong></td>
            <td style="width: 25%"></td>
            <td style="width: 25%; text-align: right">
              @Model.ReportDate.ToString("yyyy-MM-dd HH:mm:ss")
            </td>
          </tr>
        </table>
      </td>
    </tr>
    <tr>
      <td>
        <table
          style="
            width: 100%;
            font-size: 10px;
            text-align: right;
            line-height: 20px;
            border-collapse: collapse;
            border: 0px solid #cccccc;
          "
        >
          <tr>
            <td colspan="13" align="left"><strong>การเทรดที่ปิด:</strong></td>
          </tr>
          <tr
            style="
              background: #f5f5f5;
              text-align: center;
              border: 1px solid #cccccc;
            "
          >
            <td style="border: 1px solid #cccccc" width="7%">ตั๋ว</td>
            <td style="border: 1px solid #cccccc" width="12%">เวลาเปิด</td>
            <td style="border: 1px solid #cccccc" width="7%">ประเภท</td>
            <td style="border: 1px solid #cccccc" width="6%">ขนาด</td>
            <td style="border: 1px solid #cccccc" width="7%">สิ่งที่เทรด</td>
            <td style="border: 1px solid #cccccc" width="7%">ราคา</td>
            <td style="border: 1px solid #cccccc" width="7%">S/L</td>
            <td style="border: 1px solid #cccccc" width="7%">T/P</td>
            <td style="border: 1px solid #cccccc" width="12%">เวลาปิด</td>
            <td style="border: 1px solid #cccccc" width="7%">ราคา</td>
            <td style="border: 1px solid #cccccc" width="7%">ค่าคอมมิชั่น</td>
            <td style="border: 1px solid #cccccc" width="7%">ค่าสวอป</td>
            <td style="border: 1px solid #cccccc" width="7%">
              กำไร/ขาดทุนการเทรด
            </td>
          </tr>
          @{ var color = new[] { "#FFFFFF;", "#EEEEEE;" }; var counter = 0; }
                @if (Model.ClosedTrades != null && Model.ClosedTrades.Count > 0) {
                foreach (var trade in Model.ClosedTrades) {
                                                    <tr style="background: @color[counter++ % 2]">
                                                        <td style="border: 1px solid #cccccc">@trade.Ticket</td>
                                                        <td style="border: 1px solid #cccccc">@trade.OpenAt.ToString("yyyy-MM-dd HH:mm:ss")</td>
                                                        <td style="border: 1px solid #cccccc">@if(trade.Cmd == 1) { <text>Sell</text> } else if (trade.Cmd == 0){ <text>Buy</text>
                                        }
                                        else if (trade.Cmd == 6){ <text>Balance</text> }
                                    </td>
                                
                                                        @if (trade.Cmd < 2) {
                                                        <td style="border: 1px solid #cccccc">@trade.Volume</td>
                                                        <td style="border: 1px solid #cccccc">@trade.Symbol</td>
                                                        <td style="border: 1px solid #cccccc">
                                                            @string.Format("{0:F" + trade.Digits + "}", trade.OpenPrice ?? 0)
                                                        </td>
                    <td style="border: 1px solid #cccccc">
                                                                                @string.Format("{0:F" + trade.Digits + "}", trade.Sl)
                                                                            </td>
                                                                            <td style="border: 1px solid #cccccc">
                                                                                @string.Format("{0:F" + trade.Digits + "}", trade.Tp)
                                                                            </td>
                                                                            <td style="border: 1px solid #cccccc">@trade.CloseAt</td>
                                                                            <td style="border: 1px solid #cccccc">
                                                                                @string.Format("{0:F" + trade.Digits + "}", trade.ClosePrice ?? 0)
                                                                            </td>
                                                                            <td style="border: 1px solid #cccccc">
                                                                                @string.Format("{0:N2}", trade.Commission)
                                                                            </td>
                                                                            <td style="border: 1px solid #cccccc">
                                                                                @string.Format("{0:N2}", trade.Swaps)
                                                                            </td>
                                                                            } else if (trade.Cmd > 5) {
                                                                            <td style="border: 1px solid #cccccc" colspan="9" align="right">
                                                                                @trade.Comment
                                                                            </td>
                                                                            }
                                                    
                                                                            <td style="border: 1px solid #cccccc">
                                                                                @string.Format("{0:N2}", trade.Profit)
                                                                            </td>
                                                                        </tr>
                                                                        } } else {
                                                                        <tr style="background: #ffffff; text-align: center">
                                                                            <td style="border: 1px solid #cccccc" colspan="13">ไม่มีรายการ</td>
                                                                        </tr>
                                                                        }
                                                    
                                                                        <tr style="background: #eeeeee">
                                                                            <td style="border: 1px solid #cccccc" colspan="10"></td>
                                                                            <td style="border: 1px solid #cccccc">
                                                                                @string.Format("{0:N2}", Model.ClosedTradeSummary.Commission)
                                                                            </td>
                                                                            <td style="border: 1px solid #cccccc">
                                                                                @string.Format("{0:N2}", Model.ClosedTradeSummary.Swaps)
                                                                            </td>
                                                                            <td style="border: 1px solid #cccccc">
                                                                                @string.Format("{0:N2}", Model.ClosedTradeSummary.Profit)
                                                                            </td>
                                                                        </tr>
                                                                    </table>
                                                                </td>
                                                            </tr>
                                                            <tr>
                                                                <td>
                                                                    <table style="width: 100%; font-size: 12px">
                                                                        <tr>
                                                                            <td>
                                                                                <strong
                                                                                    >ฝาก/ถอน: @string.Format("{0:N2}",
                                                                                    Model.ClosedTradeSummary.Deposit)</strong
                                                                                >
                                                                            </td>
                                                                            <td>
                                                                                <strong
                                                                                    >สิทธิ์ในการกู้ยืม: @string.Format("{0:N2}",
                                                                                    Model.ClosedTradeSummary.Credit)</strong
                                                                                >
                                                                            </td>
                                                                            <td style="text-align: right">
                                                                                <strong
                                                                                    >กำไร/ขาดทุนการเทรดที่ปิด:
                                                                                    &nbsp;&nbsp;&nbsp;&nbsp;@string.Format("{0:N2}",
                                                                                    Model.ClosedTradeSummary.TotalProfit)</strong
                                                                                >
                                                                            </td>
                                                                        </tr>
                                                                    </table>
                                                                </td>
                                                            </tr>
                                                            <tr>
                                                                <td>&nbsp;</td>
                                                            </tr>
                                                            <tr>
                                                                <td>
                                                                    <table
                                                                        style="
                                                                            width: 100%;
                                                                            font-size: 10px;
                                                                            text-align: right;
                                                                            line-height: 20px;
                                                                            border-collapse: collapse;
                                                                            border: 0px solid #cccccc;
                                                                        "
                                                                    >
                                                                        <tr>
                                                                            <td colspan="12" align="left">
                                                                                <strong>การเทรดที่เปิดอยู่:</strong>
                                                                            </td>
                                                                        </tr>
                                                                        <tr
                                                                            style="
                                                                                background: #f5f5f5;
                                                                                text-align: center;
                                                                                border: 1px solid #cccccc;
                                                                                font-size: 11px;
                                                                            "
                                                                        >
                                                                            <td style="border: 1px solid #cccccc" width="7%">ตั๋ว</td>
                                                                            <td style="border: 1px solid #cccccc" width="12%">เวลาเปิด</td>
                                                                            <td style="border: 1px solid #cccccc" width="7%">ประเภท</td>
                                                                            <td style="border: 1px solid #cccccc" width="6%">ขนาด</td>
                                                                            <td style="border: 1px solid #cccccc" width="7%">สิ่งที่เทรด</td>
                                                                            <td style="border: 1px solid #cccccc" width="7%">ราคา</td>
                                                                            <td style="border: 1px solid #cccccc" width="7%">S/L</td>
                                                                            <td style="border: 1px solid #cccccc" width="7%">T/P</td>
                                                                            <td style="border: 1px solid #cccccc" width="12%">เวลาปิด</td>
                                                                            <td style="border: 1px solid #cccccc" width="7%">ราคา</td>
                                                                            <td style="border: 1px solid #cccccc" width="7%">ค่าคอมมิชั่น</td>
                                                                            <td style="border: 1px solid #cccccc" width="7%">ค่าสวอป</td>
                                                                            <td style="border: 1px solid #cccccc" width="7%">
                                                                                กำไร/ขาดทุนการเทรด
                                                                            </td>
                                                                        </tr>
                                                                        @{ counter = 0; } @if (Model.OpenTrades != null &&
                                                                        Model.OpenTrades.Count > 0) { foreach (var trade in Model.OpenTrades)
                                                                        { if (trade.Cmd < 2) {
                                                                        <tr style="background: @color[counter++ % 2]">
                                                                            <td style="border: 1px solid #cccccc">@trade.Ticket</td>
                                                                            <td style="border: 1px solid #cccccc">@trade.OpenAt.ToString("yyyy-MM-dd HH:mm:ss")</td>
                                                                            <td style="border: 1px solid #cccccc">
                                                                                @if(trade.Cmd == 1) { <text>Sell</text> } else {
                                                                                <text>Buy</text> }
                                                                            </td>
                                                                            <td style="border: 1px solid #cccccc">
                                                                                @string.Format("{0:f2}", trade.Volume)
                                                                            </td>
                                                                            <td style="border: 1px solid #cccccc">@trade.Symbol</td>
                                                                            <td style="border: 1px solid #cccccc">
                                                                                @string.Format("{0:F" + trade.Digits + "}", trade.OpenPrice ?? 0)
                                                                            </td>
                                                                            <td style="border: 1px solid #cccccc">
                                                                                @string.Format("{0:F" + trade.Digits + "}", trade.Sl)
                                                                            </td>
                                                                            <td style="border: 1px solid #cccccc">
                                                                                @string.Format("{0:F" + trade.Digits + "}", trade.Tp)
                                                                            </td>
                                                                            <td style="border: 1px solid #cccccc"></td>
                                                                            <td style="border: 1px solid #cccccc">
                                                                                @string.Format("{0:F" + trade.Digits + "}", trade.CurrentPrice ??
                                                                                0)
                                                                            </td>
                                                                            <td style="border: 1px solid #cccccc">
                                                                                @string.Format("{0:N2}", trade.Commission)
                                                                            </td>
                                                                            <td style="border: 1px solid #cccccc">
                                                                                @string.Format("{0:N2}", trade.Swaps)
                                                                            </td>
                                                                            <td style="border: 1px solid #cccccc">
                                                                                @string.Format("{0:N2}", trade.Profit)
                                                                            </td>
                                                                        </tr>
                                                                        } } } else {
                                                                        <tr style="background: #ffffff; text-align: center">
                                                                            <td style="border: 1px solid #cccccc" colspan="13">ไม่มีรายการ</td>
                                                                        </tr>
                                                                        }
                                                    
                                                                        <tr style="background: #eeeeee">
                                                                            <td style="border: 1px solid #cccccc" colspan="10"></td>
                                                                            <td style="border: 1px solid #cccccc">
                                                                                @string.Format("{0:N2}", Model.OpenTradeSummary.Commission)
                                                                            </td>
                                                                            <td style="border: 1px solid #cccccc">
                                                                                @string.Format("{0:N2}", Model.OpenTradeSummary.Swaps)
                                                                            </td>
                                                                            <td style="border: 1px solid #cccccc">
                                                                                @string.Format("{0:N2}", Model.OpenTradeSummary.Profit)
                                                                            </td>
                                                                        </tr>
                                                                    </table>
                                                                </td>
                                                            </tr>
                                                            <tr>
                                                                <td>
                                                                    <table style="width: 100%; font-size: 12px; border-collapse: collapse">
                                                                        <tr>
                                                                            <td><strong>&nbsp;</strong></td>
                                                                            <td align="right">
                                                                                <strong
                                                                                    >กำไร/ขาดทุนที่กำลังเดินทาง:&nbsp;&nbsp;&nbsp;&nbsp;
                                                                                    @string.Format("{0:N2}",  Model.OpenTradeSummary.TotalProfit)</strong
                                                                                >
                                                                            </td>
                                                                        </tr>
                                                                    </table>
                                                                </td>
                                                            </tr>
                                                            <tr>
                                                                <td>&nbsp;</td>
                                                            </tr>
                                                            <tr>
                                                                <td>
                                                                    <table
                                                                        style="
                                                                            width: 100%;
                                                                            font-size: 10px;
                                                                            text-align: right;
                                                                            line-height: 20px;
                                                                            border-collapse: collapse;
                                                                        "
                                                                    >
                                                                        <tr>
                                                                            <td colspan="12" align="left">
                                                                                <strong>คำสั่งที่กำลังดำเนินการ:</strong>
                                                                            </td>
                                                                        </tr>
                                                                        <tr style="background: #eeeeee; text-align: center">
                                                                            <td style="border: 1px solid #cccccc" width="7%">ตั๋ว</td>
                                                                            <td style="border: 1px solid #cccccc" width="12%">เวลาเปิด</td>
                                                                            <td style="border: 1px solid #cccccc" width="7%">ประเภท</td>
                                                                            <td style="border: 1px solid #cccccc" width="6%">ขนาด</td>
                                                                            <td style="border: 1px solid #cccccc" width="7%">สิ่งที่เทรด</td>
                                                                            <td style="border: 1px solid #cccccc" width="7%">ราคา</td>
                                                                            <td style="border: 1px solid #cccccc" width="7%">S/L</td>
                                                                            <td style="border: 1px solid #cccccc" width="7%">S/P</td>
                                                                            <td style="border: 1px solid #cccccc" width="12%">ราคาตลาด</td>
                                                                            <td style="border: 1px solid #cccccc" width="28%"></td>
                                                                        </tr>
                                                                        @{ counter = 0; } @if (Model.PendingTrades != null &&
                                                                        Model.PendingTrades.Count > 0) { foreach (var trade in
                                                                        Model.PendingTrades) {
                                                                        <tr style="background: @color[counter++ % 2]">
                                                                            <td style="border: 1px solid #cccccc">@trade.Ticket</td>
                                                                            <td style="border: 1px solid #cccccc">@trade.OpenAt.ToString("yyyy-MM-dd HH:mm:ss")</td>
                                                                            <td style="border: 1px solid #cccccc">@if(trade.Cmd == 1) { <text>Sell</text> } else { <text>Buy</text> }</td>
                                                                            <td style="border: 1px solid #cccccc">
                                                                                @string.Format("{0:f2}", trade.Volume)
                                                                            </td>
                                                                            <td style="border: 1px solid #cccccc">@trade.Symbol</td>
                                                                            <td style="border: 1px solid #cccccc">
                                                                                @string.Format("{0:F" + trade.Digits + "}", trade.OpenPrice ?? 0)
                                                                            </td>
                                                                            <td style="border: 1px solid #cccccc">
                                                                                @string.Format("{0:F" + trade.Digits + "}", trade.Sl)
                                                                            </td>
                                                                            <td style="border: 1px solid #cccccc">
                                                                                @string.Format("{0:F" + trade.Digits + "}", trade.Tp)
                                                                            </td>
                                                                            <td style="border: 1px solid #cccccc">
                                                                                @string.Format("{0:F" + trade.Digits + "}", trade.ClosePrice ?? 0)
                                                                            </td>
                                                                            <td style="border: 1px solid #cccccc">@trade.Comment</td>
                                                                        </tr>
                                                                        } } else {
                                                                        <tr style="background: #eeeeee; text-align: center">
                                                                            <td style="border: 1px solid #cccccc" colspan="10">
                                                                                ไม่มีคำสั่งที่กำลังดำเนินการ
                                                                            </td>
                                                                        </tr>
                                                                        }
                                                                    </table>
                                                                </td>
                                                            </tr>
                                                            <tr>
                                                                <td>
                                                                    <table
                                                                        style="
                                                                            width: 100%;
                                                                            font-size: 12px;
                                                                            text-align: right;
                                                                            line-height: 20px;
                                                                        "
                                                                    >
                                                                        <tr>
                                                                            <td colspan="4" align="left"><strong>สรุปบัญชี:</strong></td>
                                                                        </tr>
                                                                        <tr>
                                                                            <td style="width: 25%; text-align: left">ยอดเงินก่อนหน้า:</td>
                                                                            <td style="width: 25%">
                                                                                <strong
                                                                                    >@string.Format("{0:N2}", Model.Summary.PrevBalance)</strong
                                                                                >
                                                                            </td>
                                                                            <td style="width: 25%">กำไร/ขาดทุนที่กำลังเดินทาง:</td>
                                                                            <td style="width: 25%; text-align: right">
                                                                                <strong
                                                                                    >@string.Format("{0:N2}",  Model.OpenTradeSummary.TotalProfit)</strong
                                                                                >
                                                                            </td>
                                                                        </tr>
                                                                        <tr>
                                                                            <td style="width: 25%; text-align: left">
                                                                                กำไร/ขาดทุนการเทรดที่ปิด:
                                                                            </td>
                                                                            <td style="width: 25%">
                                                                                <strong
                                                                                    >@string.Format("{0:N2}",
                                                                                    Model.ClosedTradeSummary.Profit)</strong
                                                                                >
                                                                            </td>
                                                                            <td style="width: 25%">สิทธิ์ในการกู้ยืม:</td>
                                                                            <td style="width: 25%; text-align: right">
                                                                                <strong
                                                                                    >@string.Format("{0:N2}", Model.Summary.Credit)</strong
                                                                                >
                                                                            </td>
                                                                        </tr>
                                                                        <tr>
                                                                            <td style="width: 25%; text-align: left">ฝาก/ถอน:</td>
                                                                            <td style="width: 25%">
                                                                                <strong
                                                                                    >@string.Format("{0:N2}", Model.Summary.Deposit /
                                                                                    100)</strong
                                                                                >
                                                                            </td>
                                                                            <td style="width: 25%">สินทรัพย์สุทธิ:</td>
                                                                            <td style="width: 25%; text-align: right">
                                                                                <strong
                                                                                    >@string.Format("{0:N2}", (Model.Summary.Balance +
                                                                                    Model.Summary.Credit +
                                                                                    Model.OpenTradeSummary.TotalProfit))</strong
                                                                                >
                                                                            </td>
                                                                        </tr>
                                                                        <tr>
                                                                            <td style="width: 25%; text-align: left">ยอดเงินคงเหลือ:</td>
                                                                            <td style="width: 25%">
                                                                                <strong
                                                                                    >@string.Format("{0:N2}", Model.Summary.Balance)</strong
                                                                                >
                                                                            </td>
                                                                            <td style="width: 25%">ค่าเทรดมาร์จิน:</td>
                                                                            <td style="width: 25%; text-align: right">
                                                                                <strong
                                                                                    >@string.Format("{0:N2}", Model.Summary.Margin)</strong
                                                                                >
                                                                            </td>
                                                                        </tr>
                                                                        <tr>
                                                                            <td style="width: 25%">&nbsp;</td>
                                                                            <td style="width: 25%">&nbsp;</td>
                                                                            <td style="width: 25%">มาร์จินที่ใช้ได้:</td>
                                                                            <td style="width: 25%; text-align: right">
                                                                                <strong
                                                                                    >@string.Format("{0:N2}", (Model.Summary.Balance +
                                                                                    Model.Summary.Credit + Model.OpenTradeSummary.TotalProfit -
                                                                                    Model.Summary.Margin))</strong
                                                                                >
                                                                            </td>
                                                                        </tr>
                                                                    </table>
                                                                </td>
                                                            </tr>
                                                            <tr>
                                                                <td>&nbsp;</td>
                                                            </tr>
                                                            <tr>
                                                                <td align="left" style="font-size: 12px">ขอแสดงความนับถือ</td>
                                                            </tr>
                                                            <tr>
                                                                <td align="left" style="font-size: 12px">BCR</td>
                                                            </tr>
                                                            <tr>
                                                                <td align="center" style="font-size: 10px">
                                                                    กรุณารายงานให้เราภายใน 48 ชั่วโมงหากข้อมูลในรายงานไม่ถูกต้อง มิฉะนั้น
                                                                    รายงานนี้จะถือว่าถูกยืนยันจากคุณ
                                                                </td>
                                                            </tr>
                                                            <tr>
                                                                <td align="center" style="font-size: 10px">
                                                                    ค่ากำไร/ขาดทุนที่เดินทางและค่าสินทรัพย์สุทธิทั้งหมดถูกคำนวณขึ้นบนราคาของสินค้าตอนที่รายงานถูกสร้างขึ้นและอาจแตกต่างจากราคาปิดจริงของสินค้า
                                                                </td>
                                                            </tr>
                                                        </table>
                                                    ', '');
INSERT INTO cms."_TopicContent" ("Id", "TopicId", "CreatedOn", "UpdatedOn", "Language", "Title", "Author", "Content", "Subtitle") VALUES (11400, 11273, '2023-09-14 17:39:33.526201 +00:00', '2023-09-14 17:39:33.526201 +00:00', 'vi-vn', 'Tiền gửi của khách hàng đã hoàn tất', '', e'<div style="font-size: 12px; line-height: 20px">
  <p style="font-size: 16px; font-weight: 700; line-height: 24px">
    Kính gửi Đối tác BCR,
  </p>
  <p>
   Giao dịch gửi tiền của khách hàng của bạn đã hoàn thành, vui lòng xem chi tiết giao dịch gửi tiền dưới đây:
  </p>
  <table class="letter-table" style="
                      table-layout: fixed;
                      line-height: 24px;
                      margin-left: auto;
                      margin-right: auto;
                      text-align: left;
                      padding: 8px;
                      float: none;
                    " bgcolor="#f2f2f2" align="left">
    <tr>
      <th style="
                          padding-left: 24px;
                          padding-right: 24px;
                          color: #383d49;
                          white-space: nowrap;
                        ">
        Số tiền gửi:
      </th>
      <td style="
                          padding-left: 24px;
                          padding-right: 24px;
                          word-wrap: break-word;
                        ">
        {{AccountNumber}}
      </td>
    </tr>
    <tr>
      <th style="
                          padding-left: 24px;
                          padding-right: 24px;
                          color: #383d49;
                          white-space: nowrap;
                        ">
        Nhóm khách hàng:
      </th>
      <td style="
                          padding-left: 24px;
                          padding-right: 24px;
                          word-wrap: break-word;
                        ">
        {{Group}}
      </td>
    </tr>
    <tr>
      <th style="
                          padding-left: 24px;
                          padding-right: 24px;
                          color: #383d49;
                          white-space: nowrap;
                        ">
        Tên tài khoản:
      </th>
      <td style="
                          padding-left: 24px;
                          padding-right: 24px;
                          word-wrap: break-word;
                        ">
        {{NativeName}}
      </td>
    </tr>
    <tr>
      <th style="
                          padding-left: 24px;
                          padding-right: 24px;
                          color: #383d49;
                          white-space: nowrap;
                        ">
        Số tiền gửi:
      </th>
      <td style="
                          padding-left: 24px;
                          padding-right: 24px;
                          word-wrap: break-word;
                        ">
        $ {{FormattedAmount}}
      </td>
    </tr>
    <tr>
      <th style="
                          padding-left: 24px;
                          padding-right: 24px;
                          color: #383d49;
                          white-space: nowrap;
                        ">
        Ngày gửi tiền:
      </th>
      <td style="
                          padding-left: 24px;
                          padding-right: 24px;
                          word-wrap: break-word;
                        ">
        {{Date}}
      </td>
    </tr>
  </table>
</div>
', ' ');
INSERT INTO cms."_TopicContent" ("Id", "TopicId", "CreatedOn", "UpdatedOn", "Language", "Title", "Author", "Content", "Subtitle") VALUES (11402, 11273, '2023-09-14 17:41:42.403734 +00:00', '2023-09-14 17:41:42.403734 +00:00', 'jp-jp', '顧客の入金が完了しました', '', e'<div style="font-size: 12px; line-height: 20px">
