                        ">
        クライアントグループ：
      </th>
      <td style="
                          padding-left: 24px;
                          padding-right: 24px;
                          word-wrap: break-word;
                        ">
        {{Group}}
      </td>
    </tr>
    <tr>
      <th style="
                          padding-left: 24px;
                          padding-right: 24px;
                          color: #383d49;
                          white-space: nowrap;
                        ">
        アカウント名：
      </th>
      <td style="
                          padding-left: 24px;
                          padding-right: 24px;
                          word-wrap: break-word;
                        ">
        {{NativeName}}
      </td>
    </tr>
    <tr>
      <th style="
                          padding-left: 24px;
                          padding-right: 24px;
                          color: #383d49;
                          white-space: nowrap;
                        ">
        預金額：
      </th>
      <td style="
