        {{Date}}
      </td>
    </tr>
  </table>
</div>
', ' ');
INSERT INTO cms."_TopicContent" ("Id", "TopicId", "CreatedOn", "UpdatedOn", "Language", "Title", "Author", "Content", "Subtitle") VALUES (11403, 11273, '2023-09-14 17:43:39.906278 +00:00', '2023-09-14 17:43:39.906278 +00:00', 'id-id', 'Setoran Pelanggan Selesai', '', e'<div style="font-size: 12px; line-height: 20px">
