      </td>
    </tr>
    <tr>
      <th style="
                          padding-left: 24px;
                          padding-right: 24px;
                          color: #383d49;
                          white-space: nowrap;
                        ">
        Nama Akun:
      </th>
      <td style="
                          padding-left: 24px;
