                          word-wrap: break-word;
                        ">
        {{NativeName}}
      </td>
    </tr>
    <tr>
      <th style="
                          padding-left: 24px;
                          padding-right: 24px;
                          color: #383d49;
                          white-space: nowrap;
                        ">
        Jumlah Deposit:
      </th>
      <td style="
                          padding-left: 24px;
