', ' ');
INSERT INTO cms."_TopicContent" ("Id", "TopicId", "CreatedOn", "UpdatedOn", "Language", "Title", "Author", "Content", "Subtitle") VALUES (11409, 11273, '2023-09-14 17:42:38.005672 +00:00', '2023-09-14 17:42:38.005672 +00:00', 'mn-mn', 'Хэрэглэгчийн хадгаламж дууссан', '', e'<div style="font-size: 12px; line-height: 20px">
  <p style="font-size: 16px; font-weight: 700; line-height: 24px">
    BCR-ийн хамт олон,
  </p>
  <p>
   Таны харилцагчийн дүнгээ төлбөрлөв. Төлбөрийн дэлгэрэнгүйг доорхи мэдээллийн хэсэгт үзэх болно:
  </p>
  <table class="letter-table" style="
                      table-layout: fixed;
                      line-height: 24px;
                      margin-left: auto;
                      margin-right: auto;
                      text-align: left;
                      padding: 8px;
                      float: none;
                    " bgcolor="#f2f2f2" align="left">
    <tr>
      <th style="
                          padding-left: 24px;
                          padding-right: 24px;
                          color: #383d49;
                          white-space: nowrap;
                        ">
        Төлбөрийн дугаар:
      </th>
      <td style="
                          padding-left: 24px;
                          padding-right: 24px;
                          word-wrap: break-word;
                        ">
        {{AccountNumber}}
      </td>
    </tr>
    <tr>
      <th style="
                          padding-left: 24px;
                          padding-right: 24px;
                          color: #383d49;
                          white-space: nowrap;
                        ">
        Харилцагчийн бүлэг:
      </th>
      <td style="
                          padding-left: 24px;
                          padding-right: 24px;
                          word-wrap: break-word;
                        ">
        {{Group}}
      </td>
    </tr>
    <tr>
      <th style="
                          padding-left: 24px;
                          padding-right: 24px;
                          color: #383d49;
                          white-space: nowrap;
                        ">
        Дансны нэр:
      </th>
      <td style="
                          padding-left: 24px;
                          padding-right: 24px;
                          word-wrap: break-word;
                        ">
        {{NativeName}}
      </td>
    </tr>
    <tr>
      <th style="
                          padding-left: 24px;
                          padding-right: 24px;
                          color: #383d49;
                          white-space: nowrap;
                        ">
        Төлбөрийн дүн:
      </th>
      <td style="
                          padding-left: 24px;
                          padding-right: 24px;
                          word-wrap: break-word;
                        ">
        $ {{FormattedAmount}}
      </td>
    </tr>
    <tr>
      <th style="
                          padding-left: 24px;
                          padding-right: 24px;
                          color: #383d49;
                          white-space: nowrap;
                        ">
        Төлбөрийн огноо:
      </th>
      <td style="
                          padding-left: 24px;
                          padding-right: 24px;
                          word-wrap: break-word;
                        ">
        {{Date}}
      </td>
    </tr>
  </table>
</div>
', ' ');
INSERT INTO cms."_TopicContent" ("Id", "TopicId", "CreatedOn", "UpdatedOn", "Language", "Title", "Author", "Content", "Subtitle") VALUES (11411, 11274, '2023-09-13 20:43:41.497405 +00:00', '2023-09-13 20:43:41.497405 +00:00', 'th-th', 'การถอนเงินของลูกค้าล้มเหลว', '', e'<div style="font-size: 12px; line-height: 20px">
  <p
     style="font-size: 16px; font-weight: 700; line-height: 24px"
     >
    ท่านคู่ค้า BCR ที่น่ารัก,
  </p>
  <p>
    คำขอถอนเงินของลูกค้าของท่านไม่สามารถดำเนินการได้และถูกปฏิเสธ รายละเอียดเพิ่มเติมดังต่อไปนี้:
  </p>
  <table
         class="letter-table"
         style="
                table-layout: fixed;
                line-height: 24px;
                margin-left: auto;
                margin-right: auto;
                text-align: left;
                padding: 8px;
                float: none;
                "
         bgcolor="#f2f2f2"
         align="left"
         >
    <tr>
      <th
          style="
                 padding-left: 24px;
                 padding-right: 24px;
                 color: #383d49;
                 white-space: nowrap;
                 "
          >
        เลขบัญชี:
      </th>
      <td
          style="
                 padding-left: 24px;
                 padding-right: 24px;
                 word-wrap: break-word;
                 "
          >
       {{AccountNumber}}
      </td>
    </tr>
    <tr>
      <th
          style="
                 padding-left: 24px;
                 padding-right: 24px;
                 color: #383d49;
                 white-space: nowrap;
                 "
          >
        ชื่อบัญชี:
      </th>
      <td
          style="
                 padding-left: 24px;
                 padding-right: 24px;
                 word-wrap: break-word;
                 "
          >
        {{NativeName}}
      </td>
    </tr>
    <tr>
      <th
          style="
                 padding-left: 24px;
                 padding-right: 24px;
                 color: #383d49;
                 white-space: nowrap;
                 "
          >
        สกุลเงินของบัญชี:
      </th>
      <td
          style="
                 padding-left: 24px;
                 padding-right: 24px;
                 word-wrap: break-word;
                 "
          >
        {{Currency}}
      </td>
    </tr>
    <tr>
      <th
          style="
                 padding-left: 24px;
                 padding-right: 24px;
                 color: #383d49;
                 white-space: nowrap;
                 "
          >
        ยอดถอน:
      </th>
      <td
          style="
                 padding-left: 24px;
                 padding-right: 24px;
                 word-wrap: break-word;
                 "
          >
       $ {{FormattedAmount}}
      </td>
    </tr>
    <tr>
      <th
          style="
                 padding-left: 24px;
                 padding-right: 24px;
                 color: #383d49;
                 white-space: nowrap;
                 "
          >
        วันที่ขอถอน:
      </th>
      <td
          style="
                 padding-left: 24px;
                 padding-right: 24px;
                 word-wrap: break-word;
                 "
          >
       {{Date}}
      </td>
    </tr>
  </table>
  <p>
    เหตุผลที่คำขอถอนไม่สามารถดำเนินการได้คือ:
  </p>
  <p style="color: #cc1f1a; font-weight: 600">{{Reason}}</p>
  <br />
  <p>
    หากท่านยังไม่แน่ใจว่าทำไมคำขอถอนถูกปฏิเสธ กรุณาติดต่อผู้จัดการบัญชีของท่านหรือติดต่อเราผ่านการสนทนาสด.
  </p>
</div>
', '');
INSERT INTO cms."_TopicContent" ("Id", "TopicId", "CreatedOn", "UpdatedOn", "Language", "Title", "Author", "Content", "Subtitle") VALUES (11412, 11274, '2023-09-13 20:45:22.395404 +00:00', '2023-09-13 20:45:22.395404 +00:00', 'vi-vn', ' Rút tiền của khách hàng không thành công', '', e'<div style="font-size: 12px; line-height: 20px">
  <p
     style="font-size: 16px; font-weight: 700; line-height: 24px"
     >
    Thân gửi Đối tác BCR thân thương,
  </p>
  <p>
    Yêu cầu rút tiền của khách hàng của quý vị không thể được xử lý và đã bị từ chối. Chi tiết thêm được cung cấp dưới đây:
  </p>
  <table
         class="letter-table"
         style="
                table-layout: fixed;
                line-height: 24px;
                margin-left: auto;
                margin-right: auto;
                text-align: left;
                padding: 8px;
                float: none;
                "
         bgcolor="#f2f2f2"
         align="left"
         >
    <tr>
      <th
          style="
                 padding-left: 24px;
                 padding-right: 24px;
                 color: #383d49;
                 white-space: nowrap;
                 "
          >
        Số tài khoản:
      </th>
      <td
          style="
                 padding-left: 24px;
                 padding-right: 24px;
                 word-wrap: break-word;
                 "
          >
        {{AccountNumber}}
      </td>
    </tr>
    <tr>
      <th
          style="
                 padding-left: 24px;
                 padding-right: 24px;
                 color: #383d49;
                 white-space: nowrap;
                 "
          >
        Tên tài khoản:
      </th>
      <td
          style="
                 padding-left: 24px;
                 padding-right: 24px;
                 word-wrap: break-word;
                 "
          >
       {{NativeName}}
      </td>
    </tr>
    <tr>
      <th
          style="
                 padding-left: 24px;
                 padding-right: 24px;
                 color: #383d49;
                 white-space: nowrap;
                 "
          >
        Đơn vị tiền tệ tài khoản:
      </th>
      <td
          style="
                 padding-left: 24px;
                 padding-right: 24px;
                 word-wrap: break-word;
                 "
          >
        {{Currency}}
      </td>
    </tr>
    <tr>
      <th
          style="
                 padding-left: 24px;
                 padding-right: 24px;
                 color: #383d49;
                 white-space: nowrap;
                 "
          >
        Số tiền rút:
      </th>
      <td
          style="
                 padding-left: 24px;
                 padding-right: 24px;
                 word-wrap: break-word;
                 "
          >
        $ {{FormattedAmount}}
      </td>
    </tr>
    <tr>
      <th
          style="
                 padding-left: 24px;
                 padding-right: 24px;
                 color: #383d49;
                 white-space: nowrap;
                 "
          >
        Ngày yêu cầu:
      </th>
      <td
          style="
                 padding-left: 24px;
                 padding-right: 24px;
                 word-wrap: break-word;
                 "
          >
       {{Date}}
      </td>
    </tr>
  </table>
  <p>
    Lý do tại sao yêu cầu rút tiền không thể được xử lý là:
  </p>
  <p style="color: #cc1f1a; font-weight: 600">{{Reason}}</p>
  <br />
  <p>
    Nếu quý vị vẫn còn băn khoăn về việc tại sao yêu cầu rút tiền của quý vị bị từ chối, vui lòng tham khảo với người quản lý tài khoản của quý vị hoặc liên hệ với chúng tôi qua cuộc trò chuyện trực tiếp.
  </p>
</div>
', '');
INSERT INTO cms."_TopicContent" ("Id", "TopicId", "CreatedOn", "UpdatedOn", "Language", "Title", "Author", "Content", "Subtitle") VALUES (11413, 11274, '2023-09-13 20:48:10.187272 +00:00', '2023-09-13 20:48:10.187272 +00:00', 'jp-jp', '顧客の出金に失敗しました', '', e'<div style="font-size: 12px; line-height: 20px">
  <p
     style="font-size: 16px; font-weight: 700; line-height: 24px"
     >
    尊敬するBCRパートナー様へ
  </p>
  <p>
    お客様の引き出しリクエストは処理されず、拒否されました。詳細は以下に記載しております：
  </p>
  <table
         class="letter-table"
         style="
                table-layout: fixed;
                line-height: 24px;
                margin-left: auto;
                margin-right: auto;
                text-align: left;
                padding: 8px;
                float: none;
                "
         bgcolor="#f2f2f2"
         align="left"
         >
    <tr>
      <th
          style="
                 padding-left: 24px;
                 padding-right: 24px;
                 color: #383d49;
                 white-space: nowrap;
                 "
          >
        アカウント番号：
      </th>
      <td
          style="
                 padding-left: 24px;
                 padding-right: 24px;
                 word-wrap: break-word;
                 "
          >
       {{AccountNumber}}
      </td>
    </tr>
    <tr>
      <th
          style="
                 padding-left: 24px;
                 padding-right: 24px;
                 color: #383d49;
                 white-space: nowrap;
                 "
          >
        アカウント名：
      </th>
      <td
          style="
                 padding-left: 24px;
                 padding-right: 24px;
                 word-wrap: break-word;
                 "
          >
        {{NativeName}}
      </td>
    </tr>
    <tr>
      <th
          style="
                 padding-left: 24px;
                 padding-right: 24px;
                 color: #383d49;
                 white-space: nowrap;
                 "
          >
        アカウント通貨：
      </th>
      <td
          style="
                 padding-left: 24px;
                 padding-right: 24px;
                 word-wrap: break-word;
                 "
          >
        {{Currency}}
      </td>
    </tr>
    <tr>
      <th
          style="
                 padding-left: 24px;
                 padding-right: 24px;
                 color: #383d49;
                 white-space: nowrap;
                 "
          >
        引き出し金額：
      </th>
      <td
          style="
                 padding-left: 24px;
                 padding-right: 24px;
                 word-wrap: break-word;
                 "
          >
        $ {{FormattedAmount}}
      </td>
    </tr>
    <tr>
      <th
          style="
                 padding-left: 24px;
                 padding-right: 24px;
                 color: #383d49;
                 white-space: nowrap;
                 "
          >
        リクエスト日時：
      </th>
      <td
          style="
                 padding-left: 24px;
                 padding-right: 24px;
                 word-wrap: break-word;
                 "
          >
        {{Date}}
      </td>
    </tr>
  </table>
  <p>
    引き出しの処理ができなかった理由は以下の通りです：
  </p>
  <p style="color: #cc1f1a; font-weight: 600">{{Reason}}</p>
  <br />
  <p>
    引き出しリクエストが拒否された理由が不明な場合は、アカウントマネージャーにご相談いただくか、ライブチャットでお問い合わせください。
  </p>
</div>
', '');
INSERT INTO cms."_TopicContent" ("Id", "TopicId", "CreatedOn", "UpdatedOn", "Language", "Title", "Author", "Content", "Subtitle") VALUES (11414, 11274, '2023-09-13 20:50:09.827956 +00:00', '2023-09-13 20:50:09.827956 +00:00', 'mn-mn', 'Үйлчлүүлэгчийн мөнгөө татаж чадсангүй', '', e'<div style="font-size: 12px; line-height: 20px">
