      <td
          style="
                 padding-left: 24px;
                 padding-right: 24px;
                 word-wrap: break-word;
                 "
          >
        {{Currency}}
      </td>
    </tr>
    <tr>
      <th
          style="
                 padding-left: 24px;
                 padding-right: 24px;
                 color: #383d49;
                 white-space: nowrap;
                 "
          >
        Даны хууль:
      </th>
