                                        <strong>@string.Format("{0:N2}", Model.Summary.PrevBalance)</strong>
                                    </td>
                                    <td style="width: 25%">P/L Mengambang:</td>
                                    <td style="width: 25%; text-align: right">
                                        <strong
                                            >@string.Format("{0:N2}",
                            Model.OpenTradeSummary.TotalProfit)</strong
                                        >
                                    </td>
                                </tr>
                                <tr>
                                    <td style="width: 25%; text-align: left">P/L Transaksi Ditutup:</td>
                                    <td style="width: 25%">
                                        <strong
                                            >@string.Format("{0:N2}", Model.ClosedTradeSummary.Profit)</strong
                                        >
                                    </td>
                                    <td style="width: 25%">Kredit:</td>
                                    <td style="width: 25%; text-align: right">
                                        <strong>@string.Format("{0:N2}", Model.Summary.Credit)</strong>
                                    </td>
                                </tr>
                                <tr>
                                    <td style="width: 25%; text-align: left">Deposit/Tarik:</td>
                                    <td style="width: 25%">
                                        <strong
                                            >@string.Format("{0:N2}", Model.Summary.Deposit)</strong
                                        >
                                    </td>
                                    <td style="width: 25%">Ekuitas:</td>
                                    <td style="width: 25%; text-align: right">
                                        <strong
                                            >@string.Format("{0:N2}", (Model.Summary.Balance +
                                            Model.Summary.Credit +
                                            Model.OpenTradeSummary.TotalProfit))</strong
                                        >
                                    </td>
                                </tr>
                                <tr>
                                    <td style="width: 25%; text-align: left">Saldo:</td>
                                    <td style="width: 25%">
                                        <strong>@string.Format("{0:N2}", Model.Summary.Balance)</strong>
                                    </td>
                                    <td style="width: 25%">Persyaratan Margin:</td>
                                    <td style="width: 25%; text-align: right">
                                        <strong>@string.Format("{0:N2}", Model.Summary.Margin)</strong>
                                    </td>
                                </tr>
                                <tr>
                                    <td style="width: 25%">&nbsp;</td>
                                    <td style="width: 25%">&nbsp;</td>
                                    <td style="width: 25%">Margin Tersedia:</td>
                                    <td style="width: 25%; text-align: right">
                                        <strong
                                            >@string.Format("{0:N2}", (Model.Summary.Balance +
                                            Model.Summary.Credit + Model.OpenTradeSummary.TotalProfit -
                                            Model.Summary.Margin))</strong
                                        >
                                    </td>
                                </tr>
                            </table>
                            </td>
                            </tr>
                            <tr>
                            <td>&nbsp;</td>
                            </tr>
                            <tr>
                            <td align="left" style="font-size: 12px">Salam Hormat</td>
                            </tr>
                            <tr>
                            <td align="left" style="font-size: 12px">BCR</td>
                            </tr>
                            <tr>
                            <td align="center" style="font-size: 10px">
                                Harap laporkan kepada kami dalam waktu 48 jam jika laporan ini tidak benar. Jika tidak, laporan ini akan dianggap telah dikonfirmasi oleh Anda.
                            </td>
                            </tr>
                            <tr>
                            <td align="center" style="font-size: 10px">
                                Semua angka keuntungan/kerugian mengambang dan ekuitas dihitung berdasarkan harga instrumen pada saat laporan dibuat dan mungkin berbeda dengan harga penutupan aktual instrumen.
                            </td>
                            </tr>
                            </table>
                            ', '');
INSERT INTO cms."_TopicContent" ("Id", "TopicId", "CreatedOn", "UpdatedOn", "Language", "Title", "Author", "Content", "Subtitle") VALUES (10038, 10001, '2023-08-16 00:11:25.471886 +00:00', '2023-08-16 00:15:25.682271 +00:00', 'zh-tw', '賬戶申請確認電子郵件', '', e'<div style="font-size: 12px; line-height: 20px">
  <p style="font-size: 16px; font-weight: 700; line-height: 24px">
    尊敬的客戶 {{UserName}} 您好，
  </p>
  <p style="font-size: 14px;">
    感謝您開始在 BCR 開設帳戶的線上申請。這意味著您正在加入數以千計的客戶之列，他們將 BCR 視為值得信賴的提供商，用於交易外匯、貴金屬、股票和商品 CFD。為了確認您的電子郵件地址並啟用您的新 BCR 帳戶，請點擊下面的連結。
  </p>
  <p>
    <a href="{{CallbackUrl}}" target="_blank" style="color: #383d49;text-decoration: none;font-weight: 700;">點擊此處</a>
    或將地址複製到瀏覽器地址欄中：
  </p>
  <div style="margin-left: auto;margin-right: auto;text-align: center;font-style: italic;">
    {{CallbackUrl}}
  </div>
  <p>為保護您的帳戶安全，此連結將在 <strong>10 分鐘</strong> 內有效。此郵件是系統自動生成的，請勿直接回復。</p>
</div>', '請使用鏈接來確認電子郵件地址');
INSERT INTO cms."_TopicContent" ("Id", "TopicId", "CreatedOn", "UpdatedOn", "Language", "Title", "Author", "Content", "Subtitle") VALUES (10039, 10002, '2023-08-16 00:57:43.062879 +00:00', '2023-08-16 00:58:38.723190 +00:00', 'zh-tw', '重設密碼', '', e'尊敬的客戶 {{UserName}}，

<p>
  <a href="{{CallbackUrl}}" target="_blank" style="color: #383d49;text-decoration: none;font-weight: 700;">點擊這裡</a>
  或將下方網址複製到您瀏覽器的地址欄中：
</p>
<div style="margin-left: auto;margin-right: auto;text-align: center;font-style: italic;">
  {{CallbackUrl}}
</div>
<p>出於您的帳戶安全考慮，此連結將保持有效 <strong>10 分鐘</strong>。此郵件是系統自動生成的，請不要直接回覆。</p>', '重置密碼鏈接');
INSERT INTO cms."_TopicContent" ("Id", "TopicId", "CreatedOn", "UpdatedOn", "Language", "Title", "Author", "Content", "Subtitle") VALUES (10041, 11239, '2023-08-16 01:01:10.005957 +00:00', '2023-08-16 01:01:10.005957 +00:00', 'zh-tw', 'MyBCR 重要消息', '', e'<div style="font-size: 14px; line-height: 20px">
<p>由於 MyBCR 進行升級，客戶門戶將在 <b>2023 年 7 月 21 日（星期五）</b> 市場收盤後暫停使用，並將在 <b>2023 年 7 月 24 日（星期一）</b> 市場開盤前恢復正常使用。
</p>
<p>如果您在周末有任何需要客戶服務的事情，請聯繫 BCR 支援部門：<a href="mailto:info@au.thebcr.com">info@au.thebcr.com</a>。</p>
<p>如果您對以上升級有任何進一步的問題，請通過在線聊天或發送電子郵件至 info@au.thebcr.com 與我們聯繫。我們期待為您提供金融服務行業中的最佳服務。</p>
<br />
祝好，
<br />
<b>BCR</b>
<br />
</div>', 'MyBCR升級');
INSERT INTO cms."_TopicContent" ("Id", "TopicId", "CreatedOn", "UpdatedOn", "Language", "Title", "Author", "Content", "Subtitle") VALUES (11478, 11286, '2024-01-04 20:08:07.370587 +00:00', '2024-04-11 20:33:34.557600 +00:00', 'ms-my', 'Client Daily Confirmation', '', e'<meta http-equiv="content-type" content="text/html;charset=utf-8" />
<table
    align="center"
    style="
        width: 900px;
        border-collapse: collapse;
        font-family: \'微软雅黑\';
        padding: 5px 0px;
        -moz-border-radius: 5px;
        -webkit-border-radius: 5px;
        border-radius: 5px;
        border: 0px #ddcebd solid;
        background: url(https://s3.amazonaws.com/bcr-img-new/email/docs_bg.png)
            repeat-y;
        background-position: right 0 top 0;
    "
>
    <tr>
        <td>
            <table style="width: 100%">
                <tr>
                    <td
                        style="
                            text-align: left;
                            line-height: 40px;
                            font-size: 32px;
                            font-family: \'Times New Roman\', Times, serif;
                        "
                    >
                        <img src="https://s3.amazonaws.com/bcr-img-new/bcr_logo.png" />
                    </td>
                </tr>
            </table>
        </td>
    </tr>
    <tr>
        <td>
            <table style="width: 100%; font-size: 12px">
                <tr>
                    <td style="width: 25%">
                                                                Akaun: <strong>@Model.AccountNumber</strong>
                                                            </td>
                                                            <td style="width: 25%">Nama: <strong>@Model.NativeName</strong></td>
                                                            <td style="width: 25%"></td>
                                                            <td style="width: 25%; text-align: right">
                                                                @Model.ReportDate.ToString("yyyy-MM-dd HH:mm:ss")
                                                            </td>
                                                        </tr>
                                                    </table>
                                                </td>
                                            </tr>
                                            <tr>
                                                <td>
                                                    <table
                                                        style="
                                                            width: 100%;
                                                            font-size: 10px;
                                                            text-align: right;
                                                            line-height: 20px;
                                                            border-collapse: collapse;
                                                            border: 0px solid #cccccc;
                                                        "
                                                    >
                                                        <tr>
                                                            <td colspan="13" align="left"><strong>Transaksi Ditutup:</strong></td>
                                                        </tr>
                                                        <tr
                                                            style="
                                                                background: #f5f5f5;
                                                                text-align: center;
                                                                border: 1px solid #cccccc;
                                                            "
                                                        >
                                                            <td style="border: 1px solid #cccccc" width="7%">Tiket</td>
                                                            <td style="border: 1px solid #cccccc" width="12%">Waktu Buka</td>
                                                            <td style="border: 1px solid #cccccc" width="7%">Jenis</td>
                                                            <td style="border: 1px solid #cccccc" width="6%">Saiz</td>
                                                            <td style="border: 1px solid #cccccc" width="7%">Item</td>
                                                            <td style="border: 1px solid #cccccc" width="7%">Harga</td>
                                                            <td style="border: 1px solid #cccccc" width="7%">S/L</td>
                                                            <td style="border: 1px solid #cccccc" width="7%">T/P</td>
                                                            <td style="border: 1px solid #cccccc" width="12%">Waktu Tutup</td>
                                                            <td style="border: 1px solid #cccccc" width="7%">Harga</td>
                                                            <td style="border: 1px solid #cccccc" width="7%">Komisen</td>
                                                            <td style="border: 1px solid #cccccc" width="7%">Swap</td>
                                                            <td style="border: 1px solid #cccccc" width="7%">
                                                                Keuntungan Transaksi
                                                            </td>
                                                        </tr>
                                                        @{ var color = new[] { "#FFFFFF;", "#EEEEEE;" }; var counter = 0; } @if
                                                        (Model.ClosedTrades != null && Model.ClosedTrades.Count > 0) { foreach
                                                        (var trade in Model.ClosedTrades) {
                                                        <tr style="background: @color[counter++ % 2]">
                                                            <td style="border: 1px solid #cccccc">@trade.Ticket</td>
                                                            <td style="border: 1px solid #cccccc">
                                                                @trade.OpenAt.ToString("yyyy-MM-dd HH:mm:ss")
                                                            </td>
                                                            <td style="border: 1px solid #cccccc">@if(trade.Cmd == 1) { <text>Sell</text> } else if (trade.Cmd == 0){ <text>Buy</text>
                                                            }
                                                            else if (trade.Cmd == 6){ <text>Balance</text> }
                                                            </td>
                                        
                                                            @if (trade.Cmd < 2) {
                                                            <td style="border: 1px solid #cccccc">@trade.Volume</td>
                                                            <td style="border: 1px solid #cccccc">@trade.Symbol</td>
                                                            <td style="border: 1px solid #cccccc">
                                                                @string.Format("{0:F" + trade.Digits + "}", trade.OpenPrice ?? 0)
                                                            </td>
                                                            <td style="border: 1px solid #cccccc">
                                                                @string.Format("{0:F" + trade.Digits + "}", trade.Sl)
                                                            </td>
                                                            <td style="border: 1px solid #cccccc">
                                                                @string.Format("{0:F" + trade.Digits + "}", trade.Tp)
                                                            </td>
                                                            <td style="border: 1px solid #cccccc">@trade.CloseAt</td>
                                                            <td style="border: 1px solid #cccccc">
                                                                @string.Format("{0:F" + trade.Digits + "}", trade.ClosePrice ?? 0)
                                                            </td>
                                                            <td style="border: 1px solid #cccccc">
                                                                @string.Format("{0:N2}", trade.Commission)
                                                            </td>
                                                            <td style="border: 1px solid #cccccc">
                                                                @string.Format("{0:N2}", trade.Swaps)
                                                            </td>
                                                            } else if (trade.Cmd > 5) {
                                                            <td style="border: 1px solid #cccccc" colspan="9" align="right">
                                                                @trade.Comment
                                                            </td>
                                                            }
                                        
                                                            <td style="border: 1px solid #cccccc">
                                                                @string.Format("{0:N2}", trade.Profit)
                                                            </td>
                                                        </tr>
                                                        } } else {
                                                        <tr style="background: #ffffff; text-align: center">
                                                            <td style="border: 1px solid #cccccc" colspan="13">
                                                                Tiada Transaksi
                                                            </td>
                                                        </tr>
                                                        }
                                        
                                                        <tr style="background: #eeeeee">
                                                            <td style="border: 1px solid #cccccc" colspan="10"></td>
                                                            <td style="border: 1px solid #cccccc">
                                                                @string.Format("{0:N2}", Model.ClosedTradeSummary.Commission)
                                                            </td>
                                                            <td style="border: 1px solid #cccccc">
                                                                @string.Format("{0:N2}", Model.ClosedTradeSummary.Swaps)
                                                            </td>
                                                            <td style="border: 1px solid #cccccc">
                                                                @string.Format("{0:N2}", Model.ClosedTradeSummary.Profit)
                                                            </td>
                                                        </tr>
                                                    </table>
                                                </td>
                                            </tr>
                                            <tr>
                                                <td>
                                                    <table style="width: 100%; font-size: 12px">
                                                        <tr>
                                                            <td>
                                                                <strong
                                                                    >Deposit/Pengeluaran: @string.Format("{0:N2}",
                                                                    Model.ClosedTradeSummary.Deposit)</strong
                                                                >
                                                            </td>
                                                            <td>
                                                                <strong
                                                                    >Fasiliti Kredit: @string.Format("{0:N2}",
                                                                    Model.ClosedTradeSummary.Credit)</strong
                                                                >
                                                            </td>
                                                            <td style="text-align: right">
                                                                <strong
                                                                    >Keuntungan Transaksi Ditutup:
                                                                    &nbsp;&nbsp;&nbsp;&nbsp;@string.Format("{0:N2}",
                                                                    Model.ClosedTradeSummary.TotalProfit)</strong
                                                                >
                                                            </td>
                                                        </tr>
                                                    </table>
                                                </td>
                                            </tr>
                                            <tr>
                                                <td>&nbsp;</td>
                                            </tr>
                                            <tr>
                                                <td>
                                                    <table
                                                        style="
                                                            width: 100%;
                                                            font-size: 10px;
                                                            text-align: right;
                                                            line-height: 20px;
                                                            border-collapse: collapse;
                                                            border: 0px solid #cccccc;
                                                        "
                                                    >
                                                        <tr>
                                                            <td colspan="12" align="left"><strong>Transaksi Terbuka:</strong></td>
                                                        </tr>
                                                        <tr
                                                            style="
                                                                background: #f5f5f5;
                                                                text-align: center;
                                                                border: 1px solid #cccccc;
                                                                font-size: 11px;
                                                            "
                                                        >
                                                            <td style="border: 1px solid #cccccc" width="7%">Tiket</td>
                                                            <td style="border: 1px solid #cccccc" width="12%">Waktu Buka</td>
                                                            <td style="border: 1px solid #cccccc" width="7%">Jenis</td>
                                                            <td style="border: 1px solid #cccccc" width="6%">Saiz</td>
                                                            <td style="border: 1px solid #cccccc" width="7%">Item</td>
                                                            <td style="border: 1px solid #cccccc" width="7%">Harga</td>
                                                            <td style="border: 1px solid #cccccc" width="7%">S/L</td>
                                                            <td style="border: 1px solid #cccccc" width="7%">T/P</td>
                                                            <td style="border: 1px solid #cccccc" width="12%">Waktu Tutup</td>
                                                            <td style="border: 1px solid #cccccc" width="7%">Harga</td>
                                                            <td style="border: 1px solid #cccccc" width="7%">Komisen</td>
                                                            <td style="border: 1px solid #cccccc" width="7%">Swap</td>
                                                            <td style="border: 1px solid #cccccc" width="7%">
                                                                Keuntungan Transaksi
                                                            </td>
                                                        </tr>
                                                        @{ counter = 0; } @if (Model.OpenTrades != null &&
                                                        Model.OpenTrades.Count > 0) { foreach (var trade in Model.OpenTrades) {
                                                        if (trade.Cmd < 2) {
                                                        <tr style="background: @color[counter++ % 2]">
                                                            <td style="border: 1px solid #cccccc">@trade.Ticket</td>
                                                            <td style="border: 1px solid #cccccc">
                                                                @trade.OpenAt.ToString("yyyy-MM-dd HH:mm:ss")
                                                            </td>
                                                            <td style="border: 1px solid #cccccc">
                                                                @if(trade.Cmd == 1) { <text>Sell</text> } else { <text>Buy</text> }
                                                            </td>
                                                            <td style="border: 1px solid #cccccc">
                                                                @string.Format("{0:f2}", trade.Volume)
                                                            </td>
                                                            <td style="border: 1px solid #cccccc">@trade.Symbol</td>
                                                            <td style="border: 1px solid #cccccc">
                                                                @string.Format("{0:F" + trade.Digits + "}", trade.OpenPrice ?? 0)
                                                            </td>
                                                            <td style="border: 1px solid #cccccc">
                                                                @string.Format("{0:F" + trade.Digits + "}", trade.Sl)
                                                            </td>
                                                            <td style="border: 1px solid #cccccc">
                                                                @string.Format("{0:F" + trade.Digits + "}", trade.Tp)
                                                            </td>
                                                            <td style="border: 1px solid #cccccc"></td>
                                                            <td style="border: 1px solid #cccccc">
                                                                @string.Format("{0:F" + trade.Digits + "}", trade.CurrentPrice ?? 0)
                                                            </td>
                                                            <td style="border: 1px solid #cccccc">
                                                                @string.Format("{0:N2}", trade.Commission)
                                                            </td>
                                                            <td style="border: 1px solid #cccccc">
                                                                @string.Format("{0:N2}", trade.Swaps)
                                                            </td>
                                                            <td style="border: 1px solid #cccccc">
                                                                @string.Format("{0:N2}", trade.Profit)
                                                            </td>
                                                        </tr>
                                                        } } } else {
                                                        <tr style="background: #ffffff; text-align: center">
                                                            <td style="border: 1px solid #cccccc" colspan="13">
                                                                Tiada Transaksi
                                                            </td>
                                                        </tr>
                                                        }
                                        
                                                        <tr style="background: #eeeeee">
                                                            <td style="border: 1px solid #cccccc" colspan="10"></td>
                                                            <td style="border: 1px solid #cccccc">
                                                                @string.Format("{0:N2}", Model.OpenTradeSummary.Commission)
                                                            </td>
                                                            <td style="border: 1px solid #cccccc">
                                                                @string.Format("{0:N2}", Model.OpenTradeSummary.Swaps)
                                                            </td>
                                                            <td style="border: 1px solid #cccccc">
                                                                @string.Format("{0:N2}", Model.OpenTradeSummary.Profit)
                                                            </td>
                                                        </tr>
                                                    </table>
                                                </td>
                                            </tr>
                                            <tr>
                                                <td>
                                                    <table style="width: 100%; font-size: 12px; border-collapse: collapse">
                                                        <tr>
                                                            <td><strong>&nbsp;</strong></td>
                                                            <td align="right">
                                                                <strong
                                                                    >Floating P/L:&nbsp;&nbsp;&nbsp;&nbsp; @string.Format("{0:N2}",  Model.OpenTradeSummary.TotalProfit)</strong
                                                                >
                                                            </td>
                                                        </tr>
                                                    </table>
                                                </td>
                                            </tr>
                                            <tr>
                                                <td>&nbsp;</td>
                                            </tr>
                                            <tr>
                                                <td>
                                                    <table
                                                        style="
                                                            width: 100%;
                                                            font-size: 10px;
                                                            text-align: right;
                                                            line-height: 20px;
                                                            border-collapse: collapse;
                                                        "
                                                    >
                                                        <tr>
                                                            <td colspan="12" align="left">
                                                                <strong>Perintah Sedang Dilaksanakan:</strong>
                                                            </td>
                                                        </tr>
                                                        <tr style="background: #eeeeee; text-align: center">
                                                            <td style="border: 1px solid #cccccc" width="7%">Tiket</td>
                                                            <td style="border: 1px solid #cccccc" width="12%">Waktu Buka</td>
                                                            <td style="border: 1px solid #cccccc" width="7%">Jenis</td>
                                                            <td style="border: 1px solid #cccccc" width="6%">Saiz</td>
                                                            <td style="border: 1px solid #cccccc" width="7%">Item</td>
                                                            <td style="border: 1px solid #cccccc" width="7%">Harga</td>
                                                            <td style="border: 1px solid #cccccc" width="7%">S/L</td>
                                                            <td style="border: 1px solid #cccccc" width="7%">S/P</td>
                                                            <td style="border: 1px solid #cccccc" width="12%">Harga Pasaran</td>
                                                            <td style="border: 1px solid #cccccc" width="28%"></td>
                                                        </tr>
                                                        @{ counter = 0; } @if (Model.PendingTrades != null &&
                                                        Model.PendingTrades.Count > 0) { foreach (var trade in
                                                        Model.PendingTrades) {
                                                        <tr style="background: @color[counter++ % 2]">
                                                            <td style="border: 1px solid #cccccc">@trade.Ticket</td>
                                                            <td style="border: 1px solid #cccccc">
                                                                @trade.OpenAt.ToString("yyyy-MM-dd HH:mm:ss")
                                                            </td>
                                                            <td style="border: 1px solid #cccccc">
                                                                @if(trade.Cmd == 1) { <text>Sell</text> } else { <text>Buy</text> }
                                                            </td>
                                                            <td style="border: 1px solid #cccccc">
                                                                @string.Format("{0:f2}", trade.Volume)
                                                            </td>
                                                            <td style="border: 1px solid #cccccc">@trade.Symbol</td>
                                                            <td style="border: 1px solid #cccccc">
                                                                @string.Format("{0:F" + trade.Digits + "}", trade.OpenPrice ?? 0)
                                                            </td>
                                                            <td style="border: 1px solid #cccccc">
                                                                @string.Format("{0:F" + trade.Digits + "}", trade.Sl)
                                                            </td>
                                                            <td style="border: 1px solid #cccccc">
                                                                @string.Format("{0:F" + trade.Digits + "}", trade.Tp)
                                                            </td>
                                                            <td style="border: 1px solid #cccccc">
                                                                @string.Format("{0:F" + trade.Digits + "}", trade.ClosePrice ?? 0)
                                                            </td>
                                                            <td style="border: 1px solid #cccccc">@trade.Comment</td>
                                                        </tr>
                                                        } } else {
                                                        <tr style="background: #eeeeee; text-align: center">
                                                            <td style="border: 1px solid #cccccc" colspan="10">
                                                                Tiada Perintah Sedang Dilaksanakan
