INSERT INTO cms."_TopicContent" ("Id", "TopicId", "CreatedOn", "UpdatedOn", "Language", "Title", "Author", "Content", "Subtitle") VALUES (10048, 11248, '2023-08-16 01:07:18.799613 +00:00', '2023-08-16 01:07:18.799613 +00:00', 'zh-tw', ' 存款鏈接', '', e'
<div style="font-size: 12px; line-height: 20px">
  <p style="font-size: 16px; font-weight: 700; line-height: 24px">
    尊敬的客戶您好，
  </p>
  <div style="padding: 12px; background-color: #f2f2f2">
    <p style="line-height: 24px; font-size: 14px; color: #383d49; font-weight: 600;">
      存款信息
    </p>
    <p>
      以下是 BCR 存款連結 - 點擊連結並按照提供的指示進行付款。
    </p>
    <p>
      參考號碼：{{$deposit->ref_id}}<br />存款金額：US${{ number_format($deposit->amount, 2)}}
    </p>
    <div style="font-style: italic">
      <a href="{{$payLink}}" target="_blank" style="color: #383d49; text-decoration: none; font-weight: 700;">{{$payLink}}</a>
    </div>
    <p>
      這個連結在 20 分鐘內有效。請盡快使用。
    </p>
    <p style="color: #cc1f1a; font-weight: 600">
      備註：<br />
      連結將以港幣 (HKD) 顯示付款幣種。請求的存款金額將從美元 (USD) 轉換為港幣 (HKD)，並顯示港幣交易金額。選擇使用您的銀行卡支付後，銀聯將自動將港幣轉換為人民幣 (RMB)，實際支付的人民幣金額將顯示在付款頁面上。
    </p>
  </div>
</div>', '鏈接');
