INSERT INTO cms."_TopicContent" ("Id", "TopicId", "CreatedOn", "UpdatedOn", "Language", "Title", "Author", "Content", "Subtitle") VALUES (10053, 11253, '2023-08-16 01:16:49.465781 +00:00', '2023-08-23 22:25:06.953900 +00:00', 'zh-tw', 'MT4密碼已更改', '', e'<div style="font-size: 12px; line-height: 20px">
    <p style="font-size: 16px; font-weight: 700; line-height: 24px">
        尊敬的客戶，
    </p>
    <p>
        我們在 {{$wl->date_on_letter->format(\'F jS, Y\')}} 修改了您的帳戶密碼，以下是您的BCR ProTrader MT4帳戶詳細信息：
    </p>
    <table class="letter-table"
        style="table-layout:fixed;line-height:24px;margin-left:auto;margin-right:auto;text-align:left;padding:8px;float:none"
        bgcolor="#f2f2f2" align="left">
        <tr>
            <th
                style="padding-left:24px;padding-right:24px;color:#383d49;white-space:nowrap">
                MyBCR 帳戶：</th>
            <td style="padding-left:24px;padding-right:24px;word-wrap:break-word">
                {{$wl->user->email}}</td>
        </tr>
        <tr>
            <th
                style="padding-left:24px;padding-right:24px;color:#383d49;white-space:nowrap">
                MT4 帳戶：</th>
            <td style="padding-left:24px;padding-right:24px;word-wrap:break-word">
                {{$wl->user->login}}</td>
        </tr>
        <tr>
            <th
                style="padding-left:24px;padding-right:24px;color:#383d49;white-space:nowrap">
                交易帳戶密碼：</th>
            <td style="padding-left:24px;padding-right:24px;word-wrap:break-word">
                {{$wl->decryptPassword}}</td>
        </tr>
        <tr>
            <th
                style="padding-left:24px;padding-right:24px;color:#383d49;white-space:nowrap">
                MT4 伺服器：</th>
            <td style="padding-left:24px;padding-right:24px;word-wrap:break-word">BCR-REAL
            </td>
        </tr>
    </table>
    <p style="font-weight:700;line-height:24px;font-size:14px">按照以下步驟立即開始交易：</p>
    <ol>
        <li>在我們的 <a target="_blank"
                href="https://au.thebcr.com/en"
                style="color:#383d49;text-decoration:none;font-weight:700">官方網站</a> 的促銷頁面上了解更多關於不同的BCR優惠。</li>
        <li>登入 <a target="_blank" href="https://client-portal.thebcr.com/"
                style="color:#383d49;text-decoration:none;font-weight:700">MyBCR</a>
            ，然後轉到“下載”選項卡下載BCR交易平台。</li>
        <li>登入 <a target="_blank" href="https://client-portal.thebcr.com/"
                style="color:#383d49;text-decoration:none;font-weight:700">MYBCR</a>，轉到“我的存款”選項卡選擇存款方式。</li>
        <li>登入BCR Trader（MT4平台），或者如果您使用移動設備，在移動MetaTrader 4中選擇BCR-Real伺服器，並使用上面列出的帳戶號碼和交易密碼。</li>
    </ol>
    <p>
