INSERT INTO cms."_TopicContent" ("Id", "TopicId", "CreatedOn", "UpdatedOn", "Language", "Title", "Author", "Content", "Subtitle") VALUES (11361, 11267, '2023-08-16 22:02:02.283169 +00:00', '2023-08-18 20:33:37.982638 +00:00', 'zh-tw', 'BCR高端客戶批准電子郵件', '', e'<div style="font-size:12px;line-height:20px">
