INSERT INTO cms."_TopicContent" ("Id", "TopicId", "CreatedOn", "UpdatedOn", "Language", "Title", "Author", "Content", "Subtitle") VALUES (11363, 11269, '2023-08-16 22:05:23.076798 +00:00', '2023-08-18 20:38:46.616683 +00:00', 'zh-tw', ' 電子郵件：要求提供相關證明', '', e'<div style="font-size:12px;line-height:20px">
    <p style="font-size:16px;font-weight:700;line-height:24px">敬啟者：</p>
    <p>
        感謝您近期申請成為BCR高端客戶。我們需要額外的文件以完成我們的審查流程。
    </p>

    <p>
        請參閱以下詳細信息，以了解每個特定渠道所需的證明。請注意，收到此電子郵件的所有客戶必須簽署並日期
        <a  href="https://bcrpropublic.s3.ap-southeast-1.amazonaws.com/docs/ba/zh-hk/Wholesale/Sophisticated+Investor+Acknowledgement.pdf
">高級投資者確認</a> 
        表格，並將其返回給 BCR。
    </p>

    <p>
        與此同時，如果您對 BCR 高端帳戶的相關服務有任何進一步的疑問，請通過在線聊天與我們聯繫，或發送電子郵件至 <a href="mailto:wholesale@au.thebcr.com">wholesale@au.thebcr.com</a>。我們期待為您提供 CFD 行業中最佳的服務。
    </p>

    <p style="text-decoration:underline;font-weight:600;">渠道 1：交易歷史</p>
    <ul>
        <li>
            <p>您的 CFD 經紀商的交易結單</p>
            <p>我們需要您以前的交易歷史證明。您必須在過去的 12 個月內至少與一家公司進行過 75 次交易（涵蓋保證金外匯、指數、商品、貨幣、金屬和股票交易），或者在過去的 12 個月內至少與一家公司進行過 50 次重要交易（涵蓋保證金外匯、指數、商品、貨幣、金屬和股票交易）。
            </p>
        </li>
    </ul>
    <p style="text-decoration:underline;font-weight:600;">渠道 2：相關工作經驗</p>
    <p>
        如果您以前曾在金融領域工作過，或者目前正在從事一年以上需要了解槓桿交易知識的職位，則可以提供您的專業工作經驗證明。
    </p>
    <p>
        證明您專業工作經驗的文件類型包括：
    </p>
    <ul>
        <li>
            <p>當前雇主的信函，確認職位和入職日期或在職時間，並包含職位描述；或</p>
        </li>
        <li>
            <p>雇佣合同，證明職位和入職日期，並包含職位描述；或 </p>
        </li>
        <li>
            <p>以前雇主的推薦信，詳細說明以前的職位和職責；或</p>
        </li>
        <li>
            <p>LinkedIn 資料，證明職位和職責、入職日期或在職時間，支付單據原件或 PDF 副本，證明同一雇主。</p>
        </li>
    </ul>
    <p style="text-decoration:underline;font-weight:600;">渠道 3：相關正規學歷</p>
    <p>
        如果您擁有與理解保證金外匯、指數、商品、貨幣、金屬和股票有關的正規學歷，則可以提供相關證明。研究生學歷更受青睞（例如，商業學士學位或商業學士學位不足以證明經驗，但金融學或應用金融學的課程或專業可能是相關的）。
    </p>
    <p>
        證明您正規學歷的文件類型包括：
    </p>
    <ul>
        <li>
            <p>受認可大學的文憑，其中具體說明所學課程；或</p>
        </li>
        <li>
            <p>由許可合規培訓機構或持續專業發展（CPD）課程提供的證書；或 </p>
        </li>
        <li>
            <p>由經教育局批准的高等教育 FASEA 課程提供的證書。</p>
        </li>
    </ul>
    <p>
        您可以使用手機拍照，然後將文件發送到 <a href="mailto:wholesale@au.thebcr.com" >wholesale@au.thebcr.com</a>。在收到您的文件後，我們將在 7 個工作日內通知您申請結果。
    </p>
    <p>
        如果您對BCR高端客戶有任何進一步的疑問，請通過在線聊天與我們聯繫，或發送電子郵件
', 'BCR高端客戶');
