INSERT INTO cms."_TopicContent" ("Id", "TopicId", "CreatedOn", "UpdatedOn", "Language", "Title", "Author", "Content", "Subtitle") VALUES (11440, 11293, '2023-12-09 00:25:02.664617 +00:00', '2023-12-09 00:25:02.664617 +00:00', 'vi-vn', 'Đặt lại mật khẩu', '', e'
Kính gửi quý khách hàng {{UserName}},

