  </div>
  <p>Để đảm bảo an toàn cho tài khoản của quý khách, liên kết này sẽ có hiệu lực trong <strong>10 phút</strong>. Email này được tự động tạo ra bởi hệ thống, vui lòng không trả lời trực tiếp.</p>
</div>', 'đặt lại mật khẩu liên kết');
INSERT INTO cms."_TopicContent" ("Id", "TopicId", "CreatedOn", "UpdatedOn", "Language", "Title", "Author", "Content", "Subtitle") VALUES (11511, 11308, '2023-08-15 23:40:54.397779 +00:00', '2023-08-15 23:40:54.397779 +00:00', 'zh-cn', '重置MT4密码', '', e'<div style="font-size: 12px; line-height: 20px">
