INSERT INTO cms."_TopicContent" ("Id", "TopicId", "CreatedOn", "UpdatedOn", "Language", "Title", "Author", "Content", "Subtitle") VALUES (11436, 11292, '2023-12-09 00:23:19.327891 +00:00', '2023-12-09 00:25:36.973819 +00:00', 'en-us', 'Welcome Aboard', 'system', e'<div style="font-size:12px;line-height:20px">
                                <p style="font-size:16px;font-weight:700;line-height:24px">Dear {{NativeName}},</p>
                                <p>Thank you for opening a CFD trading account with BCR. Your account is open to trade
                                    as of {{OpenedDate}}, and your BCR ProTrader account
                                    details are listed below:</p>
                                <table class="letter-table"
                                    style="table-layout:fixed;line-height:24px;margin-left:auto;margin-right:auto;text-align:left;padding:8px;float:none"
                                    bgcolor="#f2f2f2" align="left">
                                    <tr>
                                        <th
                                            style="padding-left:24px;padding-right:24px;color:#383d49;white-space:nowrap">
                                            MyBCR Account:</th>
                                        <td style="padding-left:24px;padding-right:24px;word-wrap:break-word">
                                            {{UserName}}</td>
                                    </tr>
                                    <tr>
                                        <th
                                            style="padding-left:24px;padding-right:24px;color:#383d49;white-space:nowrap">
                                            Trading Account Number:</th>
                                        <td style="padding-left:24px;padding-right:24px;word-wrap:break-word">
                                            {{AccountNumber}}</td>
                                    </tr>
                                    <tr>
                                        <th
                                            style="padding-left:24px;padding-right:24px;color:#383d49;white-space:nowrap">
                                            Trading Account Password:</th>
                                        <td style="padding-left:24px;padding-right:24px;word-wrap:break-word">
                                            {{Password}}</td>
                                    </tr>
                                    <tr>
                                        <th
                                            style="padding-left:24px;padding-right:24px;color:#383d49;white-space:nowrap">
                                            Investor Password:</th>
                                        <td style="padding-left:24px;padding-right:24px;word-wrap:break-word">
                                            {{InvestorPassword}}</td>
                                    </tr>
                                    <tr>
                                        <th
                                            style="padding-left:24px;padding-right:24px;color:#383d49;white-space:nowrap">
                                            Phone Password:</th>
                                        <td style="padding-left:24px;padding-right:24px;word-wrap:break-word">
                                            {{PhonePassword}}</td>
                                    </tr>
                                    <tr>
                                        <th
                                            style="padding-left:24px;padding-right:24px;color:#383d49;white-space:nowrap">
                                            Server:</th>
                                        <td style="padding-left:24px;padding-right:24px;word-wrap:break-word">{{TradeServiceName}}
                                        </td>
                                    </tr>
                                </table>
                                <p style="font-weight:700;line-height:24px;font-size:14px">Follow these steps to start
                                    trading now:</p>
                                <ol>
                                    <li>Browse our Promotions tab on our <a target="_blank"
                                            href="https://cfds.thebcr.com"
                                            style="color:#383d49;text-decoration:none;font-weight:700">Offcial
                                            Website</a> to learn more about various BCR promotions.</li>
                                    <li>Log in to <a target="_blank" href="https://cfds-portal.thebcr.com/"
                                            style="color:#383d49;text-decoration:none;font-weight:700">MyBCR</a>
                                        and go to the Download tab to download the BCR trading platform.</li>
                                    <li>Log in to <a target="_blank" href="https://cfds-portal.thebcr.com/"
                                            style="color:#383d49;text-decoration:none;font-weight:700">MYBCR</a> and go
                                        to My deposit to choose the a deposit option.</li>
                                    <li>Log in to the BCR Trader (MT4 or MT5 Platform) or, if you are using a mobile device,
                                        select the {{TradeServiceName}} Server in Mobile MetaTrader and use the Account Number and
                                        Trading Password listed above.</li>
                                </ol>
                                <p>
                                    Please note that the Investor Password provides read-only, non-trading access to
                                    your account. If you would like to place trade orders over the telephone, you can
                                    reach us at one of the following number:</p>
                                <p style="font-weight:600;text-align:center">44 3300010590<br>
                                    <!-- New Zealand: 64-9-889-2558<br>
    UK: 44-161-818-9558<br>
    Southern China: 108 00152 1738 (For Land Line Service)<br>
    Northern China: 108 00852 1738 (For Land Line Service)<br> -->
                                </p>
                                <p>Please note that telephone trading service is only for use when there is a network
                                    connectivity problem or if the trading platform is not functioning properly.
                                </p>

                            </div>', 'Verification passed');
INSERT INTO cms."_TopicContent" ("Id", "TopicId", "CreatedOn", "UpdatedOn", "Language", "Title", "Author", "Content", "Subtitle") VALUES (11441, 11292, '2023-12-09 00:25:50.282749 +00:00', '2023-12-09 00:25:50.282749 +00:00', 'zh-cn', '欢迎加入', '', e'<div style="font-size:12px;line-height:20px">
    <p style="font-size:16px;font-weight:700;line-height:24px">尊敬的{{NativeName}}客户，</p>
    <p>感谢您开通了与BCR的差价合约（CFD）交易账户。您的账户从{{OpenedDate}}开始可以交易，
    您的BCR ProTrade 账户详情如下：</p>
    <table class="letter-table"
        style="table-layout:fixed;line-height:24px;margin-left:auto;margin-right:auto;text-align:left;padding:8px;float:none"
        bgcolor="#f2f2f2" align="left">
        <tr>
            <th
                style="padding-left:24px;padding-right:24px;color:#383d49;white-space:nowrap">
                MyBCR账户：</th>
            <td style="padding-left:24px;padding-right:24px;word-wrap:break-word">
                {{UserName}}</td>
        </tr>
        <tr>
            <th
                style="padding-left:24px;padding-right:24px;color:#383d49;white-space:nowrap">
                账户号码：</th>
            <td style="padding-left:24px;padding-right:24px;word-wrap:break-word">
                {{AccountNumber}}</td>
        </tr>
        <tr>
            <th
                style="padding-left:24px;padding-right:24px;color:#383d49;white-space:nowrap">
                交易账户密码：</th>
            <td style="padding-left:24px;padding-right:24px;word-wrap:break-word">
                {{Password}}</td>
        </tr>
        <tr>
            <th
                style="padding-left:24px;padding-right:24px;color:#383d49;white-space:nowrap">
                投资者密码：</th>
            <td style="padding-left:24px;padding-right:24px;word-wrap:break-word">
                {{InvestorPassword}}</td>
        </tr>
        <tr>
            <th
                style="padding-left:24px;padding-right:24px;color:#383d49;white-space:nowrap">
                手机密码：</th>
            <td style="padding-left:24px;padding-right:24px;word-wrap:break-word">
                {{PhonePassword}}</td>
        </tr>
        <tr>
            <th
                style="padding-left:24px;padding-right:24px;color:#383d49;white-space:nowrap">
                服务器：</th>
            <td style="padding-left:24px;padding-right:24px;word-wrap:break-word"> {{TradeServiceName}}
            </td>
        </tr>
    </table>
    <p style="font-weight:700;line-height:24px;font-size:14px">按照以下步骤开始交易：</p>
    <ol>
        <li>浏览我们的<a target="_blank"
                href="https://cfds.thebcr.com"
                style="color:#383d49;text-decoration:none;font-weight:700">官方网站</a>上的促销标签，了解更多BCR各种促销活动。</li>
        <li>登录<a target="_blank" href="https://cfds-portal.thebcr.com/"
                style="color:#383d49;text-decoration:none;font-weight:700">MyBCR</a>，并转到下载选项卡以下载BCR交易平台。</li>
        <li>登录<a target="_blank" href="https://cfds-portal.thebcr.com/"
                style="color:#383d49;text-decoration:none;font-weight:700">MYBCR</a>，然后转到我的存款，选择存款选项。</li>
        <li>登录BCR Trader（MT4或者MT5平台），或者如果您使用移动设备，请在移动MetaTrader中选择{{TradeServiceName}} 服务器，并使用上述账户号码和交易密码。</li>
    </ol>
    <p>
        请注意，投资者密码仅提供只读、非交易性的访问权限。如果您希望通过电话下达交易订单，您可以通过以下电话之一联系我们：</p>
    <p style="font-weight:600;text-align:center">44 3300010590 <br>
        <!-- 新西兰：64-9-889-2558<br>
        英国：44-161-818-9558<br>
        华南地区：108 00152 1738（固话服务）<br>
        华北地区：108 00852 1738（固话服务）<br> -->
    </p>
    <p>请注意，电话交易服务仅在网络连接问题或交易平台无法正常运行时使用。</p>
</div>
', '验证通过');
INSERT INTO cms."_TopicContent" ("Id", "TopicId", "CreatedOn", "UpdatedOn", "Language", "Title", "Author", "Content", "Subtitle") VALUES (11442, 11292, '2023-12-09 00:26:03.352381 +00:00', '2023-12-09 00:26:03.352381 +00:00', 'zh-tw', '歡迎加入', '', e'<div style="font-size:12px;line-height:20px">
    <p style="font-size:16px;font-weight:700;line-height:24px">親愛的 {{NativeName}} 客戶您好，</p>
    <p>感謝您開設 BCR 的差價合約（CFD）交易帳戶。您的帳戶已於 {{OpenedDate}} 開通，您的 BCR ProTrader 帳戶詳細資訊如下：</p>
    <table class="letter-table"
        style="table-layout:fixed;line-height:24px;margin-left:auto;margin-right:auto;text-align:left;padding:8px;float:none"
        bgcolor="#f2f2f2" align="left">
        <tr>
            <th
                style="padding-left:24px;padding-right:24px;color:#383d49;white-space:nowrap">
                MyBCR 帳戶：</th>
            <td style="padding-left:24px;padding-right:24px;word-wrap:break-word">
                {{UserName}}</td>
        </tr>
        <tr>
            <th
                style="padding-left:24px;padding-right:24px;color:#383d49;white-space:nowrap">
                 帳戶號碼：</th>
            <td style="padding-left:24px;padding-right:24px;word-wrap:break-word">
                {{AccountNumber}}</td>
        </tr>
        <tr>
            <th
                style="padding-left:24px;padding-right:24px;color:#383d49;white-space:nowrap">
                交易帳戶密碼：</th>
            <td style="padding-left:24px;padding-right:24px;word-wrap:break-word">
                {{Password}}</td>
        </tr>
        <tr>
            <th
                style="padding-left:24px;padding-right:24px;color:#383d49;white-space:nowrap">
                投資者密碼：</th>
            <td style="padding-left:24px;padding-right:24px;word-wrap:break-word">
                {{InvestorPassword}}</td>
        </tr>
        <tr>
            <th
                style="padding-left:24px;padding-right:24px;color:#383d49;white-space:nowrap">
                電話密碼：</th>
            <td style="padding-left:24px;padding-right:24px;word-wrap:break-word">
                {{PhonePassword}}</td>
        </tr>
        <tr>
            <th
                style="padding-left:24px;padding-right:24px;color:#383d49;white-space:nowrap">
                伺服器：</th>
            <td style="padding-left:24px;padding-right:24px;word-wrap:break-word">{{TradeServiceName}}
            </td>
        </tr>
    </table>
    <p style="font-weight:700;line-height:24px;font-size:14px">按照以下步驟開始進行交易：</p>
    <ol>
        <li>在我們的 <a target="_blank"
                href="https://cfds.thebcr.com"
                style="color:#383d49;text-decoration:none;font-weight:700">官方網站</a> 的優惠選項中，了解有關各種 BCR 優惠的更多信息。</li>
        <li>登錄至 <a target="_blank" href="https://cfds-portal.thebcr.com/"
                style="color:#383d49;text-decoration:none;font-weight:700">MyBCR</a>，然後轉到下載選項卡，以下載 BCR 交易平台。</li>
        <li>登錄至 <a target="_blank" href="https://cfds-portal.thebcr.com/"
                style="color:#383d49;text-decoration:none;font-weight:700">MYBCR</a>，然後轉到我的存款，選擇存款選項。</li>
        <li>登錄至 BCR 交易者（MT4或者MT5 平台）或如果您使用移動設備，請在移動 MetaTrader 中選擇 {{TradeServiceName}}伺服器，然後使用上面列出的帳戶號碼和交易密碼。</li>
    </ol>
    <p>請注意，投資者密碼僅提供唯讀的、非交易的帳戶訪問權限。如果您想透過電話下單，您可以通過以下號碼與我們聯繫：</p>
    <p style="font-weight:600;text-align:center">+44 3300010590<br>
    </p>
    <p>請注意，電話交易服務僅在網絡連接問題或交易平台未正常運行時使用。</p>
</div>', '驗證通過');
INSERT INTO cms."_TopicContent" ("Id", "TopicId", "CreatedOn", "UpdatedOn", "Language", "Title", "Author", "Content", "Subtitle") VALUES (11693, 11345, '2024-04-24 00:19:56.707938 +00:00', '2024-04-24 00:19:56.707938 +00:00', 'vi-vn', 'Đơn rút tiền đại lý', '', e'<div style="font-size: 12px; line-height: 20px">
