INSERT INTO cms."_TopicContent" ("Id", "TopicId", "CreatedOn", "UpdatedOn", "Language", "Title", "Author", "Content", "Subtitle") VALUES (11513, 11308, '2023-08-16 18:00:32.879327 +00:00', '2023-08-16 18:00:32.879327 +00:00', 'mn-mn', 'MT4 нууц үгийг дахин тохируулах', '', e'<div style="font-size: 12px; line-height: 20px">
