  </p>
  <div style="margin-left: auto; margin-right: auto; text-align: center; font-style: italic;">
    {{Link}}
  </div>
  <p>
    Таны дансны аюулгүйн хамгааллыг зөвшөөрөхийн тулд энэ линк <strong>30 минут</strong> бусадынх нь баталгаажуулах и-мэйлийг илгээжээ. Энэ нь автоматжуулсан и-мэйл юм. Та хариу хариултад бичихгүйлээрэй.
  </p>
</div>
', 'Холбоосыг нээнэ үү');
INSERT INTO cms."_TopicContent" ("Id", "TopicId", "CreatedOn", "UpdatedOn", "Language", "Title", "Author", "Content", "Subtitle") VALUES (11514, 11308, '2023-08-16 18:33:05.921008 +00:00', '2023-08-16 18:33:05.921008 +00:00', 'jp-jp', 'MT4パスワードをリセット', '', e'
