INSERT INTO cms."_TopicContent" ("Id", "TopicId", "CreatedOn", "UpdatedOn", "Language", "Title", "Author", "Content", "Subtitle") VALUES (10065, 11246, '2023-08-16 18:00:32.879327 +00:00', '2024-02-06 00:19:15.507494 +00:00', 'mn-mn', 'MT5 нууц үгийг дахин тохируулах', '', e'<div style="font-size: 12px; line-height: 20px">
  <p style="font-size: 16px; font-weight: 700; line-height: 24px">
    Шилжүүлгээний Иргэн,
  </p>
  <p>
    Нууц үгээ шинэчлэх линк дээр дарж бидний системийг ажиллуулахад оролцох бол <a href="{{Link}}" target="_blank" style="color: #383d49; text-decoration: none; font-weight: 700;">энд</a> дарж, эсвэл доорх линкээ бүртгэлтэй веб хаяг буруу бичих хэсэгт хуулж аваарай:
  </p>
  <div style="margin-left: auto; margin-right: auto; text-align: center; font-style: italic;">
    {{Link}}
  </div>
  <p>
    Таны дансны аюулгүйн хамгааллыг зөвшөөрөхийн тулд энэ линк <strong>30 минут</strong> бусадынх нь баталгаажуулах и-мэйлийг илгээжээ. Энэ нь автоматжуулсан и-мэйл юм. Та хариу хариултад бичихгүйлээрэй.
  </p>
</div>
', 'Холбоосыг нээнэ үү');
INSERT INTO cms."_TopicContent" ("Id", "TopicId", "CreatedOn", "UpdatedOn", "Language", "Title", "Author", "Content", "Subtitle") VALUES (10101, 11246, '2023-08-16 18:55:09.115049 +00:00', '2024-02-06 00:19:22.310281 +00:00', 'vi-vn', 'Đặt lại Mật khẩu MT5', '', e'
