INSERT INTO cms."_TopicContent" ("Id", "TopicId", "CreatedOn", "UpdatedOn", "Language", "Title", "Author", "Content", "Subtitle") VALUES (11601, 11328, '2024-03-26 20:31:08.991306 +00:00', '2024-03-26 20:31:08.991306 +00:00', 'vi-vn', 'Chuyển người dùng thành công', '', e'<div style="font-size: 12px; line-height: 20px">
