INSERT INTO cms."_TopicContent" ("Id", "TopicId", "CreatedOn", "UpdatedOn", "Language", "Title", "Author", "Content", "Subtitle") VALUES (11606, 11329, '2024-03-26 20:33:34.370489 +00:00', '2024-03-26 20:33:34.370489 +00:00', 'zh-tw', '轉帳失敗', '', e'<div style="font-size: 12px; line-height: 20px">
  <p style="font-size: 16px; font-weight: 700; line-height: 24px">
    尊敬的客戶，
  </p>
  <p>
    很抱歉通知您，您的轉帳請求未能被處理，並已被拒絕。以下是詳細資訊：
  </p>
  <table class="letter-table" style="table-layout: fixed; line-height: 24px; margin-left: auto; margin-right: auto; text-align: left; padding: 8px; float: none;" bgcolor="#f2f2f2" align="left">
    <tr>
      <th style="padding-left: 24px; padding-right: 24px; color: #383d49; white-space: nowrap;">
        來自：
      </th>
      <td style="padding-left: 24px; padding-right: 24px; word-wrap: break-word;">
        {{SourceAccountNumber}}
      </td>
    </tr>
    <tr>
      <th style="padding-left: 24px; padding-right: 24px; color: #383d49; white-space: nowrap;">
        至：
      </th>
      <td style="padding-left: 24px; padding-right: 24px; word-wrap: break-word;">
        {{TargetAccountNumber}}
      </td>
    </tr>
    <tr>
      <th style="padding-left: 24px; padding-right: 24px; color: #383d49; white-space: nowrap;">
        轉帳金額：
      </th>
      <td style="padding-left: 24px; padding-right: 24px; word-wrap: break-word;">
        $ {{FormattedAmount}}
      </td>
    </tr>
    <tr>
      <th style="padding-left: 24px; padding-right: 24px; color: #383d49; white-space: nowrap;">
        轉帳日期：
      </th>
      <td style="padding-left: 24px; padding-right: 24px; word-wrap: break-word;">
        {{Date}}
      </td>
    </tr>
  </table>
  <p>
    如果您對轉帳請求被拒絕原因不清楚，請諮詢您的帳戶經理或通過在線聊天與我們聯繫。
  </p>
</div>
', '');
INSERT INTO cms."_TopicContent" ("Id", "TopicId", "CreatedOn", "UpdatedOn", "Language", "Title", "Author", "Content", "Subtitle") VALUES (11607, 11329, '2024-03-26 20:34:21.159208 +00:00', '2024-03-26 20:34:21.159208 +00:00', 'vi-vn', ' Chuyển không thành công', '', e'<div style="font-size: 12px; line-height: 20px">
  <p style="font-size: 16px; font-weight: 700; line-height: 24px">
    Kính gửi Quý Khách hàng,
  </p>
  <p>
    Yêu cầu chuyển khoản của Quý vị không thể được xử lý và đã bị từ chối. Dưới đây là các chi tiết cụ thể:
  </p>
  <table class="letter-table" style="table-layout: fixed; line-height: 24px; margin-left: auto; margin-right: auto; text-align: left; padding: 8px; float: none;" bgcolor="#f2f2f2" align="left">
    <tr>
      <th style="padding-left: 24px; padding-right: 24px; color: #383d49; white-space: nowrap;">
        Từ:
      </th>
      <td style="padding-left: 24px; padding-right: 24px; word-wrap: break-word;">
        {{SourceAccountNumber}}
      </td>
    </tr>
    <tr>
      <th style="padding-left: 24px; padding-right: 24px; color: #383d49; white-space: nowrap;">
        Đến:
      </th>
      <td style="padding-left: 24px; padding-right: 24px; word-wrap: break-word;">
        {{TargetAccountNumber}}
      </td>
    </tr>
    <tr>
      <th style="padding-left: 24px; padding-right: 24px; color: #383d49; white-space: nowrap;">
        Số Tiền Chuyển:
      </th>
      <td style="padding-left: 24px; padding-right: 24px; word-wrap: break-word;">
        $ {{FormattedAmount}}
      </td>
    </tr>
    <tr>
      <th style="padding-left: 24px; padding-right: 24px; color: #383d49; white-space: nowrap;">
        Ngày Chuyển:
      </th>
      <td style="padding-left: 24px; padding-right: 24px; word-wrap: break-word;">
        {{Date}}
      </td>
    </tr>
  </table>
  <p>
    Nếu Quý vị không chắc chắn về lý do tại sao yêu cầu chuyển khoản của mình bị từ chối, vui lòng tham khảo ý kiến của quản lý tài khoản hoặc liên hệ với chúng tôi qua cuộc trò chuyện trực tuyến.
  </p>
</div>
', '');
INSERT INTO cms."_TopicContent" ("Id", "TopicId", "CreatedOn", "UpdatedOn", "Language", "Title", "Author", "Content", "Subtitle") VALUES (11608, 11329, '2024-03-26 20:34:57.138940 +00:00', '2024-03-26 20:34:57.138940 +00:00', 'th-th', 'การโอนล้มเหลว', '', e'<div style="font-size: 12px; line-height: 20px">
  <p style="font-size: 16px; font-weight: 700; line-height: 24px">
    เรียนลูกค้า,
  </p>
  <p>
    คำขอการโอนเงินของท่านไม่สามารถดำเนินการได้และถูกปฏิเสธลง ดูรายละเอียดเพิ่มเติมด้านล่าง:
  </p>
  <table class="letter-table" style="table-layout: fixed; line-height: 24px; margin-left: auto; margin-right: auto; text-align: left; padding: 8px; float: none;" bgcolor="#f2f2f2" align="left">
    <tr>
      <th style="padding-left: 24px; padding-right: 24px; color: #383d49; white-space: nowrap;">
        จาก:
      </th>
      <td style="padding-left: 24px; padding-right: 24px; word-wrap: break-word;">
        {{SourceAccountNumber}}
      </td>
    </tr>
    <tr>
      <th style="padding-left: 24px; padding-right: 24px; color: #383d49; white-space: nowrap;">
        ถึง:
      </th>
      <td style="padding-left: 24px; padding-right: 24px; word-wrap: break-word;">
        {{TargetAccountNumber}}
      </td>
    </tr>
    <tr>
      <th style="padding-left: 24px; padding-right: 24px; color: #383d49; white-space: nowrap;">
        จำนวนเงินที่โอน:
      </th>
      <td style="padding-left: 24px; padding-right: 24px; word-wrap: break-word;">
        $ {{FormattedAmount}}
      </td>
    </tr>
    <tr>
      <th style="padding-left: 24px; padding-right: 24px; color: #383d49; white-space: nowrap;">
        วันที่โอน:
      </th>
      <td style="padding-left: 24px; padding-right: 24px; word-wrap: break-word;">
        {{Date}}
      </td>
    </tr>
  </table>
  <p>
    หากท่านไม่แน่ใจว่าทำไมคำขอการโอนของท่านถูกปฏิเสธ กรุณาปรึกษาผู้จัดการบัญชีของท่านหรือติดต่อเราทางช่องทางสดติดต่อ.
  </p>
</div>
', '');
