  <table class="letter-table" style="table-layout: fixed; line-height: 24px; margin-left: auto; margin-right: auto; text-align: left; padding: 8px; float: none;" bgcolor="#f2f2f2" align="left">
    <tr>
      <th style="padding-left: 24px; padding-right: 24px; color: #383d49; white-space: nowrap;">
        来自：
      </th>
      <td style="padding-left: 24px; padding-right: 24px; word-wrap: break-word;">
        {{SourceAccountNumber}}
      </td>
    </tr>
    <tr>
      <th style="padding-left: 24px; padding-right: 24px; color: #383d49; white-space: nowrap;">
        到：
      </th>
      <td style="padding-left: 24px; padding-right: 24px; word-wrap: break-word;">
        {{TargetAccountNumber}}
      </td>
    </tr>
    <tr>
      <th style="padding-left: 24px; padding-right: 24px; color: #383d49; white-space: nowrap;">
        转账金额：
      </th>
      <td style="padding-left: 24px; padding-right: 24px; word-wrap: break-word;">
        $ {{FormattedAmount}}
      </td>
    </tr>
    <tr>
      <th style="padding-left: 24px; padding-right: 24px; color: #383d49; white-space: nowrap;">
        转账日期：
      </th>
      <td style="padding-left: 24px; padding-right: 24px; word-wrap: break-word;">
        {{Date}}
      </td>
    </tr>
  </table>
  <p>
    如果您对转账请求被拒绝原因不清楚，请咨询您的账户经理或通过在线聊天与我们联系。
  </p>
</div>
', '');
INSERT INTO cms."_TopicContent" ("Id", "TopicId", "CreatedOn", "UpdatedOn", "Language", "Title", "Author", "Content", "Subtitle") VALUES (11610, 11329, '2024-03-26 20:35:36.544112 +00:00', '2024-03-26 20:35:36.544112 +00:00', 'mn-mn', 'Дамжуулж чадсангүй', '', e'<div style="font-size: 12px; line-height: 20px">
