</div>
', '');
INSERT INTO cms."_TopicContent" ("Id", "TopicId", "CreatedOn", "UpdatedOn", "Language", "Title", "Author", "Content", "Subtitle") VALUES (11653, 11337, '2024-04-01 22:51:25.087338 +00:00', '2024-04-02 00:23:02.736381 +00:00', 'th-th', 'สร้างบัญชี IB แล้ว', '', e'<div style="font-size:12px;line-height:20px">
    <p style="font-size:16px;font-weight:700;line-height:24px">เรียนพันธมิตร BCR,</p>
    <p>ขอขอบคุณที่เปิดบัญชี IB กับ BCR ค่ะ หากต้องการเริ่มต้น โปรดเข้าสู่ระบบ MyBCR และไปที่ IB Center ค่ะ คุณจะสามารถสร้างและจัดการลิงก์การแนะนำของคุณใน IB Center ได้ค่ะ แชร์ลิงก์การแนะนำกับลูกค้าของคุณ และพวกเขาสามารถใช้งานเพื่อลงทะเบียนได้</p>
    <p>รายละเอียดบัญชี IB ของคุณแสดงด้านล่าง:</p>
    <table class="letter-table"
        style="table-layout:fixed;line-height:24px;margin-left:auto;margin-right:auto;text-align:left;padding:8px;float:none"
        bgcolor="#f2f2f2" align="left">
        <tr>
            <th
                style="padding-left:24px;padding-right:24px;color:#383d49;white-space:nowrap">
                ชื่อบัญชี IB:</th>
            <td style="padding-left:24px;padding-right:24px;word-wrap:break-word">
                {{UserName}}</td>
        </tr>
        <tr>
            <th
                style="padding-left:24px;padding-right:24px;color:#383d49;white-space:nowrap">
                รหัสบัญชี IB UID:</th>
            <td style="padding-left:24px;padding-right:24px;word-wrap:break-word">
                {{AccountUid}}</td>
        </tr>
        <tr>
            <th
                style="padding-left:24px;padding-right:24px;color:#383d49;white-space:nowrap">
                รหัส IB:</th>
            <td style="padding-left:24px;padding-right:24px;word-wrap:break-word">
                {{IbCode}}</td>
        </tr>
    </table>
</div>
', '');
INSERT INTO cms."_TopicContent" ("Id", "TopicId", "CreatedOn", "UpdatedOn", "Language", "Title", "Author", "Content", "Subtitle") VALUES (11655, 11338, '2024-04-01 22:53:08.497458 +00:00', '2024-04-03 19:00:22.009953 +00:00', 'zh-cn', '客户代理账户已创建', '', e'<div style="font-size:12px;line-height:20px">
