INSERT INTO cms."_TopicContent" ("Id", "TopicId", "CreatedOn", "UpdatedOn", "Language", "Title", "Author", "Content", "Subtitle") VALUES (11542, 11315, '2024-03-06 00:12:04.885301 +00:00', '2024-04-04 21:54:46.386746 +00:00', 'zh-tw', '客戶提款申請', '', e'<div style="font-size: 12px; line-height: 20px">
  <p style="font-size: 16px; font-weight: 700; line-height: 24px">
    尊敬的BCR合作夥伴，
  </p>
  <p>
您的客戶已提交提款申請。以下提供詳細信息：
  </p>
  <table class="letter-table" style="
      table-layout: fixed;
      line-height: 24px;
      margin-left: auto;
      margin-right: auto;
      text-align: left;
      padding: 8px;
      float: none;
      " bgcolor="#f2f2f2" align="left">
    <tr>
      <th style="
          padding-left: 24px;
          padding-right: 24px;
          color: #383d49;
          white-space: nowrap;
          ">
        提款方式：
      </th>
      <td style="
          padding-left: 24px;
          padding-right: 24px;
          word-wrap: break-word;
          ">
        {{PaymentMethod}}
      </td>
    </tr>
    <tr>
      <th style="
          padding-left: 24px;
          padding-right: 24px;
          color: #383d49;
          white-space: nowrap;
          ">
        帳戶號碼：
      </th>
      <td style="
          padding-left: 24px;
          padding-right: 24px;
          word-wrap: break-word;
          ">
        {{AccountNumber}}
      </td>
    </tr>
    <tr>
      <th style="padding-left: 24px; padding-right: 24px; color: #383d49; white-space: nowrap;">帳戶名稱：</th>
      <td style="padding-left: 24px; padding-right: 24px; word-wrap: break-word;">{{NativeName}}</td>
    </tr>
    <tr>
      <th style="
          padding-left: 24px;
          padding-right: 24px;
          color: #383d49;
          white-space: nowrap;
          ">
        貨幣：
      </th>
      <td style="
          padding-left: 24px;
          padding-right: 24px;
          word-wrap: break-word;
          ">
        {{Currency}}
      </td>
    </tr>
    <tr>
      <th style="
          padding-left: 24px;
          padding-right: 24px;
          color: #383d49;
          white-space: nowrap;
          ">
        金額：
      </th>
      <td style="
          padding-left: 24px;
          padding-right: 24px;
          word-wrap: break-word;
          ">
        $ {{Amount}}
      </td>
    </tr>
  </table>
  <p>
    要查詢您的提款記錄，請登錄到
    <a target="_blank" href="https://cfds-portal.thebcr.com/"
       style="color: #383d49; text-decoration: none; font-weight: 700;"
       >我的BCR</a>
    帳戶的部分。
  </p>
</div>
', '');
