INSERT INTO cms."_TopicContent" ("Id", "TopicId", "CreatedOn", "UpdatedOn", "Language", "Title", "Author", "Content", "Subtitle") VALUES (11658, 11338, '2024-04-01 22:54:16.872125 +00:00', '2024-04-03 19:00:17.930917 +00:00', 'vi-vn', ' Tài khoản IB của khách hàng đã được tạo', '', e'<div style="font-size:12px;line-height:20px">
