    <p>Khách hàng của bạn đã mở một tài khoản IB, và chi tiết tài khoản IB được liệt kê dưới đây:</p>
    <table class="letter-table"
        style="table-layout:fixed;line-height:24px;margin-left:auto;margin-right:auto;text-align:left;padding:8px;float:none"
        bgcolor="#f2f2f2" align="left">
        <tr>
            <th
                style="padding-left:24px;padding-right:24px;color:#383d49;white-space:nowrap">
                Tài khoản IB:</th>
            <td style="padding-left:24px;padding-right:24px;word-wrap:break-word">
                {{UserName}}</td>
        </tr>
        <tr>
            <th
                style="padding-left:24px;padding-right:24px;color:#383d49;white-space:nowrap">
                Email IB:</th>
            <td style="padding-left:24px;padding-right:24px;word-wrap:break-word">
                {{IbEmail}}</td>
        </tr>
        <tr>
            <th
                style="padding-left:24px;padding-right:24px;color:#383d49;white-space:nowrap">
                UID Tài khoản IB:</th>
            <td style="padding-left:24px;padding-right:24px;word-wrap:break-word">
                {{AccountUid}}</td>
        </tr>
        <tr>
            <th
                style="padding-left:24px;padding-right:24px;color:#383d49;white-space:nowrap">
                Mã IB:</th>
            <td style="padding-left:24px;padding-right:24px;word-wrap:break-word">
                {{IbCode}}</td>
        </tr>
    </table>
</div>
', '');
INSERT INTO cms."_TopicContent" ("Id", "TopicId", "CreatedOn", "UpdatedOn", "Language", "Title", "Author", "Content", "Subtitle") VALUES (11727, 11353, '2024-05-09 18:54:37.702409 +00:00', '2024-05-09 20:54:58.152148 +00:00', 'zh-tw', 'BCR 驗證碼', '', e'<div style="line-height:20px">
