INSERT INTO cms."_TopicContent" ("Id", "TopicId", "CreatedOn", "UpdatedOn", "Language", "Title", "Author", "Content", "Subtitle") VALUES (10092, 11255, '2023-08-16 18:43:49.019503 +00:00', '2024-06-24 21:44:56.131830 +00:00', 'jp-jp', 'ログインして申し込みを完了してください', '', e'
<td style="padding-left:32px;padding-right:32px">
  <div style="font-size:12px;line-height:20px">
    <p style="font-size:16px;font-weight:700;line-height:24px">親愛なるクライアント様へ</p>
    <p>
      BCRでアカウントのオンライン申し込みを開始いただき、ありがとうございます。これにより、クライアントの一員として、多くの方々がBCRを信頼して、外国為替、貴金属、株式、商品CFD取引の提供者として選んでいただいています。新しいBCRアカウントの確認と有効化のために、以下のリンクをクリックしてください。</p>
    <table class="letter-table"
           style="table-layout:fixed;line-height:24px;margin-left:auto;margin-right:auto;text-align:left;padding:8px;float:none"
           bgcolor="#f2f2f2" align="left">
      <tr>
        <th
            style="padding-left:24px;padding-right:24px;color:#383d49;white-space:nowrap">
          MyBCRログイン</th>
        <td style="padding-left:24px;padding-right:24px;word-wrap:break-word">{{Email}}
        </td>
      </tr>
      <tr>
        <th
            style="padding-left:24px;padding-right:24px;color:#383d49;white-space:nowrap">
          MyBCRパスワード</th>
        <td style="padding-left:24px;padding-right:24px;word-wrap:break-word">
          {{Password}}</td>
      </tr>
    </table>
    <div style="padding-top:24px;padding-bottom:24px;text-align:center"><a
                                                                           href="https://thebcrglobal.com/sign-in" target="_blank" class="footer-btn"
                                                                           style="color:#383d49;border-radius:8px;border-width:0;padding:8px 32px;font-size:18px;font-weight:600;background-color:#f7b93f;text-decoration:none">MyBCR
      ログイン</a>
    </div>
    <div style="display:flex; align-items:flex-start;">
      <div style="margin-right:2px;flex-shrink: 0;">
        <img src="https://bcr-img-new.s3.amazonaws.com/bullet_point/bullet_triple_squares_black_yellow_gray.png" alt=""
             width="10" style="margin-top:0px; margin-right:10px;" />
      </div>
      <span style="font-size:10px">もしBCRでライブトレードアカウントの登録を行っていない場合、すぐにご連絡いただきますようお願い申し上げます。詳細について確認させていただきます。</span>
    </div>
  </div>', 'BCR 取引口座申し込みを受け取りました');
INSERT INTO cms."_TopicContent" ("Id", "TopicId", "CreatedOn", "UpdatedOn", "Language", "Title", "Author", "Content", "Subtitle") VALUES (11347, 11255, '2023-08-16 21:25:54.490038 +00:00', '2024-06-24 21:45:23.526493 +00:00', 'vi-vn', 'Đăng nhập để hoàn tất đơn đăng ký của bạn', '', e'<td style="padding-left: 32px; padding-right: 32px">
  <div style="font-size: 12px; line-height: 20px">
    <p style="font-size: 16px; font-weight: 700; line-height: 24px">Kính gửi Quý khách hàng thân mến,</p>
    <p>
      Chúng tôi xin chân thành cảm ơn Quý khách đã khởi đầu việc đăng ký tài khoản trực tuyến với BCR. Bằng việc làm
      đó, Quý khách đã trở thành một trong hàng ngàn khách hàng đã chọn BCR là đối tác tin cậy để giao dịch các loại CFD như Ngoại Hối,
      Kim Loại Quý, Chứng Khoán và Hàng Hóa. Để xác nhận địa chỉ email của Quý khách và kích hoạt tài khoản BCR mới,
      vui lòng nhấp vào liên kết bên dưới.</p>
    <table class="letter-table" style="
            table-layout: fixed;
            line-height: 24px;
            margin-left: auto;
            margin-right: auto;
            text-align: left;
            padding: 8px;
            float: none;
          " bgcolor="#f2f2f2" align="left">
      <tr>
        <th style="
            padding-left: 24px;
            padding-right: 24px;
            color: #383d49;
            white-space: nowrap;
          ">
          Tài Khoản MyBCR</th>
        <td style="padding-left: 24px; padding-right: 24px; word-wrap: break-word">{{Email}}
        </td>
      </tr>
      <tr>
        <th style="
            padding-left: 24px;
            padding-right: 24px;
            color: #383d49;
            white-space: nowrap;
          ">
          Mật Khẩu MyBCR</th>
        <td style="padding-left: 24px; padding-right: 24px; word-wrap: break-word">
          {{Password}}</td>
      </tr>
    </table>
    <div style="padding-top: 24px; padding-bottom: 24px; text-align: center"><a
        href="https://thebcrglobal.com/sign-in" target="_blank" class="footer-btn"
        style="color: #383d49; border-radius: 8px; border-width: 0; padding: 8px 32px; font-size: 18px; font-weight: 600; background-color: #f7b93f; text-decoration: none">Đăng Nhập MyBCR</a>
    </div>
    <div style="display: flex; align-items: flex-start;">
      <div style="margin-right: 2px; flex-shrink: 0;">
        <img src="https://bcr-img-new.s3.amazonaws.com/bullet_point/bullet_triple_squares_black_yellow_gray.png" alt=""
             width="10" style="margin-top: 0px; margin-right: 10px;" />
      </div>
      <span style="font-size: 10px">Nếu Quý khách chưa đăng ký tài khoản giao dịch thực tại BCR, vui lòng liên hệ với chúng tôi ngay để chúng tôi có thể giải quyết tình hình này thêm chi tiết.
      </span>
    </div>
  </div>
</td>
', 'Chúng tôi đã nhận được đơn đăng ký tài khoản giao dịch BCR của bạn');
