                <td style="padding-left:24px;padding-right:24px;word-wrap:break-word">
                    {{Password}}</td>
            </tr>
        </table>
        <div style="padding-top:24px;padding-bottom:24px;text-align:center"><a
                href="https://thebcrglobal.com/sign-in" target="_blank" class="footer-btn"
                style="color:#383d49;border-radius:8px;border-width:0;padding:8px 32px;font-size:18px;font-weight:600;background-color:#f7b93f;text-decoration:none">MyBCR
                登錄</a>
        </div>
        <div style="display:flex; align-items:flex-start;">
            <div style="margin-right:2px;flex-shrink: 0;">
                <img src="https://bcr-img-new.s3.amazonaws.com/bullet_point/bullet_triple_squares_black_yellow_gray.png" alt=""
                    width="10" style="margin-top:0px; margin-right:10px;" />
