INSERT INTO cms."_TopicContent" ("Id", "TopicId", "CreatedOn", "UpdatedOn", "Language", "Title", "Author", "Content", "Subtitle") VALUES (11681, 11342, '2024-04-24 00:07:08.944437 +00:00', '2024-04-24 00:07:08.944437 +00:00', 'th-th', 'การสมัครถอนเงิน', '', e'<div style="font-size: 12px; line-height: 20px">
