INSERT INTO cms."_TopicContent" ("Id", "TopicId", "CreatedOn", "UpdatedOn", "Language", "Title", "Author", "Content", "Subtitle") VALUES (11709, 11347, '2024-04-24 00:29:45.954357 +00:00', '2024-04-24 00:29:45.954357 +00:00', 'vi-vn', ' Rút tiền đại lý không thành công', '', e'<div style="font-size: 12px; line-height: 20px">
  <p style="font-size: 16px; font-weight: 700; line-height: 24px">
    Kính gửi đối tác BCR,
  </p>
  <p>
    Yêu cầu rút tiền của đại lý của bạn không thể được xử lý và đã bị từ chối. Dưới đây là chi tiết:
  </p>
  <table class="letter-table" style="
                table-layout: fixed;
                line-height: 24px;
                margin-left: auto;
                margin-right: auto;
                text-align: left;
                padding: 8px;
                float: none;
                " bgcolor="#f2f2f2" align="left">
    <tr>
      <th style="
                 padding-left: 24px;
                 padding-right: 24px;
                 color: #383d49;
                 white-space: nowrap;
                 ">
        Email của đại lý:
      </th>
      <td style="
                 padding-left: 24px;
                 padding-right: 24px;
                 word-wrap: break-word;
                 ">
        {{AgentEmail}}
      </td>
    </tr>
    <tr>
      <th style="
                 padding-left: 24px;
                 padding-right: 24px;
                 color: #383d49;
                 white-space: nowrap;
                 ">
        Tên của đại lý:
      </th>
      <td style="
                 padding-left: 24px;
                 padding-right: 24px;
                 word-wrap: break-word;
                 ">
        {{NativeName}}
      </td>
    </tr>
    <tr>
      <th style="
                 padding-left: 24px;
                 padding-right: 24px;
                 color: #383d49;
                 white-space: nowrap;
                 ">
        Tiền tệ:
      </th>
      <td style="
                 padding-left: 24px;
                 padding-right: 24px;
                 word-wrap: break-word;
                 ">
        {{Currency}}
      </td>
    </tr>
    <tr>
      <th style="
                 padding-left: 24px;
                 padding-right: 24px;
                 color: #383d49;
                 white-space: nowrap;
                 ">
        Số tiền:
      </th>
      <td style="
                 padding-left: 24px;
                 padding-right: 24px;
                 word-wrap: break-word;
                 ">
        $ {{Amount}}
      </td>
    </tr>
    <tr>
      <th style="
                 padding-left: 24px;
                 padding-right: 24px;
                 color: #383d49;
                 white-space: nowrap;
                 ">
        Ngày yêu cầu:
      </th>
      <td style="
                 padding-left: 24px;
                 padding-right: 24px;
                 word-wrap: break-word;
                 ">
         {{Date}}
      </td>
    </tr>
  </table>
  <p>
    Lý do không thể xử lý yêu cầu rút tiền là:
  </p>
  <p style="color: #cc1f1a; font-weight: 600">{{Reason}}</p>
  <br />
  <p>
    Nếu bạn vẫn không chắc chắn về lý do tại sao yêu cầu rút tiền của đại lý của bạn bị từ chối, vui lòng tham khảo ý kiến của quản lý tài khoản hoặc liên hệ với chúng tôi qua trò chuyện trực tiếp.
  </p>
</div>
', '');
INSERT INTO cms."_TopicContent" ("Id", "TopicId", "CreatedOn", "UpdatedOn", "Language", "Title", "Author", "Content", "Subtitle") VALUES (11710, 11347, '2024-04-24 00:30:36.619614 +00:00', '2024-04-24 00:30:36.619614 +00:00', 'th-th', 'การถอนตัวแทนล้มเหลว', '', e'<div style="font-size: 12px; line-height: 20px">
  <p style="font-size: 16px; font-weight: 700; line-height: 24px">
    เรียนพันธมิตร BCR ที่เคารพ,
  </p>
  <p>
    คำขอถอนเงินของตัวแทนของคุณไม่สามารถดำเนินการได้และถูกปฏิเสธ ดังต่อไปนี้คือรายละเอียดเพิ่มเติม:
  </p>
  <table class="letter-table" style="
                table-layout: fixed;
                line-height: 24px;
                margin-left: auto;
                margin-right: auto;
                text-align: left;
                padding: 8px;
                float: none;
                " bgcolor="#f2f2f2" align="left">
    <tr>
      <th style="
                 padding-left: 24px;
                 padding-right: 24px;
                 color: #383d49;
                 white-space: nowrap;
                 ">
        อีเมลของตัวแทน:
      </th>
      <td style="
                 padding-left: 24px;
                 padding-right: 24px;
                 word-wrap: break-word;
                 ">
        {{AgentEmail}}
      </td>
    </tr>
    <tr>
      <th style="
                 padding-left: 24px;
                 padding-right: 24px;
                 color: #383d49;
                 white-space: nowrap;
                 ">
        ชื่อตัวแทน:
      </th>
      <td style="
                 padding-left: 24px;
                 padding-right: 24px;
                 word-wrap: break-word;
                 ">
        {{NativeName}}
      </td>
    </tr>
    <tr>
      <th style="
                 padding-left: 24px;
                 padding-right: 24px;
                 color: #383d49;
                 white-space: nowrap;
                 ">
        สกุลเงิน:
      </th>
      <td style="
                 padding-left: 24px;
                 padding-right: 24px;
                 word-wrap: break-word;
                 ">
        {{Currency}}
      </td>
    </tr>
    <tr>
      <th style="
                 padding-left: 24px;
                 padding-right: 24px;
                 color: #383d49;
                 white-space: nowrap;
                 ">
        จำนวน:
      </th>
      <td style="
                 padding-left: 24px;
                 padding-right: 24px;
                 word-wrap: break-word;
                 ">
        $ {{Amount}}
      </td>
    </tr>
    <tr>
      <th style="
                 padding-left: 24px;
                 padding-right: 24px;
                 color: #383d49;
                 white-space: nowrap;
                 ">
        วันที่ขอ:
      </th>
      <td style="
                 padding-left: 24px;
                 padding-right: 24px;
                 word-wrap: break-word;
                 ">
         {{Date}}
      </td>
    </tr>
  </table>
  <p>
    เหตุผลที่ไม่สามารถดำเนินการถอนได้คือ:
  </p>
  <p style="color: #cc1f1a; font-weight: 600">{{Reason}}</p>
  <br />
  <p>
    หากยังไม่แน่ใจว่าเหตุใดทำให้คำขอถอนเงินของตัวแทนของคุณถูกปฏิเสธ กรุณาติดต่อผู้จัดการบัญชีของคุณหรือติดต่อเราผ่านการสนทนาสด
  </p>
</div>
', '');
