INSERT INTO cms."_TopicContent" ("Id", "TopicId", "CreatedOn", "UpdatedOn", "Language", "Title", "Author", "Content", "Subtitle") VALUES (10074, 11255, '2023-08-16 18:20:46.727491 +00:00', '2024-06-24 21:45:09.899220 +00:00', 'mn-mn', 'Өргөдлөө дуусгахын тулд нэвтэрнэ үү', '', e'<td style="padding-left:32px;padding-right:32px">
