INSERT INTO cms."_TopicContent" ("Id", "TopicId", "CreatedOn", "UpdatedOn", "Language", "Title", "Author", "Content", "Subtitle") VALUES (10035, 11262, '2023-08-16 00:03:31.604218 +00:00', '2024-12-02 21:31:39.898387 +00:00', 'zh-cn', '开户文件未通过验证的通知', '', e'<div>亲爱的 {{NativeName}}，</div>

<p>感谢您提交的开户文件。遗憾的是，我们在审核过程中未能通过您的身份证明文件/地址证明的验证。原因可能包括文件已过期、信息缺失 、 文件非彩色 、资料不准确或难以阅读。</p>

<p>为了确保顺利完成开户，请您重新提交一份最新、完整、清晰且可读取的文件。我们建议您仔细检查文件的有效期以及所有信息的准确性，确保文件符合我们的审核要求。</p>

<p>为保障每位用户的隐私和安全，我们严格遵守相关安全政策和指南。感谢您的理解与配合。  </p>

<p>如有任何疑问或需要进一步的帮助，请随时与我们联系。我们将竭诚为您提供支持。</p>

<p>感谢您的理解与配合。</p>

<p>祝您一切顺利！</p>', '');
INSERT INTO cms."_TopicContent" ("Id", "TopicId", "CreatedOn", "UpdatedOn", "Language", "Title", "Author", "Content", "Subtitle") VALUES (11809, 11381, '2024-08-05 21:59:15.372069 +00:00', '2024-08-05 21:59:15.372069 +00:00', 'jp-jp', ' 顧客のショップ注文の通知', '', e'<div style="font-size: 12px; line-height: 20px">
