INSERT INTO cms."_TopicContent" ("Id", "TopicId", "CreatedOn", "UpdatedOn", "Language", "Title", "Author", "Content", "Subtitle") VALUES (11790, 11376, '2024-07-23 22:00:03.616648 +00:00', '2024-08-07 22:16:36.624766 +00:00', 'en-us', 'Margin Call Notice', 'system', e'<div>
  <p>
    <span id="date">
     Date:  {{Date}}
    </span>
  </p>

  <p>
    Dear Sir/Madam,
  </p>
  <p>
    Hello! Your account\'s net value has currently fallen below the 100% margin level. Please be advised that if the margin level continues to drop to or below the stop-out level, your open positions will be automatically closed. 
    <br />
    <br />
    You may consider depositing more funds into your account or closing some of your existing positions to meet the margin requirements. 
    <br />
    <ul>
      <li>
        <strong>Account Number: </strong>{{AccountNumber}}
      </li>
      <li>
        <strong>Account Net Value: </strong>{{NetValue}}
      </li>
      <li>
        <strong>Current Margin Level: </strong>{{Level}}
      </li>
    </ul>
    Please be reminded that trading CFDs can result in losses exceeding the margin you
    have deposited and may not be suitable for every investor. Therefore, please ensure
    that you fully understand the risks involved.
    
    <br/>
    <br/>
        <a href="https://thebcrglobal.com/sign-in">FUND NOW</a>
    <br/>
    <br/>
  </p>
</div>', '');
INSERT INTO cms."_TopicContent" ("Id", "TopicId", "CreatedOn", "UpdatedOn", "Language", "Title", "Author", "Content", "Subtitle") VALUES (11816, 1000, '2024-08-09 21:00:18.428517 +00:00', '2024-08-09 21:02:36.592534 +00:00', 'en-us', 'Earning Release Margin Adjustment', 'system', e'<h3>Earning Release Margin Adjustment</h3>
    <p>Dear Valued Client,</p>
    <p>We are contacting you to let you know that we are making changes to some of the terms and conditions that govern our relationship with you and the way we provide BCR services to you.</p>
    
    <p><strong>What terms and conditions are we making changes to?</strong></p>
    <p>We are making changes to the following terms and conditions:</p>
    <ul>
        <li>US Shares margin requirement</li>
    </ul>
    
    <p><strong>What changes have we made?</strong></p>
    <p>US Shares margin requirement</p>
    <p>For US shares the margin requirement will increase from 10% to 40% three trading days before an earnings release and will return to the normal level within one trading day after the earnings release.</p>
    
    <p><strong>What do you have to do?</strong></p>
    <p>These changes will go into effect on the Trading Platform on 12 August 2024 at GMT 21:05 and will automatically apply to your trading capabilities. Be sure that you monitor the maintenance margin requirements on your BCR trading accounts at all times. You are solely responsible for the maintenance of your BCR trading account.</p>
    
    <p>BCR</p>', ' ');
INSERT INTO cms."_TopicContent" ("Id", "TopicId", "CreatedOn", "UpdatedOn", "Language", "Title", "Author", "Content", "Subtitle") VALUES (11818, 1000, '2024-08-09 21:03:41.623998 +00:00', '2024-08-09 21:48:05.784738 +00:00', 'zh-cn', '重大财经新闻发布更变', '', e'<h3>重大财经新闻发布更变</h3>
    <p>致尊敬的客户：</p>
    <p>BCR正在与您联系，以告知BCR正在更改部分条款和条件，这些条款和条件关于BCR与阁下之间的关系以及BCR向客户提供BCR服务的方式。</p>
    <p><strong>BCR需要更改哪些条款和条件？</strong></p>
    <p>BCR正在对以下的条款和条件进行更改：</p>
    <ul>
        <li>股票保证金收取模式</li>
    </ul>
    <p><strong>BCR作出什么的改变？</strong></p>
    <p>BCR将修改平台上的股票保证金收取模式收取模式，保证金要求将在业绩发布
前三个交易日从 10% 增加到 40%，并将在业绩发布后一个交易日内恢复到正
常水准。</p>
    <p><strong>阁下是否需要进行任何操作?</strong></p>
    <p>不需要。这些更改将于平台时间2024年08月12日GMT 21:05生效，并将自动应用于BCR为您提供的交易服务。敬请阁下仔细评估风险承受能力，并留意账户资金水平，提前做好资金调配。</p>
    <p>BCR</p>', '');
INSERT INTO cms."_TopicContent" ("Id", "TopicId", "CreatedOn", "UpdatedOn", "Language", "Title", "Author", "Content", "Subtitle") VALUES (11817, 1000, '2024-08-09 21:03:01.713484 +00:00', '2024-08-09 21:48:14.966396 +00:00', 'zh-tw', '重大財經新聞發佈更变', '', e'<h3>重大財經新聞發佈更变</h3>
    <p>致尊敬的客户：</p>
    <p>BCR正在与您联系，以告知BCR正在更改部份条款和条件，这些条款和条件关于BCR与阁下之间的关系以及BCR向客户提供BCR服务的方式。</p>
    <p><strong>BCR需要更改哪些条款和条件？</strong></p>
    <p>BCR正在对以下的条款和条件进行更改：</p>
    <ul>
        <li>股票保証金收取模式</li>
    </ul>
    <p><strong>BCR作出什么的改变？</strong></p>
    <p>BCR將修改平臺上的股票保証金收取模式收取模式，保證金要求將在業績發佈
前三個交易日從 10% 增加到 40%，並將在業績發佈後一個交易日內恢復到正
常水準。</p>
    <p><strong>阁下是否需要进行任何操作?</strong></p>
    <p>不需要。 这些更改将于平台时间2024年08月12日GMT 21:05 生效，并将自动应用于BCR为您提供的交易服务。敬請閣下仔細評估風險承受能力，並留意賬戶資金水平，提前做好資金調配。</p>
    <p>BCR</p>', '');
INSERT INTO cms."_TopicContent" ("Id", "TopicId", "CreatedOn", "UpdatedOn", "Language", "Title", "Author", "Content", "Subtitle") VALUES (11819, 1000, '2024-08-09 21:04:28.386816 +00:00', '2024-08-09 21:04:28.386816 +00:00', 'vi-vn', 'Điều chỉnh yêu cầu ký quỹ trước báo cáo thu nhập', '', e'<h3>Điều chỉnh yêu cầu ký quỹ trước báo cáo thu nhập</h3>
    <p>Kính gửi Quý Khách hàng,</p>
    <p>Chúng tôi liên hệ với bạn để thông báo rằng chúng tôi đang thực hiện các thay đổi đối với một số điều khoản và điều kiện điều chỉnh mối quan hệ giữa chúng tôi với bạn và cách chúng tôi cung cấp dịch vụ BCR cho bạn.</p>
    
    <p><strong>Chúng tôi đang thay đổi những điều khoản và điều kiện nào?</strong></p>
    <p>Chúng tôi đang thay đổi các điều khoản và điều kiện sau:</p>
    <ul>
        <li>Yêu cầu ký quỹ cổ phiếu Mỹ</li>
    </ul>
    
    <p><strong>Chúng tôi đã thực hiện những thay đổi gì?</strong></p>
    <p>Yêu cầu ký quỹ cổ phiếu Mỹ</p>
    <p>Đối với cổ phiếu Mỹ, yêu cầu ký quỹ sẽ tăng từ 10% lên 40% ba ngày giao dịch trước khi công bố thu nhập và sẽ trở lại mức bình thường trong vòng một ngày giao dịch sau khi công bố thu nhập.</p>
    
    <p><strong>Bạn cần phải làm gì?</strong></p>
    <p>Những thay đổi này sẽ có hiệu lực trên Nền tảng Giao dịch vào ngày 12 tháng 8 năm 2024 lúc 21:05 GMT và sẽ tự động áp dụng cho các khả năng giao dịch của bạn. Hãy chắc chắn rằng bạn luôn theo dõi các yêu cầu ký quỹ duy trì trên các tài khoản giao dịch BCR của bạn. Bạn hoàn toàn chịu trách nhiệm về việc duy trì tài khoản giao dịch BCR của mình.</p>
    
    <p>BCR</p>', '');
INSERT INTO cms."_TopicContent" ("Id", "TopicId", "CreatedOn", "UpdatedOn", "Language", "Title", "Author", "Content", "Subtitle") VALUES (10057, 11262, '2023-08-16 01:21:26.349308 +00:00', '2024-12-02 21:39:29.707631 +00:00', 'zh-tw', '有關驗證失敗的通知', '', e'<div>親愛的 {{NativeName}}</div>
<p>您好！</p>
<p>感謝您提交開戶文件。但很抱歉，在審核過程中我們無法驗證您的身份證明文件/地址證明。這可能是由於文件已過期、資料不完整、文件非彩色、資料不準確，或文件不清晰難以辨認等原因。</p>
<p>為確保您能順利完成開戶程序，請重新提交最新、完整、清晰且易於辨識的文件。我們建議您仔細檢查文件的有效性，並確保所有資料準確無誤，以符合我們的驗證要求。</p>
<p>為保護所有用戶的隱私和安全，我們嚴格遵守相關安全政策和準則。感謝您的理解與配合。</p>
<p>如果您有任何疑問或需要進一步協助，歡迎隨時與我們聯繫。我們很樂意為您提供協助。</p>
<p>再次感謝您的理解與配合。</p>', '');
