INSERT INTO cms."_TopicContent" ("Id", "TopicId", "CreatedOn", "UpdatedOn", "Language", "Title", "Author", "Content", "Subtitle") VALUES (11792, 11376, '2024-07-23 22:23:43.343067 +00:00', '2024-08-07 22:20:18.523971 +00:00', 'zh-tw', '保證金追加通知', '', e'<div>
  <p>
    <span id="date">
     日期:  {{Date}}
    </span>
  </p>

  <p>
    尊敬的客戶：
  </p>
  <p>
    您好！您的帳戶淨值目前已低於 100% 保證金水準。閣下需知悉，當保證金水準低於50%時，將自動清算帳戶中個別頭寸進行平倉直至帳戶淨值足以支撐現有的持倉頭寸為止。
    <br />
    <br />
    閣下可考慮向帳戶存入更多資金或關閉部分現有部位來降低因保證金不足而被強行平倉的風險。
    <br />
    <ul>
      <li>
        <strong>帳戶號碼: </strong>{{AccountNumber}}
      </li>
      <li>
        <strong>帳戶淨值: </strong>{{NetValue}}
      </li>
      <li>
        <strong>當前保證金水平: </strong>{{Level}}
      </li>
    </ul>
    我們建議閣下在任何時間都要密切監察閣下的帳戶淨值及管理好所有部位。
    <br/>
    <br/>
    請謹記，差價合約交易可能會導致損失超過閣下所存入的保證金，因此未必適合每一位投資人士，故此請確保閣下完全了解所涉及的風險。
    <br/>
    <br/>
    BCR致力於為客戶提供專業的交易服務、簡易的操作、優異的客戶服務。我們提供全天候24小時，每週五天全方位的客戶服務。如有任何查詢或建議，歡迎電子郵件至 info@thebcr.com 聯絡BCR員工。
    <br/>
    <br/>
        <a href="https://thebcrglobal.com/sign-in">存入保證金</a>
    <br/>
    <br/>
  </p>
</div>', '');
INSERT INTO cms."_TopicContent" ("Id", "TopicId", "CreatedOn", "UpdatedOn", "Language", "Title", "Author", "Content", "Subtitle") VALUES (11791, 11376, '2024-07-23 22:22:50.406378 +00:00', '2024-08-07 22:20:27.101932 +00:00', 'zh-cn', '保证金追加通知', '', e'<div>
  <p>
    <span id="date">
     日期:  {{Date}}
    </span>
  </p>

  <p>
    尊敬的客户：
  </p>
  <p>
    您好！您的账户净值目前已低于 100% 保证金水平。阁下需知悉，当保证金水平低于50%时，将自动清算账户中个别头寸进行平仓直至账户净值足以支撑现有的持仓头寸为止。
    <br />
    <br />
    阁下可考虑向账户存入更多资金或关闭部分现有仓位来降低因保证金不足而被强行平仓的风险。
    <br />
    <ul>
      <li>
        <strong>账户号码: </strong>{{AccountNumber}}
      </li>
      <li>
        <strong>账户净值: </strong>{{NetValue}}
      </li>
      <li>
        <strong>当前保证金水平: </strong>{{Level}}
      </li>
    </ul>
    我们建议阁下在任何时候都要密切监察阁下的账户净值及管理好所有仓位。
    <br/>
    <br/>
    请谨记，差价合约交易可能会导致损失超过阁下所存入的保证金，因此未必适合每一位投资人士，故此请确保阁下完全了解所涉及的风险。
    <br/>
    <br/>
    BCR致力为客户提供专业的交易服务、简易的操作、优异的客户服务。我们提供全天候24小时，每周五天全方位的客户服务。如有任何查询或建议，欢迎电邮至 info@thebcr.com 联系BCR员工。
    <br/>
    <br/>
        <a href="https://thebcrglobal.com/sign-in">存入保证金</a>
    <br/>
    <br/>
  </p>
</div>', '');
INSERT INTO cms."_TopicContent" ("Id", "TopicId", "CreatedOn", "UpdatedOn", "Language", "Title", "Author", "Content", "Subtitle") VALUES (10042, 11244, '2023-08-16 01:02:42.619601 +00:00', '2025-03-17 19:05:35.189112 +00:00', 'zh-tw', '歡迎加入', '', e'<div style="font-size:12px;line-height:20px">
    <p style="font-size:16px;font-weight:700;line-height:24px">親愛的 {{NativeName}} 客戶您好，</p>
    <p>感謝您開設 BCR 的差價合約（CFD）交易帳戶。您的帳戶已於 {{OpenedDate}} 開通，您的 BCR ProTrader 帳戶詳細資訊如下：</p>
    <table class="letter-table"
        style="table-layout:fixed;line-height:24px;margin-left:auto;margin-right:auto;text-align:left;padding:8px;float:none"
        bgcolor="#f2f2f2" align="left">
        <tr>
            <th
                style="padding-left:24px;padding-right:24px;color:#383d49;white-space:nowrap">
                MyBCR 帳戶：</th>
            <td style="padding-left:24px;padding-right:24px;word-wrap:break-word">
                {{UserName}}</td>
        </tr>
        <tr>
            <th
                style="padding-left:24px;padding-right:24px;color:#383d49;white-space:nowrap">
                 帳戶號碼：</th>
            <td style="padding-left:24px;padding-right:24px;word-wrap:break-word">
                {{AccountNumber}}</td>
        </tr>
        <tr>
            <th
                style="padding-left:24px;padding-right:24px;color:#383d49;white-space:nowrap">
                交易帳戶密碼：</th>
            <td style="padding-left:24px;padding-right:24px;word-wrap:break-word">
                {{Password}}</td>
        </tr>
        <!-- <tr>
            <th
                style="padding-left:24px;padding-right:24px;color:#383d49;white-space:nowrap">
                投資者密碼：</th>
            <td style="padding-left:24px;padding-right:24px;word-wrap:break-word">
                {{InvestorPassword}}</td>
        </tr>-->
        <tr>
            <th
                style="padding-left:24px;padding-right:24px;color:#383d49;white-space:nowrap">
                電話密碼：</th>
            <td style="padding-left:24px;padding-right:24px;word-wrap:break-word">
                {{PhonePassword}}</td>
        </tr>
        <tr>
            <th
                style="padding-left:24px;padding-right:24px;color:#383d49;white-space:nowrap">
                伺服器：</th>
            <td style="padding-left:24px;padding-right:24px;word-wrap:break-word">{{TradeServiceName}}
            </td>
        </tr>
    </table>
    <p style="font-weight:700;line-height:24px;font-size:14px">按照以下步驟開始進行交易：</p>
    <ol>
        <li>在我們的 <a target="_blank"
                href="https://cfds.thebcr.com"
                style="color:#383d49;text-decoration:none;font-weight:700">官方網站</a> 的優惠選項中，了解有關各種 BCR 優惠的更多信息。</li>
        <li>登錄至 <a target="_blank" href="https://portal.thebcr.com/"
                style="color:#383d49;text-decoration:none;font-weight:700">MyBCR</a>，然後轉到下載選項卡，以下載 BCR 交易平台。</li>
        <li>登錄至 <a target="_blank" href="https://portal.thebcr.com/"
                style="color:#383d49;text-decoration:none;font-weight:700">MYBCR</a>，然後轉到我的存款，選擇存款選項。</li>
        <li>登錄至 BCR 交易者（MT4或者MT5 平台）或如果您使用移動設備，請在移動 MetaTrader 中選擇 {{TradeServiceName}}伺服器，然後使用上面列出的帳戶號碼和交易密碼。</li>
    </ol>
    <p>請注意，投資者密碼僅提供唯讀的、非交易的帳戶訪問權限。如果您想透過電話下單，您可以通過以下號碼與我們聯繫：</p>
    <p style="font-weight:600;text-align:center">英國: 44 20 3807 3375<br>
中國南方: 108 00152 1738 (用於固定電話服務)<br>
中國北方: 108 00852 1738 (用於固定電話服務)<br>

    </p>
    <p>請注意，電話交易服務僅在網絡連接問題或交易平台未正常運行時使用。</p>
</div>', '驗證通過');
INSERT INTO cms."_TopicContent" ("Id", "TopicId", "CreatedOn", "UpdatedOn", "Language", "Title", "Author", "Content", "Subtitle") VALUES (11645, 11336, '2024-04-01 22:36:42.322515 +00:00', '2024-09-11 05:45:09.348085 +00:00', 'vi-vn', 'Tài khoản giao dịch khách hàng đã được tạo', '', e'<div style="font-size:12px;line-height:20px">
    <p style="font-size:16px;font-weight:700;line-height:24px">Kính gửi Đối tác BCR,</p>
    <p> Khách hàng của bạn đã mở một tài khoản giao dịch CFD. Chi tiết tài khoản giao dịch được liệt kê dưới đây:</p>
    <table class="letter-table"
        style="table-layout:fixed;line-height:24px;margin-left:auto;margin-right:auto;text-align:left;padding:8px;float:none"
        bgcolor="#f2f2f2" align="left">
        <tr>
            <th
                style="padding-left:24px;padding-right:24px;color:#383d49;white-space:nowrap">
                Tên Tài khoản Giao dịch:</th>
            <td style="padding-left:24px;padding-right:24px;word-wrap:break-word">
                {{UserName}}</td>
        </tr>
        <tr>
            <th
                style="padding-left:24px;padding-right:24px;color:#383d49;white-space:nowrap">
                Số Tài khoản Giao dịch:</th>
            <td style="padding-left:24px;padding-right:24px;word-wrap:break-word">
                {{AccountNumber}}</td>
        </tr>

        <tr>
            <th
                style="padding-left:24px;padding-right:24px;color:#383d49;white-space:nowrap">
                Máy chủ:</th>
            <td style="padding-left:24px;padding-right:24px;word-wrap:break-word">{{TradeServiceName}}
            </td>
        </tr>
    </table>
</div>
', '');
INSERT INTO cms."_TopicContent" ("Id", "TopicId", "CreatedOn", "UpdatedOn", "Language", "Title", "Author", "Content", "Subtitle") VALUES (10063, 11244, '2023-08-16 17:58:18.049394 +00:00', '2025-03-17 18:58:36.432915 +00:00', 'mn-mn', 'Усан онгоцонд тавтай морил', '', e'<div style="font-size:12px;line-height:20px">
    <p style="font-size:16px;font-weight:700;line-height:24px">Сайн уу, {{NativeName}}!</p>
    <p>BCR-тэй CFD худалдаа авах дансаа нээсэн таньд баярлалаа. Таны данс асуудалгүй болсон огноогоор {{OpenedDate}} болсон байна. Таны BCR ProTrader дансны дэлгэрэнгүй мэдээлэл доор харуулсан байна:</p>
    <table class="letter-table"
           style="table-layout:fixed;line-height:24px;margin-left:auto;margin-right:auto;text-align:left;padding:8px;float:none"
           bgcolor="#f2f2f2" align="left">
        <tr>
            <th
                    style="padding-left:24px;padding-right:24px;color:#383d49;white-space:nowrap">
                Миний MyBCR данс:</th>
            <td style="padding-left:24px;padding-right:24px;word-wrap:break-word">
                {{UserName}}</td>
        </tr>
        <tr>
            <th
                    style="padding-left:24px;padding-right:24px;color:#383d49;white-space:nowrap">
                Худалдаа авах дансны дугаар:</th>
            <td style="padding-left:24px;padding-right:24px;word-wrap:break-word">
                {{AccountNumber}}</td>
        </tr>
        <tr>
            <th
                    style="padding-left:24px;padding-right:24px;color:#383d49;white-space:nowrap">
                Худалдаа авах дансны нууц үг:</th>
            <td style="padding-left:24px;padding-right:24px;word-wrap:break-word">
                {{Password}}</td>
        </tr>
    <!--     <tr>
            <th
                    style="padding-left:24px;padding-right:24px;color:#383d49;white-space:nowrap">
                Инвесторын нууц үг:</th>
            <td style="padding-left:24px;padding-right:24px;word-wrap:break-word">
                {{InvestorPassword}}</td>
        </tr> -->
        <tr>
            <th
                    style="padding-left:24px;padding-right:24px;color:#383d49;white-space:nowrap">
                Утасны нууц үг:</th>
            <td style="padding-left:24px;padding-right:24px;word-wrap:break-word">
                {{PhonePassword}}</td>
        </tr>
        <tr>
            <th
                    style="padding-left:24px;padding-right:24px;color:#383d49;white-space:nowrap">
                Сервер:</th>
            <td style="padding-left:24px;padding-right:24px;word-wrap:break-word">{{TradeServiceName}}
            </td>
        </tr>
    </table>
    <p style="font-weight:700;line-height:24px;font-size:14px">Дараах алхамуудыг дагаж худалдааны ажиллагааг эхлүүл:</p>
    <ol>
        <li>Бидний BCR болон түүний багцанд орж буй нэмэлт мэдээллүүдийг олж үзэхийн тулд <a target="_blank"
                                                            href="https://cfds.thebcr.com"
                                                            style="color:#383d49;text-decoration:none;font-weight:700">Официал вэбсайт</a>-д зочилно уу.</li>
        <li><a target="_blank" href="https://portal.thebcr.com/"
                style="color:#383d49;text-decoration:none;font-weight:700">MyBCR</a>-д нэвтрээд "Татаж авах" хэсгээр BCR худалдаа авах платформыг татан авна уу.</li>
        <li><a target="_blank" href="https://portal.thebcr.com/"
                style="color:#383d49;text-decoration:none;font-weight:700">MYBCR</a>-д нэвтрээд "Миний орлого" хэсгээр орлого сонгоно уу.</li>
        <li>BCR Trader (MT4 эсвэл MT5 платформ) руу нэвтрэх эсвэл мобайл төхөөрөмж ашиглаж байгаа бол {{TradeServiceName}} серверийг Mobile MetaTrader-д сонгох болно, дээрх дахин давтагдах дансны дугаар болон худалдаа авах нууц үгийг ашиглаарай.</li>
    </ol>
    <p>
        Инвесторын нууц үг нь таны дансанд зарим хугацаанд худалдааны ажиллагаа үзэх зөвлөгөөг олгодог болно. Худалдаа авах захиалга өгөхийг хүсвэл дараах дугаартай манайтай холбогдоно уу:</p>
    <p style="font-weight:600;text-align:center">        UK: 44 20 3807 3375<br>
    </p>
    <p>Телефон худалдаа ашиглах үйлчилгээ нь замын холболтын асуудал болон худалдаа авах платформ ажиллагааг хийхгүй болох үед зөвшөөрөлгүй.</p>
</div>
', 'Баталгаажуулсан');
