INSERT INTO cms."_TopicContent" ("Id", "TopicId", "CreatedOn", "UpdatedOn", "Language", "Title", "Author", "Content", "Subtitle") VALUES (11860, 11398, '2024-09-25 18:26:09.192194 +00:00', '2024-09-26 16:51:17.773231 +00:00', 'zh-cn', 'BCR 推广活动通知', '', e'<div style="font-size:12px;line-height:20px">
 <p style="text-align:end">
    <span id="date">{{Date}}</span>
  </p>
  <p style="font-size:16px;font-weight:700;line-height:24px">
    尊敬的客户：
  </p>
  <p>
    感谢阁下参与本公司的推广活动, 由于阁下的交易账户 ( {{AccountNumber}} )未达到推广活动的交易量要求及净值已低于推广活动的要求水平，阁下的交易账户将被扣除活动中获得的等值。
  </p>

<p><strong>有关交易账户净值(不含从百汇其他活动中领取的赠金和信用额)在任何时间内低于或等于奖品市值金额定义如下:</strong></p>


  <ul>
    <li>
      <p>客户同时参加赠金活动及奖品活动时, 当交易账户在任何时间内净值低于赠金及奖品价值而未完成相关的交易要求时，赠金及奖品价值将会在交易账户中被扣除。</p>
    </li>
<li>
      <p>倘若交易账户在持仓的情况下，交易账户将会被设定为只可平仓。</p>
    </li>
<li>
      <p>如客户在下一个交易日收盘时账户净值仍然低于赠金及奖品价值，平台将会在当天收盘时按照收盘价格自动平仓，无论客户最终在平仓后净值多少，在平仓后赠金及奖品价值将会在交易账户中扣除。</p>
    </li>
<li>
      <p>如若交易账户在下一个交易日收盘时净值回复至赠金及奖品价值的200%，账户将会回复正常交易状态。
</p>
    </li>
  </ul>

  <p>更多有关详情可参阅推广活动的条件及条款，特此通知。</p>
<br/>

  <p>BCR致力为客户提供专业的交易服务、简易的操作、优异的客户服务。我们提供全天候24小时，每周五天全方位的客户服务。如有任何查询或建议，欢迎电邮至 <a href="mailto:info@thebcr.com">info@thebcr.com</a>联系BCR员工。</p>
  
  <br/>
  BCR客服团队

</div>', '');
INSERT INTO cms."_TopicContent" ("Id", "TopicId", "CreatedOn", "UpdatedOn", "Language", "Title", "Author", "Content", "Subtitle") VALUES (11859, 11398, '2024-09-25 18:10:18.440126 +00:00', '2024-09-26 16:57:42.856557 +00:00', 'en-us', 'BCR Promotion Notification', 'system', e'<div style="font-size:12px;line-height:20px">
 <p style="text-align:end">
    <span id="date">{{Date}}</span>
  </p>
  <p style="font-size:16px;font-weight:700;line-height:24px">
    Dear BCR Client,
  </p>
  <p>
    Thank you for joining our promotion.
  </p>

<p>Unfortunately, your trading account ( {{AccountNumber}} ) equity balance has dropped below the promotional limit, and/or you have not fulfilled the trading turnover requirement associated with this promotion. Therefore, we must inform you that an amount equal to the value of the promotional gift received will be deducted from your trading account.</p>

  <p>The definition of the trading account\'s equity balance dropping below the promotional limit (excluding bonuses and/or credits gained from other BCR promotions) is less than or equal to the stated value of the received promotional gift at any time as stated below:</p>


  <ul>
    <li>
      <p>If the client participates in the Bonus Promotion and Gift Promotion, and their trading account equity balance becomes less than or equal to the <strong>credit bonus plus the gift value</strong> at any time but does not fulfill the promotion requirements, BCR is entitled to deduct an amount equal to the credit bonus and gift value from the trading account.</p>
    </li>
<li>
      <p>If the client\'s trading account has open positions, the account will be set to "liquidation only" status and will no longer be able to open new positions.</p>
    </li>
<li>
      <p>If the client equity balance is lower than the promotion requirement at the next market day close time, the trading platform will automatically liquidate positions at that market day close time. BCR is entitled to deduct the credit bonus and gift value from the trading account, regardless of the account balance after the liquidation,</p>
    </li>
<li>
      <p>If the client trading account equity balance rises higher than the promotion requirement (200% of the promotion item value) at the next market day close time, the account will be removed from “liquidity only” status and be able to open new positions.
</p>
    </li>
  </ul>

  <p>For more information, please visit our website for promotion criteria.</p>
<br/>

  <p>BCR is committed to offering our clients excellent execution, easy accessibility, and exceptional client service in Contracts for Difference trading. We provide full client service, with live support 24 hours a day, 5 days a week. If you have any questions or concerns, you can contact the BCR staff via email at <a href="mailto:info@thebcr.com">info@thebcr.com</a>.</p>
  
  <br/>
  Regards,<br/>
  BCR

</div>', '');
INSERT INTO cms."_TopicContent" ("Id", "TopicId", "CreatedOn", "UpdatedOn", "Language", "Title", "Author", "Content", "Subtitle") VALUES (11330, 11262, '2023-08-07 19:45:30.539318 +00:00', '2024-12-02 21:37:35.596369 +00:00', 'en-us', 'Notification Regarding the Verification Failure', 'system', e'<div>Dear {{NativeName}}</div>
<p>I hope this message finds you well.</p>
<p>Thank you for submitting your account opening documents. Unfortunately, we were unable to verify your identity document/address proof during our review process. The reason may be due to the document being expired, missing information, the document not being in color, inaccurate details, or the document being unclear or hard to read.</p>
<p>To ensure the successful completion of your account setup, please resubmit a recent, complete, clear, and legible document. We recommend that you carefully check the document\'s validity and ensure all information is accurate to meet our verification requirements.</p>
<p>To protect the privacy and security of all users, we strictly adhere to relevant security policies and guidelines. Thank you for your understanding and cooperation.</p>
<p>If you have any questions or need further assistance, please feel free to contact us. We are here to help.</p>
<p>Thank you for your understanding and cooperation.</p>', ' ');
INSERT INTO cms."_TopicContent" ("Id", "TopicId", "CreatedOn", "UpdatedOn", "Language", "Title", "Author", "Content", "Subtitle") VALUES (11349, 11262, '2023-08-16 21:27:13.783766 +00:00', '2024-12-02 21:41:11.714919 +00:00', 'vi-vn', 'Thông Báo Về Việc Xác Minh Không Thành Công', '', e'<div>Kính gửi {{NativeName}}</div>
<p>Chúng tôi hy vọng email này đến với bạn trong tình trạng tốt đẹp.</p>
<p>Cảm ơn bạn đã gửi tài liệu mở tài khoản. Tuy nhiên, trong quá trình xem xét, chúng tôi không thể xác minh được giấy tờ tùy thân/chứng minh địa chỉ của bạn. Lý do có thể là do tài liệu đã hết hạn, thiếu thông tin, tài liệu không phải là bản màu, thông tin không chính xác, hoặc tài liệu không rõ ràng hoặc khó đọc.</p>
<p>Để đảm bảo việc thiết lập tài khoản của bạn được hoàn tất thành công, vui lòng gửi lại tài liệu mới, đầy đủ, rõ ràng và dễ đọc. Chúng tôi khuyên bạn nên kiểm tra kỹ tính hợp lệ của tài liệu và đảm bảo tất cả thông tin đều chính xác để đáp ứng các yêu cầu xác minh của chúng tôi.</p>
<p>Để bảo vệ quyền riêng tư và an ninh của tất cả người dùng, chúng tôi tuân thủ nghiêm ngặt các chính sách và hướng dẫn bảo mật liên quan. Cảm ơn sự thông cảm và hợp tác của bạn.</p>
<p>Nếu bạn có bất kỳ câu hỏi hoặc cần hỗ trợ thêm, xin vui lòng liên hệ với chúng tôi. Chúng tôi luôn sẵn sàng hỗ trợ bạn.</p>
<p>Cảm ơn sự thông cảm và hợp tác của bạn.</p>', '');
INSERT INTO cms."_TopicContent" ("Id", "TopicId", "CreatedOn", "UpdatedOn", "Language", "Title", "Author", "Content", "Subtitle") VALUES (10094, 11262, '2023-08-16 18:45:48.462351 +00:00', '2024-12-02 21:41:51.045199 +00:00', 'jp-jp', '本人確認手続き不備のお知らせ', '', e'<div>{{NativeName}}様</div>
<p>いつもお世話になっております。</p>
<p>口座開設に関する書類をご提出いただき、誠にありがとうございます。しかしながら、審査過程において、ご提出いただきましたご本人確認書類/現住所証明書類の確認ができかねました。これは、書類の有効期限切れ、情報の不足、カラーでない書類、情報の不一致、または書類が不鮮明で判読が困難である等の理由によるものと考えられます。</p>
<p>口座開設手続きを円滑に完了させていただくため、最新かつ完全で、鮮明で判読可能な書類を再度ご提出くださいますようお願い申し上げます。弊社の確認要件を満たすため、書類の有効性と全ての情報の正確性を慎重にご確認いただきますようお願いいたします。</p>
<p>すべてのユーザー様のプライバシーとセキュリティを保護するため、弊社では関連するセキュリティポリシーとガイドラインを厳守しております。ご理解とご協力を賜りますよう、よろしくお願い申し上げます。</p>
<p>ご不明な点やご質問がございましたら、お気軽にお問い合わせください。喜んでサポートさせていただきます。</p>
<p>ご理解とご協力を賜り、誠にありがとうございます。</p>', '');
INSERT INTO cms."_TopicContent" ("Id", "TopicId", "CreatedOn", "UpdatedOn", "Language", "Title", "Author", "Content", "Subtitle") VALUES (11298, 11244, '2023-07-19 21:22:00.260928 +00:00', '2025-03-17 18:57:38.409224 +00:00', 'en-us', 'Welcome Aboard', 'system', e'<div style="font-size:12px;line-height:20px">
