                                            {{Password}}</td>
                                    </tr>
                                   <!--   <tr>
                                        <th
                                            style="padding-left:24px;padding-right:24px;color:#383d49;white-space:nowrap">
                                            Investor Password:</th>
                                        <td style="padding-left:24px;padding-right:24px;word-wrap:break-word">
                                            {{InvestorPassword}}</td>
                                    </tr>-->
                                    <tr>
                                        <th
                                            style="padding-left:24px;padding-right:24px;color:#383d49;white-space:nowrap">
                                            Phone Password:</th>
                                        <td style="padding-left:24px;padding-right:24px;word-wrap:break-word">
                                            {{PhonePassword}}</td>
                                    </tr>
                                    <tr>
                                        <th
                                            style="padding-left:24px;padding-right:24px;color:#383d49;white-space:nowrap">
                                            Server:</th>
                                        <td style="padding-left:24px;padding-right:24px;word-wrap:break-word">{{TradeServiceName}}
                                        </td>
                                    </tr>
                                </table>
                                <p style="font-weight:700;line-height:24px;font-size:14px">Follow these steps to start
                                    trading now:</p>
                                <ol>
                                    <li>Browse our Promotions tab on our <a target="_blank"
                                            href="https://cfds.thebcr.com"
                                            style="color:#383d49;text-decoration:none;font-weight:700">Offcial
                                            Website</a> to learn more about various BCR promotions.</li>
                                    <li>Log in to <a target="_blank" href="https://cfds-portal.thebcr.com/"
                                            style="color:#383d49;text-decoration:none;font-weight:700">MyBCR</a>
                                        and go to the Download tab to download the BCR trading platform.</li>
                                    <li>Log in to <a target="_blank" href="https://cfds-portal.thebcr.com/"
                                            style="color:#383d49;text-decoration:none;font-weight:700">MYBCR</a> and go
                                        to My deposit to choose the a deposit option.</li>
                                    <li>Log in to the BCR Trader (MT4 or MT5 Platform) or, if you are using a mobile device,
                                        select the {{TradeServiceName}} Server in Mobile MetaTrader and use the Account Number and
                                        Trading Password listed above.</li>
                                </ol>
                                <p>
                                    Please note that the Investor Password provides read-only, non-trading access to
                                    your account. If you would like to place trade orders over the telephone, you can
                                    reach us at one of the following number:</p>
                                <p style="font-weight:600;text-align:center">
                                    <!-- 44 3300010590<br> New Zealand: 64-9-889-2558<br>-->
    UK: 44 20 3807 3375<br>
    Southern China: 108 00152 1738 (For Land Line Service)<br>
    Northern China: 108 00852 1738 (For Land Line Service)<br> 
                                </p>
                                <p>Please note that telephone trading service is only for use when there is a network
                                    connectivity problem or if the trading platform is not functioning properly.
                                </p>

                            </div>', 'Verification passed');
INSERT INTO cms."_TopicContent" ("Id", "TopicId", "CreatedOn", "UpdatedOn", "Language", "Title", "Author", "Content", "Subtitle") VALUES (10081, 11244, '2023-08-16 18:30:38.467295 +00:00', '2025-03-17 18:58:03.027367 +00:00', 'jp-jp', 'ようこそ、ご搭乗ください', '', e'<div style="font-size:12px;line-height:20px">
